    'risk_level', 'low',
    'fields', jsonb_build_object('route_key', v_target->>'route_key'),
    'resolution', jsonb_build_object('mode', 'not_applicable', 'entity_type', 'none'),
    'ui_hint', jsonb_build_object(
      'type', 'route',
      'component', NULL,
      'target', v_target->>'target',
      'prefill', NULL,
