CREATE OR REPLACE FUNCTION "public"."_expense_plan_generate_cycle"("p_plan_id" "uuid", "p_cycle_date" "date") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_plan_unsafe  public.expense_plans%ROWTYPE;
  v_plan         public.expense_plans%ROWTYPE;
  v_home_active  boolean;
  v_expense      public.expenses%ROWTYPE;
BEGIN
  IF p_plan_id IS NULL OR p_cycle_date IS NULL THEN
    PERFORM public.api_error('INVALID_PLAN', 'Plan id and cycle date are required.', '22023');
  END IF;

  SELECT *
    INTO v_plan_unsafe
    FROM public.expense_plans ep
   WHERE ep.id = p_plan_id;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_FOUND',
      'Expense plan not found.',
      'P0002',
      jsonb_build_object('planId', p_plan_id)
    );
  END IF;

  SELECT h.is_active
    INTO v_home_active
    FROM public.homes h
   WHERE h.id = v_plan_unsafe.home_id
   FOR UPDATE;

  IF v_home_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004');
  END IF;

  SELECT *
    INTO v_plan
    FROM public.expense_plans ep
   WHERE ep.id = p_plan_id
   FOR UPDATE;

  IF v_plan.home_id <> v_plan_unsafe.home_id THEN
    PERFORM public.api_error(
      'CONCURRENT_MODIFICATION',
      'Plan changed while generating cycle; retry.',
      '40001',
      jsonb_build_object('planId', p_plan_id)
    );
  END IF;

  IF v_plan.status <> 'active' THEN
    PERFORM public.api_error(
      'PLAN_NOT_ACTIVE',
      'Cannot generate cycles for a terminated plan.',
      'P0004',
      jsonb_build_object('planId', p_plan_id, 'status', v_plan.status)
    );
  END IF;

  BEGIN
    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      plan_id,
      recurrence_interval,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      v_plan.home_id,
      v_plan.created_by_user_id,
      'active',
      v_plan.split_type,
      v_plan.amount_cents,
      v_plan.description,
      v_plan.notes,
      v_plan.evidence_photo_path,
      v_plan.id,
      v_plan.recurrence_interval,
      v_plan.recurrence_every,
      v_plan.recurrence_unit,
      p_cycle_date
    )
    RETURNING * INTO v_expense;

  EXCEPTION WHEN unique_violation THEN
    SELECT *
      INTO v_expense
      FROM public.expenses e
     WHERE e.plan_id = v_plan.id
       AND e.start_date = p_cycle_date
     LIMIT 1;

    IF NOT FOUND THEN
      PERFORM public.api_error(
        'STATE_CHANGED_RETRY',
        'Cycle already exists but could not be read; retry.',
        '40001',
        jsonb_build_object('planId', v_plan.id, 'cycleDate', p_cycle_date)
      );
    END IF;

    RETURN v_expense;
  END;

  INSERT INTO public.expense_splits (
    expense_id,
    debtor_user_id,
    amount_cents,
    status,
    marked_paid_at
  )
  SELECT
    v_expense.id,
    d.debtor_user_id,
    d.share_amount_cents,
    CASE
      WHEN d.debtor_user_id = v_plan.created_by_user_id
        THEN 'paid'::public.expense_share_status
      ELSE 'unpaid'::public.expense_share_status
    END,
    CASE
      WHEN d.debtor_user_id = v_plan.created_by_user_id
        THEN now()
      ELSE NULL
    END
  FROM public.expense_plan_debtors d
  WHERE d.plan_id = v_plan.id;

  PERFORM public._home_usage_apply_delta(
    v_plan.home_id,
    jsonb_build_object('active_expenses', 1)
  );

  RETURN v_expense;
END;
$$;


ALTER FUNCTION "public"."_expense_plan_generate_cycle"("p_plan_id" "uuid", "p_cycle_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_expense_plan_generate_cycle_v3"("p_plan_id" "uuid", "p_cycle_date" "date", "p_apply_quota" boolean DEFAULT true) RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_plan public.expense_plans%ROWTYPE;
  v_expense public.expenses%ROWTYPE;
  v_invalid_reason text := NULL;
BEGIN
  IF p_plan_id IS NULL OR p_cycle_date IS NULL THEN
    PERFORM public.api_error('INVALID_PLAN', 'Plan id and cycle date are required.', '22023');
  END IF;

  v_plan := public._expense_lock_plan_with_home_active(p_plan_id);

  IF v_plan.status <> 'active' THEN
    PERFORM public.api_error(
      'PLAN_NOT_ACTIVE',
      'Cannot generate cycles for a terminated plan.',
      'P0004',
      jsonb_build_object('planId', p_plan_id, 'status', v_plan.status)
    );
  END IF;

  IF p_apply_quota THEN
    PERFORM public._expense_quota_assert_generate_cycle(v_plan.home_id);
  END IF;

  IF COALESCE(v_plan.allocation_target_type, 'debtor_based') = 'unit_based' THEN
    IF EXISTS (
      SELECT 1
      FROM public.expense_plan_units u
      WHERE u.plan_id = v_plan.id
        AND u.home_id <> v_plan.home_id
    ) THEN
      v_invalid_reason := 'UNIT_TARGET_HOME_MISMATCH';
    ELSIF EXISTS (
      SELECT 1
      FROM public.expense_plan_units u
      LEFT JOIN public.home_units hu
        ON hu.id = u.unit_id
       AND hu.home_id = u.home_id
      WHERE u.plan_id = v_plan.id
        AND hu.id IS NULL
    ) THEN
      v_invalid_reason := 'UNIT_TARGET_INVALID';
    ELSIF EXISTS (
      SELECT 1
      FROM public.expense_plan_units u
      JOIN public.home_units hu
        ON hu.id = u.unit_id
       AND hu.home_id = u.home_id
      WHERE u.plan_id = v_plan.id
        AND hu.archived_at IS NOT NULL
    ) THEN
      v_invalid_reason := 'UNIT_TARGET_ARCHIVED';
    END IF;

    IF v_invalid_reason IS NOT NULL THEN
      UPDATE public.expense_plans
      SET status = 'terminated',
          termination_reason = v_invalid_reason,
          updated_at = now()
      WHERE id = v_plan.id;

      PERFORM public.api_error(
        'PLAN_TERMINATED_INVALID_TARGETS',
        'Recurring plan terminated because unit targets are no longer valid.',
        'P0004',
        jsonb_build_object('planId', v_plan.id, 'reason', v_invalid_reason)
      );
    END IF;
  END IF;

  BEGIN
    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      allocation_target_type,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      plan_id,
      recurrence_interval,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      v_plan.home_id,
      v_plan.created_by_user_id,
      'active',
      COALESCE(v_plan.allocation_target_type, 'debtor_based'),
      v_plan.split_type,
      v_plan.amount_cents,
      v_plan.description,
      v_plan.notes,
      v_plan.evidence_photo_path,
      v_plan.id,
      v_plan.recurrence_interval,
      v_plan.recurrence_every,
      v_plan.recurrence_unit,
      p_cycle_date
    )
    RETURNING * INTO v_expense;
  EXCEPTION
    WHEN unique_violation THEN
      SELECT *
      INTO v_expense
      FROM public.expenses e
      WHERE e.plan_id = v_plan.id
        AND e.start_date = p_cycle_date
      LIMIT 1;

      IF NOT FOUND THEN
        PERFORM public.api_error(
          'STATE_CHANGED_RETRY',
          'Cycle already exists but could not be read; retry.',
          '40001',
          jsonb_build_object('planId', v_plan.id, 'cycleDate', p_cycle_date)
        );
      END IF;

      RETURN v_expense;
  END;

  IF COALESCE(v_plan.allocation_target_type, 'debtor_based') = 'unit_based' THEN
    INSERT INTO public.expense_unit_splits (
      expense_id,
      home_id,
      unit_id,
      amount_cents,
      paid_cents,
      fully_paid_at
    )
    SELECT
      v_expense.id,
      u.home_id,
      u.unit_id,
      u.share_amount_cents,
      0,
      NULL
    FROM public.expense_plan_units u
    WHERE u.plan_id = v_plan.id
    ON CONFLICT (expense_id, unit_id) DO NOTHING;
  ELSE
    INSERT INTO public.expense_splits (
      expense_id,
      debtor_user_id,
      amount_cents,
      status,
      marked_paid_at
    )
    SELECT
      v_expense.id,
      d.debtor_user_id,
      d.share_amount_cents,
      CASE
        WHEN d.debtor_user_id = v_plan.created_by_user_id THEN 'paid'::public.expense_share_status
        ELSE 'unpaid'::public.expense_share_status
      END,
      CASE
        WHEN d.debtor_user_id = v_plan.created_by_user_id THEN now()
        ELSE NULL
      END
    FROM public.expense_plan_debtors d
    WHERE d.plan_id = v_plan.id
    ON CONFLICT (expense_id, debtor_user_id) DO NOTHING;
  END IF;

  IF p_apply_quota THEN
    PERFORM public._expense_quota_apply_generate_cycle(v_plan.home_id);
  END IF;

  RETURN v_expense;
END;
$$;


ALTER FUNCTION "public"."_expense_plan_generate_cycle_v3"("p_plan_id" "uuid", "p_cycle_date" "date", "p_apply_quota" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_expense_plan_next_cycle_date"("p_interval" "public"."recurrence_interval", "p_from" "date") RETURNS "date"
    LANGUAGE "plpgsql" IMMUTABLE STRICT
    SET "search_path" TO ''
    AS $$
BEGIN
  CASE p_interval
    WHEN 'weekly' THEN
      RETURN (p_from + 7)::date;
    WHEN 'every_2_weeks' THEN
      RETURN (p_from + 14)::date;
    WHEN 'monthly' THEN
      RETURN (p_from + INTERVAL '1 month')::date;
    WHEN 'every_2_months' THEN
      RETURN (p_from + INTERVAL '2 months')::date;
    WHEN 'annual' THEN
      RETURN (p_from + INTERVAL '1 year')::date;
    ELSE
      RAISE EXCEPTION
        'Recurrence interval % not supported for expense plans.',
        p_interval
        USING ERRCODE = '22023';
  END CASE;
END;
$$;


ALTER FUNCTION "public"."_expense_plan_next_cycle_date"("p_interval" "public"."recurrence_interval", "p_from" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_expense_plan_next_cycle_date_v2"("p_every" integer, "p_unit" "text", "p_from" "date") RETURNS "date"
    LANGUAGE "plpgsql" IMMUTABLE STRICT
    SET "search_path" TO ''
    AS $$
BEGIN
  IF p_every IS NULL OR p_unit IS NULL THEN
    RAISE EXCEPTION
      'Recurrence every/unit is required for expense plans.'
      USING ERRCODE = '22023';
  END IF;

  IF p_every < 1 THEN
    RAISE EXCEPTION
      'Recurrence every must be >= 1.'
      USING ERRCODE = '22023';
  END IF;

  CASE p_unit
    WHEN 'day' THEN
      RETURN (p_from + p_every)::date;
    WHEN 'week' THEN
      RETURN (p_from + (p_every * 7))::date;
    WHEN 'month' THEN
      RETURN (p_from + make_interval(months => p_every))::date;
    WHEN 'year' THEN
      RETURN (p_from + make_interval(years => p_every))::date;
    ELSE
      RAISE EXCEPTION
        'Recurrence unit % not supported for expense plans.',
        p_unit
        USING ERRCODE = '22023';
  END CASE;
END;
$$;


ALTER FUNCTION "public"."_expense_plan_next_cycle_date_v2"("p_every" integer, "p_unit" "text", "p_from" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_expense_plan_units_fill_home_id"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_home_id uuid;
BEGIN
  IF NEW.plan_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.home_id IS NULL THEN
    SELECT ep.home_id
    INTO v_home_id
    FROM public.expense_plans ep
    WHERE ep.id = NEW.plan_id;

    NEW.home_id := v_home_id;
  END IF;

  RETURN NEW;
END;
$$;


