    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $_$
DECLARE
  base       public.citext;
  candidate  public.citext;
  n          int := 0;
  max_tries  int := 100000;
  prefix_len int;
BEGIN
  -- derive from email local-part (DOT-LESS); fallback to id
  base := lower(
            coalesce(
              nullif(replace(split_part(p_email, '@', 1), '.', ''), ''),
              'user_' || substr(p_id::text, 1, 8)
            )
          );

  -- keep only [a-z0-9._], trim edges
  base := regexp_replace(base, '[^a-z0-9._]', '', 'g');
  base := regexp_replace(base, '^[._]+|[._]+$', '', 'g');

  -- (optional) collapse repeated separators: '..' or '__' -> '_'
  base := regexp_replace(base, '[._]{2,}', '_', 'g');

  -- ensure min length 3 (fallback to uuid prefix)
  IF length(base) < 3 THEN
    base := 'user' || substr(p_id::text, 1, 8);
  END IF;

  -- cap to 30 (we’ll shorten further if we add suffix)
  base := left(base, 30);

  -- serialize attempts per-base (reduces races)
  PERFORM pg_try_advisory_xact_lock(hashtextextended(base::text, 0));

  -- try base, then base_1, base_2, ... (keep total <= 30)
  LOOP
    IF n = 0 THEN
      candidate := base;
    ELSE
      -- room for '_' + n
      prefix_len := greatest(1, 30 - 1 - length(n::text));
      candidate  := left(base, prefix_len) || '_' || n::text;
    END IF;

    -- must match the CHECK regex: start/end alnum
    IF candidate ~ '^[a-z0-9](?:[a-z0-9._]{1,28})[a-z0-9]$' THEN
      -- skip if reserved
      IF NOT EXISTS (
           SELECT 1 FROM public.reserved_usernames r
           WHERE r.name = candidate
         )
      THEN
        -- unique test (case-insensitive due to citext + unique index)
        PERFORM 1 FROM public.profiles WHERE username = candidate;
        IF NOT FOUND THEN
          RETURN candidate;
        END IF;
      END IF;
    END IF;

    n := n + 1;
    IF n > max_tries THEN
      RAISE EXCEPTION 'Could not generate unique username after % attempts (base=%)', max_tries, base;
    END IF;
  END LOOP;
END
$_$;


ALTER FUNCTION "public"."_gen_unique_username"("p_email" "text", "p_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_assert_quota"("p_home_id" "uuid", "p_deltas" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_plan       text;
  v_is_premium boolean;
  v_counters   public.home_usage_counters%ROWTYPE;

  v_metric_key   text;
  v_metric_enum  public.home_usage_metric;
  v_raw_value    jsonb;
  v_delta        integer;
  v_current      integer;
  v_new          integer;
  v_max          integer;
BEGIN
  v_plan := public._home_effective_plan(p_home_id);

  v_is_premium := public._home_is_premium(p_home_id);
  IF v_is_premium THEN
    RETURN;
  END IF;

  IF p_deltas IS NULL OR jsonb_typeof(p_deltas) <> 'object' THEN
    RETURN;
  END IF;

  SELECT *
  INTO v_counters
  FROM public.home_usage_counters
  WHERE home_id = p_home_id;

  IF NOT FOUND THEN
    v_counters.active_chores               := 0;
    v_counters.chore_photos                := 0;
    v_counters.active_members              := 0;
    v_counters.active_expenses             := 0;
    v_counters.shopping_item_photos        := 0;
    v_counters.expense_photos              := 0;
    v_counters.house_directory_note_photos := 0;
  END IF;

  FOR v_metric_key, v_raw_value IN
    SELECT key, value FROM jsonb_each(p_deltas)
  LOOP
    BEGIN
      v_metric_enum := v_metric_key::public.home_usage_metric;
    EXCEPTION WHEN invalid_text_representation THEN
      CONTINUE;
    END;

    IF jsonb_typeof(v_raw_value) <> 'number' THEN
      PERFORM public.api_error(
        'INVALID_QUOTA_DELTA',
        'Quota delta must be numeric.',
        '22023',
        jsonb_build_object('metric', v_metric_key, 'value', v_raw_value)
      );
    END IF;

    v_delta := (v_raw_value #>> '{}')::integer;
    IF COALESCE(v_delta, 0) <= 0 THEN
      CONTINUE;
    END IF;

    SELECT max_value
    INTO v_max
    FROM public.home_plan_limits
    WHERE plan = v_plan
      AND metric = v_metric_enum;

    IF v_max IS NULL THEN
      CONTINUE;
    END IF;

    v_current := CASE v_metric_enum
      WHEN 'active_chores'               THEN COALESCE(v_counters.active_chores, 0)
      WHEN 'chore_photos'                THEN COALESCE(v_counters.chore_photos, 0)
      WHEN 'active_members'              THEN COALESCE(v_counters.active_members, 0)
      WHEN 'active_expenses'             THEN COALESCE(v_counters.active_expenses, 0)
      WHEN 'shopping_item_photos'        THEN COALESCE(v_counters.shopping_item_photos, 0)
      WHEN 'expense_photos'              THEN COALESCE(v_counters.expense_photos, 0)
      WHEN 'house_directory_note_photos' THEN COALESCE(v_counters.house_directory_note_photos, 0)
    END;

    v_new := GREATEST(0, v_current + v_delta);

    IF v_new > v_max THEN
      PERFORM public.api_error(
        'PAYWALL_LIMIT_' || upper(v_metric_key),
        format('Free plan allows up to %s %s per home.', v_max, v_metric_key),
        'P0001',
        jsonb_build_object(
          'limit_type', v_metric_key,
          'plan',       v_plan,
          'max',        v_max,
          'current',    v_current,
          'projected',  v_new
        )
      );
    END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."_home_assert_quota"("p_home_id" "uuid", "p_deltas" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_home_assert_quota"("p_home_id" "uuid", "p_deltas" "jsonb") IS 'Generic quota enforcement: checks deltas against per-plan limits in home_plan_limits and raises api_error when exceeding quotas.';



CREATE OR REPLACE FUNCTION "public"."_home_attach_subscription_to_home"("_user_id" "uuid", "_home_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- Attach the user's live subscription (if any) that is currently unattached
  UPDATE public.user_subscriptions
  SET home_id    = _home_id,
      updated_at = now()
  WHERE user_id = _user_id
    AND home_id IS NULL
    AND status IN ('active', 'cancelled');

  -- We rely on the trigger to call home_entitlements_refresh(_home_id)
END;
$$;


ALTER FUNCTION "public"."_home_attach_subscription_to_home"("_user_id" "uuid", "_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_detach_subscription_to_home"("_home_id" "uuid", "_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  UPDATE public.user_subscriptions
  SET home_id    = NULL,
      updated_at = now()
  WHERE user_id = _user_id
    AND home_id = _home_id
    AND status IN ('active', 'cancelled');

  -- trigger on user_subscriptions will call home_entitlements_refresh(v_home_id)
END;
$$;


ALTER FUNCTION "public"."_home_detach_subscription_to_home"("_home_id" "uuid", "_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_effective_plan"("p_home_id" "uuid") RETURNS "text"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT COALESCE(
    (
      SELECT he.plan
      FROM public.home_entitlements he
      WHERE he.home_id = p_home_id
        AND (he.expires_at IS NULL OR he.expires_at > now())
      ORDER BY he.expires_at NULLS LAST, he.created_at DESC
      LIMIT 1
    ),
    'free'
  );
$$;


ALTER FUNCTION "public"."_home_effective_plan"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_is_premium"("p_home_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT COALESCE(
    (
      SELECT plan = 'premium'
             AND (expires_at IS NULL OR expires_at > now())
      FROM public.home_entitlements
      WHERE home_id = p_home_id
    ),
    FALSE
  );
$$;


ALTER FUNCTION "public"."_home_is_premium"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__ensure_personal"("p_home_id" "uuid", "p_membership_id" "uuid", "p_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_unit_id uuid;
  v_name text;
BEGIN
  PERFORM 1
  FROM public.memberships m
  WHERE m.id = p_membership_id
    AND m.home_id = p_home_id
    AND m.valid_to IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'membership_not_active',
      'Membership is not active for this home.',
      '42501',
      jsonb_build_object('home_id', p_home_id, 'membership_id', p_membership_id)
    );
  END IF;

  SELECT hu.id
  INTO v_unit_id
  FROM public.home_units hu
  WHERE hu.home_id = p_home_id
    AND hu.unit_type = 'personal'
    AND hu.personal_membership_id = p_membership_id
    AND hu.archived_at IS NULL
  LIMIT 1;

  IF v_unit_id IS NULL THEN
    SELECT COALESCE(
      NULLIF(btrim(p.full_name), ''),
      'Personal'
    )
    INTO v_name
    FROM public.profiles p
    WHERE p.id = p_user_id;

    INSERT INTO public.home_units (
      home_id,
      unit_type,
      name,
      personal_membership_id,
      created_by_user_id
    )
    VALUES (
      p_home_id,
      'personal',
      COALESCE(v_name, 'Personal'),
      p_membership_id,
      p_user_id
    )
    RETURNING id INTO v_unit_id;
  END IF;

  INSERT INTO public.home_unit_members (unit_id, home_id, membership_id)
  VALUES (v_unit_id, p_home_id, p_membership_id)
  ON CONFLICT (unit_id, membership_id) DO NOTHING;

  RETURN v_unit_id;
END;
$$;


ALTER FUNCTION "public"."_home_units__ensure_personal"("p_home_id" "uuid", "p_membership_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__ensure_personal_membership_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  IF NEW.valid_to IS NULL THEN
    PERFORM public._home_units__ensure_personal(NEW.home_id, NEW.id, NEW.user_id);
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."_home_units__ensure_personal_membership_trigger"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__member_user_ids"("p_unit_id" "uuid") RETURNS "text"[]
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT COALESCE(
    array_agg(m.user_id::text ORDER BY m.user_id::text),
    ARRAY[]::text[]
  )
  FROM public.home_unit_members hum
  JOIN public.memberships m
    ON m.id = hum.membership_id
   AND m.valid_to IS NULL
  WHERE hum.unit_id = p_unit_id;
$$;


ALTER FUNCTION "public"."_home_units__member_user_ids"("p_unit_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__membership_departure_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  IF OLD.valid_to IS NULL AND NEW.valid_to IS NOT NULL THEN
    UPDATE public.home_units hu
    SET archived_at = COALESCE(hu.archived_at, now())
    WHERE hu.unit_type = 'personal'
      AND hu.personal_membership_id = NEW.id
      AND hu.archived_at IS NULL;

    DELETE FROM public.home_unit_members hum
    USING public.home_units hu
    WHERE hum.unit_id = hu.id
      AND hum.membership_id = NEW.id
      AND hu.unit_type = 'shared'
      AND hu.archived_at IS NULL;

    UPDATE public.home_units hu
    SET archived_at = COALESCE(hu.archived_at, now())
    WHERE hu.unit_type = 'shared'
      AND hu.archived_at IS NULL
      AND hu.home_id = NEW.home_id
      AND hu.id IN (
        SELECT hu2.id
        FROM public.home_units hu2
        LEFT JOIN public.home_unit_members hum2
          ON hum2.unit_id = hu2.id
        LEFT JOIN public.memberships m2
          ON m2.id = hum2.membership_id
         AND m2.valid_to IS NULL
        WHERE hu2.unit_type = 'shared'
          AND hu2.archived_at IS NULL
          AND hu2.home_id = NEW.home_id
        GROUP BY hu2.id
        HAVING COUNT(m2.id) < 2
      );

    PERFORM public._home_units__reconcile_member_projection(NEW.home_id);
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."_home_units__membership_departure_trigger"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__reconcile_member_projection"("p_home_id" "uuid" DEFAULT NULL::"uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_updated integer := 0;
BEGIN
  UPDATE public.home_unit_members hum
  SET
    home_id = hu.home_id,
    is_active_shared = (hu.unit_type = 'shared' AND hu.archived_at IS NULL)
  FROM public.home_units hu
  WHERE hu.id = hum.unit_id
    AND (p_home_id IS NULL OR hu.home_id = p_home_id)
    AND (
      hum.home_id IS DISTINCT FROM hu.home_id
      OR hum.is_active_shared IS DISTINCT FROM (hu.unit_type = 'shared' AND hu.archived_at IS NULL)
    );

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."_home_units__reconcile_member_projection"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__sync_member_projection"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_unit public.home_units;
BEGIN
  SELECT *
  INTO v_unit
  FROM public.home_units hu
  WHERE hu.id = NEW.unit_id
  LIMIT 1;

  IF v_unit.id IS NULL THEN
    PERFORM public.api_error(
      'unit_not_found',
      'Home unit not found.',
      'P0002',
      jsonb_build_object('unit_id', NEW.unit_id)
    );
  END IF;

  NEW.home_id := v_unit.home_id;
  NEW.is_active_shared := (v_unit.unit_type = 'shared' AND v_unit.archived_at IS NULL);

  IF v_unit.unit_type = 'personal'
     AND NEW.membership_id <> v_unit.personal_membership_id THEN
    PERFORM public.api_error(
      'invalid_personal_unit_member',
      'Personal units may only contain their linked personal membership.',
      '22023',
      jsonb_build_object('unit_id', NEW.unit_id, 'membership_id', NEW.membership_id)
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."_home_units__sync_member_projection"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_home_units__sync_members_from_unit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  UPDATE public.home_unit_members hum
  SET
    home_id = NEW.home_id,
    is_active_shared = (NEW.unit_type = 'shared' AND NEW.archived_at IS NULL)
  WHERE hum.unit_id = NEW.id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."_home_units__sync_members_from_unit"() OWNER TO "postgres";


