CREATE TABLE IF NOT EXISTS "public"."home_usage_counters" (
    "home_id" "uuid" NOT NULL,
    "active_chores" integer DEFAULT 0 NOT NULL,
    "chore_photos" integer DEFAULT 0 NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "active_members" integer DEFAULT 0 NOT NULL,
    "active_expenses" integer DEFAULT 0 NOT NULL,
    "shopping_item_photos" integer DEFAULT 0 NOT NULL,
    "expense_photos" integer DEFAULT 0 NOT NULL,
    "house_directory_note_photos" integer DEFAULT 0 NOT NULL,
    CONSTRAINT "home_usage_counters_active_chores_check" CHECK (("active_chores" >= 0)),
    CONSTRAINT "home_usage_counters_active_expenses_check" CHECK (("active_expenses" >= 0)),
    CONSTRAINT "home_usage_counters_active_members_check" CHECK (("active_members" >= 0)),
    CONSTRAINT "home_usage_counters_chore_photos_check" CHECK (("chore_photos" >= 0)),
    CONSTRAINT "home_usage_counters_expense_photos_check" CHECK (("expense_photos" >= 0)),
    CONSTRAINT "home_usage_counters_house_directory_note_photos_check" CHECK (("house_directory_note_photos" >= 0)),
    CONSTRAINT "home_usage_counters_shopping_item_photos_check" CHECK (("shopping_item_photos" >= 0))
);


ALTER TABLE "public"."home_usage_counters" OWNER TO "postgres";


COMMENT ON TABLE "public"."home_usage_counters" IS 'Cached usage counters (active chores, expectation photos) for paywall checks.';



COMMENT ON COLUMN "public"."home_usage_counters"."active_chores" IS 'Non-cancelled chores that still count versus the free quota (e.g. completed recurring + scheduled/assigned, one-off completed removed).';



COMMENT ON COLUMN "public"."home_usage_counters"."chore_photos" IS 'Number of chores with expectation photos.';



COMMENT ON COLUMN "public"."home_usage_counters"."active_members" IS 'Number of current/active members in the home (owner + members).';



COMMENT ON COLUMN "public"."home_usage_counters"."active_expenses" IS 'Number of draft/active expenses that still count toward the plan quota (freed when cancelled or fully paid).';



COMMENT ON COLUMN "public"."home_usage_counters"."house_directory_note_photos" IS 'Cumulative count of home-directory note photos added for the home. Replacements do not increment again.';



CREATE OR REPLACE FUNCTION "public"."_home_usage_apply_delta"("p_home_id" "uuid", "p_deltas" "jsonb") RETURNS "public"."home_usage_counters"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_row                               public.home_usage_counters;
  v_home_active                       boolean;

  v_active_chores_delta               integer := 0;
  v_chore_photos_delta                integer := 0;
  v_active_members_delta              integer := 0;
  v_active_expenses_delta             integer := 0;
  v_shopping_item_photos_delta        integer := 0;
  v_expense_photos_delta              integer := 0;
  v_house_directory_note_photos_delta integer := 0;
BEGIN
  IF p_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_HOME', 'Home id is required.', '22023');
  END IF;

  SELECT h.is_active
    INTO v_home_active
    FROM public.homes h
   WHERE h.id = p_home_id
   FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_FOUND',
      'Home not found.',
      'P0002',
      jsonb_build_object('homeId', p_home_id)
    );
  END IF;

  INSERT INTO public.home_usage_counters (home_id)
  VALUES (p_home_id)
  ON CONFLICT (home_id) DO NOTHING;

  IF p_deltas IS NOT NULL AND jsonb_typeof(p_deltas) = 'object' THEN
    IF jsonb_typeof(p_deltas->'active_chores') = 'number' THEN
      v_active_chores_delta := (p_deltas->>'active_chores')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'chore_photos') = 'number' THEN
      v_chore_photos_delta := (p_deltas->>'chore_photos')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'active_members') = 'number' THEN
      v_active_members_delta := (p_deltas->>'active_members')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'active_expenses') = 'number' THEN
      v_active_expenses_delta := (p_deltas->>'active_expenses')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'shopping_item_photos') = 'number' THEN
      v_shopping_item_photos_delta := (p_deltas->>'shopping_item_photos')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'expense_photos') = 'number' THEN
      v_expense_photos_delta := (p_deltas->>'expense_photos')::integer;
    END IF;

    IF jsonb_typeof(p_deltas->'house_directory_note_photos') = 'number' THEN
      v_house_directory_note_photos_delta := (p_deltas->>'house_directory_note_photos')::integer;
    END IF;
  END IF;

  UPDATE public.home_usage_counters h
     SET active_chores               = GREATEST(0, COALESCE(h.active_chores, 0) + v_active_chores_delta),
         chore_photos                = GREATEST(0, COALESCE(h.chore_photos, 0) + v_chore_photos_delta),
         active_members              = GREATEST(0, COALESCE(h.active_members, 0) + v_active_members_delta),
         active_expenses             = GREATEST(0, COALESCE(h.active_expenses, 0) + v_active_expenses_delta),
         shopping_item_photos        = GREATEST(0, COALESCE(h.shopping_item_photos, 0) + v_shopping_item_photos_delta),
         expense_photos              = GREATEST(0, COALESCE(h.expense_photos, 0) + v_expense_photos_delta),
         house_directory_note_photos = GREATEST(0, COALESCE(h.house_directory_note_photos, 0) + v_house_directory_note_photos_delta),
         updated_at                  = now()
   WHERE h.home_id = p_home_id
   RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."_home_usage_apply_delta"("p_home_id" "uuid", "p_deltas" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_assert_owner"("p_home_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  PERFORM public._assert_authenticated();

  IF NOT public.is_home_owner(p_home_id, auth.uid()) THEN
    PERFORM public.api_error(
      'FORBIDDEN_OWNER_ONLY',
      'Only the home owner can perform this action.',
      '42501',
      jsonb_build_object('home_id', p_home_id)
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."_house_directory_assert_owner"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_assert_valid_reminder_offset"("p_term_start_date" "date", "p_term_end_date" "date", "p_offset_value" integer, "p_offset_unit" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_due_at date;
BEGIN
  IF p_offset_value IS NULL AND p_offset_unit IS NULL THEN
    RETURN;
  END IF;

  v_due_at := public._house_directory_compute_renewal_due_at(
    p_term_start_date,
    p_term_end_date,
    p_offset_value,
    p_offset_unit
  );

  PERFORM public.api_assert(
    v_due_at IS NOT NULL,
    'HOUSE_DIRECTORY_INVALID_REMINDER_OFFSET',
    'Reminder offset falls outside the service term.',
    '22023',
    jsonb_build_object(
      'term_start_date', p_term_start_date,
      'term_end_date', p_term_end_date,
      'renewal_reminder_offset_value', p_offset_value,
      'renewal_reminder_offset_unit', p_offset_unit
    )
  );
END;
$$;


ALTER FUNCTION "public"."_house_directory_assert_valid_reminder_offset"("p_term_start_date" "date", "p_term_end_date" "date", "p_offset_value" integer, "p_offset_unit" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_build_wifi_qr"("p_ssid" "text", "p_password" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_ssid text := public._house_directory_escape_qr_part(p_ssid);
  v_password text := public._house_directory_escape_qr_part(p_password);
BEGIN
  -- Simplified consumer-wifi assumption.
  -- Works for most standard home Wi-Fi networks.
  -- - open network => nopass
  -- - password-based network => WPA
  -- Hidden SSIDs, enterprise auth, and uncommon security modes are out of scope for v1.
  IF p_password IS NULL THEN
    RETURN format('WIFI:T:nopass;S:%s;;', v_ssid);
  END IF;

  RETURN format('WIFI:T:WPA;S:%s;P:%s;;', v_ssid, v_password);
END;
$$;


ALTER FUNCTION "public"."_house_directory_build_wifi_qr"("p_ssid" "text", "p_password" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_compute_renewal_due_at"("p_term_start_date" "date", "p_term_end_date" "date", "p_offset_value" integer, "p_offset_unit" "text") RETURNS "date"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_offset_value integer := COALESCE(p_offset_value, 3);
  v_offset_unit text := COALESCE(p_offset_unit, 'month');
  v_due_at date;
BEGIN
  IF p_term_start_date IS NULL OR p_term_end_date IS NULL THEN
    RETURN NULL;
  END IF;

  IF v_offset_value < 1 THEN
    RETURN NULL;
  END IF;

  IF v_offset_unit = 'day' THEN
    v_due_at := (p_term_end_date::timestamp - make_interval(days => v_offset_value))::date;
  ELSIF v_offset_unit = 'week' THEN
    v_due_at := (p_term_end_date::timestamp - make_interval(days => v_offset_value * 7))::date;
  ELSIF v_offset_unit = 'month' THEN
    v_due_at := (p_term_end_date::timestamp - make_interval(months => v_offset_value))::date;
  ELSE
    RETURN NULL;
  END IF;

  IF v_due_at < p_term_start_date OR v_due_at > p_term_end_date THEN
    RETURN NULL;
  END IF;

  RETURN v_due_at;
END;
$$;


ALTER FUNCTION "public"."_house_directory_compute_renewal_due_at"("p_term_start_date" "date", "p_term_end_date" "date", "p_offset_value" integer, "p_offset_unit" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_due_reminders_json"("p_home_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
  WITH due_rows AS (
    SELECT
      r.id,
      r.service_id,
      r.reminder_kind,
      r.status,
      r.term_start_date,
      r.term_end_date,
      r.due_at,
      r.dismissed_at,
      r.dismissed_by_user_id,
      s.service_type,
      s.provider_name,
      s.custom_label,
      s.link_url
    FROM public.home_directory_service_reminders r
    JOIN public.home_directory_services s
      ON s.id = r.service_id
    WHERE s.home_id = p_home_id
      AND r.reminder_kind = 'renewal'
      AND r.status = 'active'
      AND s.archived_at IS NULL
      AND s.term_start_date = r.term_start_date
      AND s.term_end_date = r.term_end_date
      AND public._house_directory_today_utc() >= r.due_at
      AND NOT EXISTS (
        SELECT 1
        FROM public.home_directory_service_reminder_acknowledgements ra
        WHERE ra.reminder_id = r.id
          AND ra.user_id = p_user_id
      )
  )
  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'id', d.id,
               'service_id', d.service_id,
               'reminder_kind', d.reminder_kind,
               'status', d.status,
               'term_start_date', d.term_start_date,
               'term_end_date', d.term_end_date,
               'due_at', d.due_at,
               'service_type', d.service_type,
               'provider_name', d.provider_name,
               'custom_label', d.custom_label,
               'link_url', d.link_url,
               'acknowledged_by_me', false
             )
             ORDER BY d.due_at, lower(d.provider_name), d.service_id
           ),
           '[]'::jsonb
         )
  FROM due_rows d;
$$;


ALTER FUNCTION "public"."_house_directory_due_reminders_json"("p_home_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_escape_qr_part"("p_value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
  SELECT replace(
           replace(
             replace(
               replace(COALESCE(p_value, ''), E'\\', E'\\\\'),
               ';', E'\\;'
             ),
             ',', E'\\,'
           ),
           ':', E'\\:'
         );
$$;


ALTER FUNCTION "public"."_house_directory_escape_qr_part"("p_value" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_directory_reconcile_service_reminder"("p_service_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_service public.home_directory_services%ROWTYPE;
  v_due_at date;
  v_target public.home_directory_service_reminders%ROWTYPE;
  v_had_target boolean := false;
  v_material_change boolean := false;
BEGIN
  -- Lock the service row first.
  SELECT *
    INTO v_service
  FROM public.home_directory_services
  WHERE id = p_service_id
  FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_SERVICE_NOT_FOUND',
      'House directory service was not found.',
      'P0002',
      jsonb_build_object('service_id', p_service_id)
    );
  END IF;

  -- Archived service => retire all reminder rows for that service.
  IF v_service.archived_at IS NOT NULL THEN
    UPDATE public.home_directory_service_reminders r
       SET status = 'retired'
     WHERE r.service_id = v_service.id
       AND r.reminder_kind = 'renewal'
       AND r.status <> 'retired';

    RETURN;
  END IF;

  v_due_at := public._house_directory_compute_renewal_due_at(
    v_service.term_start_date,
    v_service.term_end_date,
    v_service.renewal_reminder_offset_value,
    v_service.renewal_reminder_offset_unit
  );

  -- No valid due date => retire all reminder rows for that service.
  IF v_due_at IS NULL THEN
    UPDATE public.home_directory_service_reminders r
       SET status = 'retired'
     WHERE r.service_id = v_service.id
       AND r.reminder_kind = 'renewal'
       AND r.status <> 'retired';

    RETURN;
  END IF;

  -- Find the current non-retired reminder row for the current term, if any.
  SELECT *
    INTO v_target
  FROM public.home_directory_service_reminders r
  WHERE r.service_id = v_service.id
    AND r.reminder_kind = 'renewal'
    AND r.term_start_date = v_service.term_start_date
    AND r.term_end_date = v_service.term_end_date
    AND r.status <> 'retired'
  FOR UPDATE;

  v_had_target := FOUND;

  IF NOT v_had_target THEN
    -- There is no current live reminder row for this term, but there may be
    -- a retired row already occupying the unique key. Reopen/refresh it.
    UPDATE public.home_directory_service_reminders r
       SET due_at = v_due_at,
           status = 'active',
           dismissed_at = NULL,
           dismissed_by_user_id = NULL
     WHERE r.service_id = v_service.id
       AND r.reminder_kind = 'renewal'
       AND r.term_start_date = v_service.term_start_date
       AND r.term_end_date = v_service.term_end_date
    RETURNING * INTO v_target;

    IF FOUND THEN
      v_material_change := true;
    ELSE
      INSERT INTO public.home_directory_service_reminders (
        service_id,
        reminder_kind,
        status,
        term_start_date,
        term_end_date,
        due_at
      )
      VALUES (
        v_service.id,
        'renewal',
        'active',
        v_service.term_start_date,
        v_service.term_end_date,
        v_due_at
      )
      RETURNING * INTO v_target;

      v_material_change := true;
    END IF;
  ELSE
    -- Compare old vs new state explicitly.
    v_material_change :=
      v_target.due_at IS DISTINCT FROM v_due_at
      OR v_target.status <> 'active';

    IF v_material_change THEN
      UPDATE public.home_directory_service_reminders r
         SET due_at = v_due_at,
             status = 'active',
             dismissed_at = NULL,
             dismissed_by_user_id = NULL
       WHERE r.id = v_target.id
      RETURNING * INTO v_target;
    END IF;
  END IF;

  -- If materially changed, reopen visibility for members.
  IF v_material_change THEN
    DELETE FROM public.home_directory_service_reminder_acknowledgements ra
    WHERE ra.reminder_id = v_target.id;
  END IF;

  -- Retire any other reminder rows for this service that are no longer current.
  UPDATE public.home_directory_service_reminders r
     SET status = 'retired'
   WHERE r.service_id = v_service.id
     AND r.reminder_kind = 'renewal'
     AND r.id <> v_target.id
     AND r.status <> 'retired';

END;
$$;


ALTER FUNCTION "public"."_house_directory_reconcile_service_reminder"("p_service_id" "uuid") OWNER TO "postgres";


