CREATE OR REPLACE FUNCTION "public"."_house_norms_generate_content"("p_inputs" "jsonb", "p_template_body" "jsonb", "p_locale_base" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO ''
    AS $$
DECLARE
  v_section_keys constant text[] := ARRAY[
    'norms_rhythm_quiet',
    'norms_shared_spaces',
    'norms_guests_social',
    'norms_responsibility_flow',
    'norms_repair_style',
    'norms_home_identity'
  ];
  v_section_key text;
  v_section_option text;
  v_section_title_key text;
  v_section_text text;
  v_sections jsonb := '{}'::jsonb;

  v_prop_i text;
  v_rel_i text;
  v_property text;
  v_relation text;
  v_context_template text;
  v_context_line text;

  v_summary_title_key text;
  v_summary_subtitle_key text;
  v_summary_framing text;
BEGIN
  PERFORM public.api_assert(
    jsonb_typeof(p_template_body) = 'object',
    'HOUSE_NORMS_INVALID_TEMPLATE',
    'Template body must be a JSON object.',
    '22023'
  );

  v_summary_title_key := nullif(btrim(p_template_body #>> '{summary,title_key}'), '');
  v_summary_subtitle_key := nullif(btrim(p_template_body #>> '{summary,subtitle_key}'), '');
  v_summary_framing := nullif(btrim(p_template_body #>> '{summary,framing_default}'), '');

  PERFORM public.api_assert(
    v_summary_title_key IS NOT NULL
    AND v_summary_subtitle_key IS NOT NULL
    AND v_summary_framing IS NOT NULL,
    'HOUSE_NORMS_INVALID_TEMPLATE',
    'Template summary fields are required.',
    '22023'
  );

  v_prop_i := p_inputs ->> 'norms_property_context';
  v_rel_i := p_inputs ->> 'norms_relationship_model';

  v_property := nullif(
    btrim(p_template_body #>> ARRAY['context', 'property_context', v_prop_i]),
    ''
  );
  v_relation := nullif(
    btrim(p_template_body #>> ARRAY['context', 'relationship_model', v_rel_i]),
    ''
  );

  PERFORM public.api_assert(
    v_property IS NOT NULL
    AND v_relation IS NOT NULL,
    'HOUSE_NORMS_INVALID_TEMPLATE',
    'Template context options are missing.',
    '22023',
    jsonb_build_object(
      'norms_property_context', v_prop_i,
      'norms_relationship_model', v_rel_i
    )
  );

  v_context_template := nullif(btrim(p_template_body #>> '{context,line_template}'), '');
  PERFORM public.api_assert(
    v_context_template IS NOT NULL,
    'HOUSE_NORMS_INVALID_TEMPLATE',
    'Template context line_template is required.',
    '22023'
  );

  v_context_line := replace(
    replace(v_context_template, '{{property_context}}', v_property),
    '{{relationship_model}}',
    v_relation
  );

  FOREACH v_section_key IN ARRAY v_section_keys LOOP
    v_section_option := p_inputs ->> v_section_key;
    v_section_title_key := nullif(
      btrim(p_template_body #>> ARRAY['sections', v_section_key, 'title_key']),
      ''
    );
    v_section_text := nullif(
      btrim(p_template_body #>> ARRAY['sections', v_section_key, 'options', v_section_option]),
      ''
    );

    PERFORM public.api_assert(
      v_section_title_key IS NOT NULL
      AND v_section_text IS NOT NULL,
      'HOUSE_NORMS_INVALID_TEMPLATE',
      'Template section data is missing.',
      '22023',
      jsonb_build_object(
        'section_key', v_section_key,
        'option', v_section_option
      )
    );

    v_sections := v_sections || jsonb_build_object(
      v_section_key,
      jsonb_build_object(
        'title_key', v_section_title_key,
        'text', v_section_text
      )
    );
  END LOOP;

  RETURN jsonb_build_object(
    'locale_base', p_locale_base,
    'summary', jsonb_build_object(
      'title_key', v_summary_title_key,
      'subtitle_key', v_summary_subtitle_key,
      'framing', v_summary_framing
    ),
    'context', jsonb_build_object(
      'line', v_context_line
    ),
    'sections', v_sections
  );
END;
$$;


ALTER FUNCTION "public"."_house_norms_generate_content"("p_inputs" "jsonb", "p_template_body" "jsonb", "p_locale_base" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_generate_public_id"() RETURNS "public"."citext"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_candidate text;
  v_try int := 0;
BEGIN
  LOOP
    v_try := v_try + 1;
    v_candidate := lower(substring(replace(gen_random_uuid()::text, '-', '') from 1 for 12));

    EXIT WHEN NOT EXISTS (
      SELECT 1
      FROM public.house_norms hn
      WHERE hn.home_public_id = v_candidate::public.citext
    );

    IF v_try >= 50 THEN
      PERFORM public.api_error(
        'HOUSE_NORMS_PUBLIC_ID_GENERATION_FAILED',
        'Failed to allocate a unique public id.',
        'P0001'
      );
    END IF;
  END LOOP;

  RETURN v_candidate::public.citext;
END;
$$;


ALTER FUNCTION "public"."_house_norms_generate_public_id"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_inputs_valid"("p_inputs" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO ''
    AS $_$
DECLARE
  v_required_keys constant text[] := ARRAY[
    'norms_property_context',
    'norms_relationship_model',
    'norms_rhythm_quiet',
    'norms_shared_spaces',
    'norms_guests_social',
    'norms_responsibility_flow',
    'norms_repair_style',
    'norms_home_identity'
  ];
  v_key text;
  v_val_text text;
  v_max_bytes constant int := 2048;
BEGIN
  IF p_inputs IS NULL OR jsonb_typeof(p_inputs) <> 'object' THEN
    RETURN false;
  END IF;

  IF octet_length(p_inputs::text) > v_max_bytes THEN
    RETURN false;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM unnest(v_required_keys) AS k
    WHERE NOT (p_inputs ? k)
  ) THEN
    RETURN false;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM jsonb_object_keys(p_inputs) AS k
    WHERE NOT (k = ANY(v_required_keys))
  ) THEN
    RETURN false;
  END IF;

  FOREACH v_key IN ARRAY v_required_keys LOOP
    v_val_text := p_inputs ->> v_key;
    IF v_val_text IS NULL OR v_val_text !~ '^[0-2]$' THEN
      RETURN false;
    END IF;
  END LOOP;

  RETURN true;
END;
$_$;


ALTER FUNCTION "public"."_house_norms_inputs_valid"("p_inputs" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_next_published_version"("p_prev" "text") RETURNS "text"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO ''
    AS $_$
DECLARE
  v_next int;
BEGIN
  IF p_prev IS NULL OR btrim(p_prev) = '' THEN
    RETURN 'v000001';
  END IF;

  IF p_prev !~ '^v[0-9]{6}$' THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_INVALID_PUBLISHED_VERSION',
      'Invalid published version format.',
      '22023',
      jsonb_build_object('published_version', p_prev)
    );
  END IF;

  v_next := substring(p_prev from 2)::int + 1;
  RETURN 'v' || lpad(v_next::text, 6, '0');
END;
$_$;


ALTER FUNCTION "public"."_house_norms_next_published_version"("p_prev" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_publish_job_dispatch"("p_job_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_job public.house_norms_publish_jobs%ROWTYPE;
  v_supabase_url text;
  v_secret text;
  v_request_id bigint;
BEGIN
  SELECT *
    INTO v_job
  FROM public.house_norms_publish_jobs j
  WHERE j.job_id = p_job_id;

  IF v_job.job_id IS NULL THEN
    RETURN jsonb_build_object(
      'ok', false,
      'reason', 'not_found',
      'job_id', p_job_id
    );
  END IF;

  IF v_job.status = 'succeeded' THEN
    RETURN jsonb_build_object(
      'ok', true,
      'job_id', p_job_id,
      'skipped', 'already_succeeded'
    );
  END IF;

  IF v_job.status <> 'dispatching' THEN
    RETURN jsonb_build_object(
      'ok', false,
      'job_id', p_job_id,
      'reason', 'not_dispatching_state',
      'status', v_job.status
    );
  END IF;

  BEGIN
    SELECT s.decrypted_secret
      INTO v_supabase_url
    FROM vault.decrypted_secrets s
    WHERE s.name = 'SUPABASE_URL'
    LIMIT 1;
  EXCEPTION
    WHEN undefined_table OR insufficient_privilege THEN
      v_supabase_url := NULL;
  END;

  BEGIN
    SELECT s.decrypted_secret
      INTO v_secret
    FROM vault.decrypted_secrets s
    WHERE s.name = 'WORKER_SHARED_SECRET'
    LIMIT 1;
  EXCEPTION
    WHEN undefined_table OR insufficient_privilege THEN
      v_secret := NULL;
  END;

  IF v_supabase_url IS NULL OR btrim(v_supabase_url) = '' THEN
    v_supabase_url := NULLIF(current_setting('app.settings.supabase_url', true), '');
  END IF;

  IF v_secret IS NULL OR btrim(v_secret) = '' THEN
    v_secret := NULLIF(current_setting('app.settings.worker_shared_secret', true), '');
  END IF;

  IF v_supabase_url IS NULL OR v_secret IS NULL THEN
    UPDATE public.house_norms_publish_jobs
    SET status = 'failed',
        current_stage = 'dispatch_config',
        last_error_code = 'dispatch_config_missing',
        last_error = 'Publish job dispatch missing SUPABASE_URL or WORKER_SHARED_SECRET.',
        last_error_at = now(),
        heartbeat_at = now(),
        processed_at = now()
    WHERE job_id = p_job_id
      AND status = 'dispatching';

    RETURN jsonb_build_object(
      'ok', false,
      'job_id', p_job_id,
      'reason', 'dispatch_config_missing'
    );
  END IF;

  BEGIN
    SELECT net.http_post(
      url := v_supabase_url || '/functions/v1/house_norms_publish_sync',
      headers := jsonb_strip_nulls(jsonb_build_object(
        'Content-Type', 'application/json',
        'x-internal-secret', v_secret
      )),
      body := v_job.payload || jsonb_build_object(
        'publish_job_id', v_job.job_id
      )
    )
      INTO v_request_id;
  EXCEPTION
    WHEN OTHERS THEN
      UPDATE public.house_norms_publish_jobs
      SET status = 'failed',
          current_stage = 'dispatch_enqueue',
          last_error_code = SQLSTATE,
          last_error = left(SQLERRM, 1000),
          last_error_at = now(),
          heartbeat_at = now(),
          processed_at = now()
      WHERE job_id = p_job_id
        AND status = 'dispatching';

      RETURN jsonb_build_object(
        'ok', false,
        'job_id', p_job_id,
        'reason', 'dispatch_enqueue_failed',
        'sqlstate', SQLSTATE
      );
  END;

  UPDATE public.house_norms_publish_jobs
  SET current_stage = 'dispatch_queued',
      last_request_id = v_request_id::text,
      last_error_code = NULL,
      last_error = NULL,
      last_error_at = NULL,
      heartbeat_at = now()
  WHERE job_id = p_job_id
    AND status = 'dispatching';

  RETURN jsonb_build_object(
    'ok', true,
    'job_id', p_job_id,
    'request_id', v_request_id
  );
END;
$$;


ALTER FUNCTION "public"."_house_norms_publish_job_dispatch"("p_job_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_publish_sync_call"("p_home_public_id" "text", "p_published_at" timestamp with time zone, "p_published_version" "text", "p_template_key" "text", "p_locale_base" "text", "p_published_content" "jsonb", "p_public_url_path" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_supabase_url text;
  v_secret text;
  v_published_at_iso text := public._to_iso_utc_ms(p_published_at);
  v_http_url text;

  v_req_id bigint;
  v_started timestamptz := clock_timestamp();
  -- Keep below authenticated role timeout budget (currently 8s in runtime env).
  v_deadline interval := interval '7 seconds';
  -- Explicit pg_net timeout to avoid relying on default (often 5000 ms).
  v_http_timeout_milliseconds integer := 6500;
  v_status_code int;
  v_content text;
  v_error_msg text;
  v_body jsonb := '{}'::jsonb;
  v_edge_error_code text;
  v_edge_error_details text;
  v_artifact_ok boolean := false;
  v_revalidate_ok boolean := false;
BEGIN
  BEGIN
    SELECT s.decrypted_secret
      INTO v_supabase_url
    FROM vault.decrypted_secrets s
    WHERE s.name = 'SUPABASE_URL'
    LIMIT 1;
  EXCEPTION
    WHEN undefined_table OR insufficient_privilege THEN
      v_supabase_url := NULL;
  END;

  BEGIN
    SELECT s.decrypted_secret
      INTO v_secret
    FROM vault.decrypted_secrets s
    WHERE s.name = 'WORKER_SHARED_SECRET'
    LIMIT 1;
  EXCEPTION
    WHEN undefined_table OR insufficient_privilege THEN
      v_secret := NULL;
  END;

  IF v_supabase_url IS NULL OR btrim(v_supabase_url) = '' THEN
    v_supabase_url := NULLIF(current_setting('app.settings.supabase_url', true), '');
  END IF;

  IF v_secret IS NULL OR btrim(v_secret) = '' THEN
    v_secret := NULLIF(current_setting('app.settings.worker_shared_secret', true), '');
  END IF;

  IF v_supabase_url IS NULL THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      'Publish sync config missing SUPABASE_URL.',
      'P0001',
      jsonb_build_object(
        'stage', 'config',
        'missing', 'SUPABASE_URL',
        'lookup_order', jsonb_build_array(
          'vault.decrypted_secrets.SUPABASE_URL',
          'app.settings.supabase_url'
        )
      )
    );
  END IF;

  IF v_secret IS NULL THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      'Publish sync config missing WORKER_SHARED_SECRET.',
      'P0001',
      jsonb_build_object(
        'stage', 'config',
        'missing', 'WORKER_SHARED_SECRET',
        'lookup_order', jsonb_build_array(
          'vault.decrypted_secrets.WORKER_SHARED_SECRET',
          'app.settings.worker_shared_secret'
        )
      )
    );
  END IF;

  v_http_url := v_supabase_url || '/functions/v1/house_norms_publish_sync';

  v_req_id := net.http_post(
    url := v_http_url,
    headers := jsonb_strip_nulls(jsonb_build_object(
      'Content-Type', 'application/json',
      'x-internal-secret', v_secret
    )),
    body := jsonb_build_object(
      'home_public_id', p_home_public_id,
      'published_at', v_published_at_iso,
      'published_version', p_published_version,
      'template_key', p_template_key,
      'locale_base', p_locale_base,
      'published_content', p_published_content,
      'public_url_path', p_public_url_path
    ),
    timeout_milliseconds := v_http_timeout_milliseconds
  );

  LOOP
    SELECT r.status_code, r.content, r.error_msg
      INTO v_status_code, v_content, v_error_msg
    FROM net._http_response r
    WHERE r.id = v_req_id
    ORDER BY r.created DESC
    LIMIT 1;

    EXIT WHEN v_status_code IS NOT NULL
           OR v_error_msg IS NOT NULL
           OR clock_timestamp() - v_started > v_deadline;

    PERFORM pg_sleep(0.10);
  END LOOP;

  IF v_error_msg IS NOT NULL THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      'Publish sync HTTP request failed before receiving a response.',
      'P0001',
      jsonb_build_object(
        'stage', 'http_post',
        'request_id', v_req_id,
        'url', v_http_url,
        'error', v_error_msg,
        'timeout_milliseconds', v_http_timeout_milliseconds,
        'timeout_seconds', EXTRACT(epoch FROM v_deadline)
      )
    );
  END IF;

  IF v_status_code IS NULL THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      'Publish sync request timed out waiting for edge response.',
      'P0001',
      jsonb_build_object(
        'stage', 'wait_response',
        'request_id', v_req_id,
        'url', v_http_url,
        'timeout_seconds', EXTRACT(epoch FROM v_deadline),
        'timeout_milliseconds', v_http_timeout_milliseconds
      )
    );
  END IF;

  IF v_status_code BETWEEN 200 AND 299 THEN
    BEGIN
      v_body := COALESCE(v_content, '{}')::jsonb;
    EXCEPTION WHEN others THEN
      PERFORM public.api_error(
        'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
        'Publish sync returned success status but invalid JSON body.',
        'P0001',
        jsonb_build_object(
          'stage', 'parse_response',
          'request_id', v_req_id,
          'status_code', v_status_code,
          'body', left(COALESCE(v_content, ''), 1200)
        )
      );
    END;
  ELSE
    BEGIN
      v_body := COALESCE(v_content, '{}')::jsonb;
    EXCEPTION WHEN others THEN
      v_body := jsonb_build_object('raw_body', left(COALESCE(v_content, ''), 1200));
    END;

    v_edge_error_code := nullif(v_body->>'error_code', '');
    v_edge_error_details := nullif(v_body->>'details', '');

    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      format('Publish sync returned non-success status (%s).', v_status_code),
      'P0001',
      jsonb_strip_nulls(jsonb_build_object(
        'stage', 'edge_response',
        'request_id', v_req_id,
        'status_code', v_status_code,
        'url', v_http_url,
        'edge_error_code', v_edge_error_code,
        'edge_error_details', v_edge_error_details,
        'body', v_body,
        'likely_causes',
          CASE
            WHEN v_status_code = 401 THEN jsonb_build_array(
              'WORKER_SHARED_SECRET mismatch between database config and edge function env.',
              'Edge function JWT verification is enabled; internal calls need verify_jwt=false.'
            )
            WHEN v_status_code = 400 THEN jsonb_build_array(
              'Payload validation failed in house_norms_publish_sync.'
            )
            WHEN v_status_code = 413 THEN jsonb_build_array(
              'Published payload exceeded edge size limits.'
            )
            WHEN v_status_code >= 500 THEN jsonb_build_array(
              'Missing edge env vars (SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, WORKER_SHARED_SECRET, VERCEL_REVALIDATE_URL, VERCEL_REVALIDATE_SECRET).',
              'Storage artifact write failed, or revalidation endpoint failed.'
            )
            ELSE NULL
          END
      ))
    );
  END IF;

  v_edge_error_code := nullif(v_body->>'error_code', '');
  v_edge_error_details := nullif(v_body->>'details', '');
  v_artifact_ok := lower(COALESCE(v_body->>'artifact_ok', 'false')) IN ('true', 't', '1');
  v_revalidate_ok := lower(COALESCE(v_body->>'revalidate_ok', 'false')) IN ('true', 't', '1');

  IF NOT v_artifact_ok THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_ARTIFACT_FAILED',
      'Publish artifact write failed.',
      'P0001',
      jsonb_strip_nulls(jsonb_build_object(
        'stage', 'artifact_check',
        'request_id', v_req_id,
        'status_code', v_status_code,
        'edge_error_code', v_edge_error_code,
        'edge_error_details', v_edge_error_details,
        'body', v_body
      ))
    );
  END IF;

  IF NOT v_revalidate_ok THEN
    PERFORM public.api_error(
      'HOUSE_NORMS_PUBLISH_REVALIDATE_FAILED',
      'Publish revalidation failed.',
      'P0001',
      jsonb_strip_nulls(jsonb_build_object(
        'stage', 'revalidate_check',
        'request_id', v_req_id,
        'status_code', v_status_code,
        'edge_error_code', v_edge_error_code,
        'edge_error_details', v_edge_error_details,
        'body', v_body
      ))
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."_house_norms_publish_sync_call"("p_home_public_id" "text", "p_published_at" timestamp with time zone, "p_published_version" "text", "p_template_key" "text", "p_locale_base" "text", "p_published_content" "jsonb", "p_public_url_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_house_norms_section_key_valid"("p_section_key" "text") RETURNS boolean
