CREATE TABLE IF NOT EXISTS "public"."member_cap_join_requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "home_id" "uuid" NOT NULL,
    "joiner_user_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "resolved_at" timestamp with time zone,
    "resolved_reason" "text",
    "resolved_payload" "jsonb",
    "resolution_notified_at" timestamp with time zone,
    CONSTRAINT "member_cap_join_requests_resolved_reason_check" CHECK (("resolved_reason" = ANY (ARRAY['joined'::"text", 'joiner_superseded'::"text", 'home_inactive'::"text", 'invite_missing'::"text", 'owner_dismissed'::"text"])))
);


ALTER TABLE "public"."member_cap_join_requests" OWNER TO "postgres";


COMMENT ON TABLE "public"."member_cap_join_requests" IS 'Queue of join attempts blocked by member cap; resolved on owner upgrade/dismiss. Joiner names are read live from profiles.';



COMMENT ON COLUMN "public"."member_cap_join_requests"."resolution_notified_at" IS 'Set when the owner has been notified about the resolved join request.';



CREATE OR REPLACE FUNCTION "public"."_member_cap_enqueue_request"("p_home_id" "uuid", "p_joiner_user_id" "uuid") RETURNS "public"."member_cap_join_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_row public.member_cap_join_requests;
BEGIN
  IF p_home_id IS NULL OR p_joiner_user_id IS NULL THEN
    PERFORM public.api_error('INVALID_INPUT', 'home_id and joiner_user_id are required.', '22023');
  END IF;

  INSERT INTO public.member_cap_join_requests (home_id, joiner_user_id)
  VALUES (p_home_id, p_joiner_user_id)
  ON CONFLICT (home_id, joiner_user_id) WHERE resolved_at IS NULL DO UPDATE
    SET home_id = EXCLUDED.home_id  -- no-op; keeps RETURNING working
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."_member_cap_enqueue_request"("p_home_id" "uuid", "p_joiner_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_member_cap_resolve_requests"("p_home_id" "uuid", "p_reason" "text", "p_request_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_payload" "jsonb" DEFAULT NULL::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  IF p_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_INPUT', 'home_id is required.', '22023');
  END IF;

  IF p_reason IS NULL THEN
    PERFORM public.api_error('INVALID_REASON', 'resolved_reason is required.', '22023');
  END IF;

  UPDATE public.member_cap_join_requests
     SET resolved_at      = now(),
         resolved_reason  = p_reason,
         resolved_payload = p_payload
   WHERE home_id = p_home_id
     AND resolved_at IS NULL
     AND (p_request_ids IS NULL OR id = ANY(p_request_ids));
END;
$$;


ALTER FUNCTION "public"."_member_cap_resolve_requests"("p_home_id" "uuid", "p_reason" "text", "p_request_ids" "uuid"[], "p_payload" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_member_directory_assert_same_active_home"("p_target_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_my_home_id uuid;
  v_target_home_id uuid;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_target_user_id IS NULL THEN
    PERFORM public.api_error(
      'MEMBER_DIRECTORY_INVALID_INPUT',
      'target_user_id is required.',
      '22023'
    );
  END IF;

  IF p_target_user_id = v_user THEN
    RETURN;
  END IF;

  v_my_home_id := public._member_directory_get_current_active_home_id(v_user);
  v_target_home_id := public._member_directory_get_current_active_home_id(p_target_user_id);

  IF v_my_home_id IS DISTINCT FROM v_target_home_id THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You do not share an active home with this member.',
      '42501',
      jsonb_build_object('target_user_id', p_target_user_id)
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."_member_directory_assert_same_active_home"("p_target_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_member_directory_assert_same_active_home"("p_target_user_id" "uuid") IS 'Internal helper that allows access only when the authenticated user is the target user or shares the same active home with the target user.';



CREATE OR REPLACE FUNCTION "public"."_member_directory_assert_valid_photo_path"("p_user_id" "uuid", "p_photo_path" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_home_id uuid;
  v_expected_prefix text;
BEGIN
  IF p_photo_path IS NULL THEN
    RETURN;
  END IF;

  v_home_id := public._member_directory_get_current_active_home_id(p_user_id);

  -- Assumes photo_path stores the object key inside the households bucket.
  -- Expected shape:
  --   house_directory/{home_id}/member_directory/{user_id}/...
  v_expected_prefix :=
    'house_directory/' || v_home_id::text || '/member_directory/' || p_user_id::text || '/';

  PERFORM public.api_assert(
    p_photo_path LIKE v_expected_prefix || '%',
    'MEMBER_DIRECTORY_NOTE_INVALID_PHOTO_PATH',
    'photo_path must be under house_directory/{home_id}/member_directory/{user_id}/ in the households bucket.',
    '22023'
  );
END;
$$;


ALTER FUNCTION "public"."_member_directory_assert_valid_photo_path"("p_user_id" "uuid", "p_photo_path" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_member_directory_assert_valid_photo_path"("p_user_id" "uuid", "p_photo_path" "text") IS 'Internal helper that validates note photo_path against the user current active home and expected households-bucket object key prefix. Validation is path-shape only.';



CREATE OR REPLACE FUNCTION "public"."_member_directory_enforce_other_note_limit"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_other_count integer;
BEGIN
  IF NEW.note_type <> 'other' OR NEW.archived_at IS NOT NULL THEN
    RETURN NEW;
  END IF;

  SELECT count(*)
    INTO v_other_count
  FROM public.member_directory_notes n
  WHERE n.user_id = NEW.user_id
    AND n.note_type = 'other'
    AND n.archived_at IS NULL
    AND n.id <> COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid);

  IF v_other_count >= 20 THEN
    PERFORM public.api_error(
      'MEMBER_DIRECTORY_OTHER_NOTE_LIMIT_REACHED',
      'At most 20 active other notes are allowed.',
      '22023'
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."_member_directory_enforce_other_note_limit"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_member_directory_enforce_other_note_limit"() IS 'Internal trigger function that enforces the best-effort soft cap on active other notes per user.';



CREATE OR REPLACE FUNCTION "public"."_member_directory_get_current_active_home_id"("p_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_home_id uuid;
BEGIN
  IF p_user_id IS NULL THEN
    PERFORM public.api_error(
      'MEMBER_DIRECTORY_INVALID_INPUT',
      'user_id is required.',
      '22023'
    );
  END IF;

  SELECT m.home_id
    INTO v_home_id
  FROM public.memberships m
  JOIN public.homes h
    ON h.id = m.home_id
  WHERE m.user_id = p_user_id
    AND m.is_current = TRUE
    AND h.is_active = TRUE;

  IF v_home_id IS NULL THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'User does not belong to an active home.',
      '42501',
      jsonb_build_object('user_id', p_user_id)
    );
  END IF;

  RETURN v_home_id;
END;
$$;


ALTER FUNCTION "public"."_member_directory_get_current_active_home_id"("p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_member_directory_get_current_active_home_id"("p_user_id" "uuid") IS 'Internal helper that returns the user current active home id using the memberships table and an active home row.';



