CREATE OR REPLACE FUNCTION "public"."acknowledge_home_directory_reminder"("p_home_id" "uuid", "p_reminder_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_today_utc date := public._house_directory_today_utc();
  v_row public.home_directory_service_reminders%ROWTYPE;
  v_acknowledged_at timestamptz;
  v_exists_for_home boolean := false;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  SELECT true
    INTO v_exists_for_home
  FROM public.home_directory_service_reminders r
  JOIN public.home_directory_services s
    ON s.id = r.service_id
  WHERE r.id = p_reminder_id
    AND s.home_id = p_home_id
  LIMIT 1;

  IF NOT COALESCE(v_exists_for_home, false) THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_REMINDER_NOT_FOUND',
      'The reminder was not found for this home.',
      'P0002',
      jsonb_build_object(
        'home_id', p_home_id,
        'reminder_id', p_reminder_id
      )
    );
  END IF;

  SELECT r.*
    INTO v_row
  FROM public.home_directory_service_reminders r
  JOIN public.home_directory_services s
    ON s.id = r.service_id
  WHERE r.id = p_reminder_id
    AND s.home_id = p_home_id
    AND r.reminder_kind = 'renewal'
    AND r.status = 'active'
    AND s.archived_at IS NULL
    AND s.term_start_date = r.term_start_date
    AND s.term_end_date = r.term_end_date
    AND v_today_utc >= r.due_at;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_REMINDER_NOT_ACTIONABLE',
      'Reminder cannot be acknowledged because it is not currently actionable for this home.',
      '22023',
      jsonb_build_object(
        'home_id', p_home_id,
        'reminder_id', p_reminder_id
      )
    );
  END IF;

  INSERT INTO public.home_directory_service_reminder_acknowledgements (
    reminder_id,
    user_id
  )
  VALUES (
    v_row.id,
    v_user
  )
  ON CONFLICT (reminder_id, user_id) DO NOTHING;

  SELECT ra.acknowledged_at
    INTO v_acknowledged_at
  FROM public.home_directory_service_reminder_acknowledgements ra
  WHERE ra.reminder_id = v_row.id
    AND ra.user_id = v_user;

  RETURN jsonb_build_object(
    'ok', true,
    'reminder_id', v_row.id,
    'acknowledged_by_user_id', v_user,
    'acknowledged_at', v_acknowledged_at
  );
END;
$$;


ALTER FUNCTION "public"."acknowledge_home_directory_reminder"("p_home_id" "uuid", "p_reminder_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_feature_steps_get"("p_feature_key" "text") RETURNS "jsonb"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'feature_key', s.feature_key,
        'step_key', s.step_key,
        'step_order', s.step_order,
        'role_key', s.role_key,
        'stage', r.stage
      )
      ORDER BY s.step_order ASC
    ),
    '[]'::jsonb
  )
  FROM public.ai_feature_steps s
  JOIN public.ai_roles r
    ON r.role_key = s.role_key
  WHERE s.feature_key = p_feature_key
    AND s.active = true;
$$;


ALTER FUNCTION "public"."ai_feature_steps_get"("p_feature_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ai_role_route_get"("p_role_key" "text") RETURNS "jsonb"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT jsonb_build_object(
    'role_key', r.role_key,
    'stage', ar.stage,
    'provider', p.provider_key,
    'adapter_kind', p.adapter_kind,
    'base_url', p.base_url,
    'secret_name', p.secret_name,
    'model', m.model_key,
    'prompt_version', r.prompt_version,
    'execution_mode', r.execution_mode,
    'deterministic_fallback_allowed', r.deterministic_fallback_allowed,
    'max_retries', r.max_retries
  )
  FROM public.ai_role_routes r
  JOIN public.ai_models m
    ON m.model_id = r.model_id
  JOIN public.ai_providers p
    ON p.provider_id = m.provider_id
  JOIN public.ai_roles ar
    ON ar.role_key = r.role_key
  WHERE r.role_key = p_role_key
    AND r.active = true
    AND m.active = true
    AND p.active = true;
$$;


ALTER FUNCTION "public"."ai_role_route_get"("p_role_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."api_assert"("p_condition" boolean, "p_code" "text", "p_msg" "text", "p_sqlstate" "text" DEFAULT 'P0001'::"text", "p_details" "jsonb" DEFAULT NULL::"jsonb", "p_hint" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
BEGIN
  IF NOT coalesce(p_condition, false) THEN
    PERFORM public.api_error(p_code, p_msg, p_sqlstate, p_details, p_hint);
  END IF;
END;
$$;


ALTER FUNCTION "public"."api_assert"("p_condition" boolean, "p_code" "text", "p_msg" "text", "p_sqlstate" "text", "p_details" "jsonb", "p_hint" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."api_error"("p_code" "text", "p_msg" "text", "p_sqlstate" "text" DEFAULT 'P0001'::"text", "p_details" "jsonb" DEFAULT NULL::"jsonb", "p_hint" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  v_message text;
  v_detail  text;
BEGIN
  -- Build a structured JSON error message.
  v_message := pg_catalog.json_build_object(
    'code',    p_code,
    'message', p_msg,
    'details', COALESCE(p_details, '{}'::jsonb)
  )::text;

  -- DETAIL should never be NULL in RAISE ... USING
  v_detail := COALESCE(p_details::text, '');

  RAISE EXCEPTION USING
    MESSAGE = COALESCE(v_message, 'Unknown error'),
    ERRCODE = COALESCE(p_sqlstate, 'P0001'),
    DETAIL  = v_detail,
    HINT    = COALESCE(p_hint, '');
END;
$$;


ALTER FUNCTION "public"."api_error"("p_code" "text", "p_msg" "text", "p_sqlstate" "text", "p_details" "jsonb", "p_hint" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."archive_home_directory_note"("p_home_id" "uuid", "p_note_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_note public.home_directory_notes%ROWTYPE;
  v_existing public.home_directory_notes%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_active(p_home_id);
  PERFORM public._house_directory_assert_owner(p_home_id);

  UPDATE public.home_directory_notes n
     SET archived_at = now(),
         updated_by_user_id = v_user
   WHERE n.id = p_note_id
     AND n.home_id = p_home_id
     AND n.archived_at IS NULL
  RETURNING * INTO v_note;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'ok', true,
      'already_archived', false,
      'note', jsonb_build_object(
        'id', v_note.id,
        'home_id', v_note.home_id,
        'title', v_note.title,
        'details', v_note.details,
        'note_type', v_note.note_type,
        'reference_url', v_note.reference_url,
        'photo_path', v_note.photo_path,
        'archived_at', v_note.archived_at,
        'created_at', v_note.created_at,
        'updated_at', v_note.updated_at
      )
    );
  END IF;

  SELECT *
    INTO v_existing
  FROM public.home_directory_notes n
  WHERE n.id = p_note_id
    AND n.home_id = p_home_id;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_NOTE_NOT_FOUND',
      'The note was not found for this home.',
      'P0002',
      jsonb_build_object('home_id', p_home_id, 'note_id', p_note_id)
    );
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'already_archived', true,
    'note', jsonb_build_object(
      'id', v_existing.id,
      'home_id', v_existing.home_id,
      'title', v_existing.title,
      'details', v_existing.details,
      'note_type', v_existing.note_type,
      'reference_url', v_existing.reference_url,
      'photo_path', v_existing.photo_path,
      'archived_at', v_existing.archived_at,
      'created_at', v_existing.created_at,
      'updated_at', v_existing.updated_at
    )
  );
END;
$$;


