    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select
    r.rewrite_request,
    r.target_locale,
    r.policy_version
  from public.rewrite_requests r
  where r.rewrite_request_id = p_rewrite_request_id
