CREATE OR REPLACE FUNCTION "public"."complaint_trigger_pop_pending"("p_limit" integer DEFAULT 20, "p_max_attempts" integer DEFAULT 10) RETURNS TABLE("entry_id" "uuid", "home_id" "uuid", "author_user_id" "uuid", "recipient_user_id" "uuid", "request_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_request_id uuid := gen_random_uuid();
begin
  return query
  with cte as (
    select t.entry_id
    from public.complaint_rewrite_triggers t
    where t.status = 'queued'
      and t.attempts < coalesce(p_max_attempts, 10)
      and (t.retry_after is null or t.retry_after <= now())
    order by coalesce(t.retry_after, t.created_at), t.created_at
    limit coalesce(p_limit, 20)
    for update skip locked
  )
  update public.complaint_rewrite_triggers t
     set status = 'processing',
         request_id = v_request_id,
         attempts = t.attempts + 1,
         last_attempt_at = now(),
         processing_started_at = now(),
         retry_after = null,
         processed_at = null
    from cte
   where t.entry_id = cte.entry_id
  returning t.entry_id, t.home_id, t.author_user_id, t.recipient_user_id, t.request_id;
end;
$$;


ALTER FUNCTION "public"."complaint_trigger_pop_pending"("p_limit" integer, "p_max_attempts" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complaint_trigger_requeue_stale_processing"("p_stale_after" interval DEFAULT '00:10:00'::interval, "p_limit" integer DEFAULT 200, "p_retry_delay" interval DEFAULT '00:00:30'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_count integer := 0;
begin
  with cte as (
    select entry_id
    from public.complaint_rewrite_triggers
    where status = 'processing'
      and processing_started_at is not null
      and processing_started_at <= now() - coalesce(p_stale_after, interval '10 minutes')
    order by processing_started_at
    limit coalesce(p_limit, 200)
    for update skip locked
  )
  update public.complaint_rewrite_triggers t
     set status = 'queued',
         request_id = null,
         processing_started_at = null,
         processed_at = null,
         retry_after = now() + coalesce(p_retry_delay, interval '30 seconds'),
         note = case
                  when t.note is null or t.note = '' then 'requeued_stale_processing'
                  else t.note || ' | requeued_stale_processing'
                end
    from cte
   where t.entry_id = cte.entry_id;

  get diagnostics v_count = row_count;
  return v_count;
end;
$$;


ALTER FUNCTION "public"."complaint_trigger_requeue_stale_processing"("p_stale_after" interval, "p_limit" integer, "p_retry_delay" interval) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_complaint_rewrite_job"("p_job_id" "uuid", "p_rewrite_request_id" "uuid", "p_recipient_user_id" "uuid", "p_rewritten_text" "text", "p_output_language" "text", "p_target_locale" "text", "p_model" "text", "p_provider" "text", "p_prompt_version" "text", "p_policy_version" "text", "p_lexicon_version" "text", "p_eval_result" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_non_terminal_count int;
  v_any_failed boolean;
begin
  perform public.api_assert(
    exists (
      select 1
      from public.rewrite_jobs j
      where j.job_id = p_job_id
        and j.rewrite_request_id = p_rewrite_request_id
        and j.recipient_user_id = p_recipient_user_id
        and j.status = 'processing'
      limit 1
    ),
    'JOB_MISMATCH',
    'Job does not match request/recipient or is not processing.',
    '22023'
  );

  perform public.api_assert(
    public._locale_primary(p_output_language) is not null
    and public._locale_primary(p_output_language) = public._locale_primary(p_target_locale),
    'LANG_MISMATCH',
    'output_language does not match target locale language.',
    '22023'
  );

  insert into public.rewrite_outputs(
    rewrite_request_id, recipient_user_id, rewritten_text, output_language, target_locale,
    model, provider, prompt_version, policy_version, lexicon_version, eval_result
  ) values (
    p_rewrite_request_id, p_recipient_user_id, p_rewritten_text, p_output_language, p_target_locale,
    p_model, p_provider, p_prompt_version, p_policy_version, p_lexicon_version, p_eval_result
  )
  on conflict (rewrite_request_id, recipient_user_id)
  do update set
    rewritten_text = excluded.rewritten_text,
    output_language = excluded.output_language,
    target_locale = excluded.target_locale,
    model = excluded.model,
    provider = excluded.provider,
    prompt_version = excluded.prompt_version,
    policy_version = excluded.policy_version,
    lexicon_version = excluded.lexicon_version,
    eval_result = excluded.eval_result,
    created_at = now();

  update public.rewrite_jobs
     set status = 'completed',
         updated_at = now(),
         last_error = null,
         last_error_at = null
   where job_id = p_job_id;

  -- Only complete request if ALL jobs are terminal.
  select count(*) into v_non_terminal_count
  from public.rewrite_jobs j
  where j.rewrite_request_id = p_rewrite_request_id
    and j.status in ('queued','processing','batch_submitted');

  if v_non_terminal_count = 0 then
    select exists(
      select 1
      from public.rewrite_jobs j
      where j.rewrite_request_id = p_rewrite_request_id
        and j.status in ('failed','canceled')
      limit 1
    ) into v_any_failed;

    update public.rewrite_requests
       set status = case when v_any_failed then 'failed' else 'completed' end,
           rewrite_completed_at = coalesce(rewrite_completed_at, now()),
           updated_at = now()
     where rewrite_request_id = p_rewrite_request_id;
  end if;
end;
$$;


ALTER FUNCTION "public"."complete_complaint_rewrite_job"("p_job_id" "uuid", "p_rewrite_request_id" "uuid", "p_recipient_user_id" "uuid", "p_rewritten_text" "text", "p_output_language" "text", "p_target_locale" "text", "p_model" "text", "p_provider" "text", "p_prompt_version" "text", "p_policy_version" "text", "p_lexicon_version" "text", "p_eval_result" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_member_directory_note"("p_note_type" "text", "p_label" "text" DEFAULT NULL::"text", "p_custom_title" "text" DEFAULT NULL::"text", "p_contact_name" "text" DEFAULT NULL::"text", "p_phone_number" "text" DEFAULT NULL::"text", "p_details" "text" DEFAULT NULL::"text", "p_photo_path" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
DECLARE
  v_user uuid := auth.uid();
  v_note_type text := lower(COALESCE(nullif(btrim(p_note_type), ''), ''));
  v_label text := nullif(btrim(p_label), '');
  v_custom_title text := nullif(btrim(p_custom_title), '');
  v_contact_name text := nullif(btrim(p_contact_name), '');
  v_phone_number text := nullif(btrim(p_phone_number), '');
  v_details text := nullif(btrim(p_details), '');
  v_photo_path text := nullif(btrim(p_photo_path), '');
  v_active_other_count integer;
  v_row public.member_directory_notes%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();

  PERFORM public.api_assert(
    v_note_type IN ('emergency_contact', 'allergy', 'other'),
    'MEMBER_DIRECTORY_INVALID_ENUM',
    'note_type must be emergency_contact, allergy, or other.',
    '22023'
  );

  PERFORM public._member_directory_assert_valid_photo_path(v_user, v_photo_path);

  IF v_note_type = 'allergy' THEN
    PERFORM public.api_assert(
      v_label IS NOT NULL,
      'MEMBER_DIRECTORY_ALLERGY_LABEL_REQUIRED',
      'label is required for allergy notes.',
      '22023'
    );
  ELSE
    PERFORM public.api_assert(
      v_label IS NULL,
      'MEMBER_DIRECTORY_ALLERGY_LABEL_FORBIDDEN',
      'label is only allowed for allergy notes.',
      '22023'
    );
  END IF;

  IF v_note_type = 'other' THEN
    PERFORM public.api_assert(
      v_custom_title IS NOT NULL,
      'MEMBER_DIRECTORY_OTHER_TITLE_REQUIRED',
      'custom_title is required for other notes.',
      '22023'
    );
  ELSE
    PERFORM public.api_assert(
      v_custom_title IS NULL,
      'MEMBER_DIRECTORY_OTHER_TITLE_FORBIDDEN',
      'custom_title is only allowed for other notes.',
      '22023'
    );
  END IF;

  IF v_note_type = 'emergency_contact' THEN
    PERFORM public.api_assert(
      v_contact_name IS NOT NULL AND v_phone_number IS NOT NULL,
      'MEMBER_DIRECTORY_EMERGENCY_CONTACT_REQUIRED_FIELDS',
      'contact_name and phone_number are required for emergency_contact notes.',
      '22023'
    );
  ELSE
    PERFORM public.api_assert(
      v_contact_name IS NULL AND v_phone_number IS NULL,
      'MEMBER_DIRECTORY_CONTACT_FIELDS_FORBIDDEN',
      'contact_name and phone_number are only allowed for emergency_contact notes.',
      '22023'
    );
  END IF;

  PERFORM public.api_assert(
    v_phone_number IS NULL
    OR (
      v_phone_number ~ '^[0-9+()\- ]{1,30}$'
      AND v_phone_number ~ '[0-9]'
    ),
    'MEMBER_DIRECTORY_INVALID_PHONE_NUMBER',
    'phone_number must use digits, spaces, plus, parentheses, or hyphen and contain at least one digit.',
    '22023'
  );

  IF v_note_type = 'allergy' THEN
    PERFORM public.api_assert(
      v_details IS NULL,
      'MEMBER_DIRECTORY_DETAILS_FORBIDDEN',
      'details is not allowed for allergy notes.',
      '22023'
    );
  END IF;

  IF v_note_type = 'other' THEN
    SELECT count(*)
      INTO v_active_other_count
    FROM public.member_directory_notes n
    WHERE n.user_id = v_user
      AND n.note_type = 'other'
      AND n.archived_at IS NULL;

    PERFORM public.api_assert(
      v_active_other_count < 20,
      'MEMBER_DIRECTORY_OTHER_NOTE_LIMIT_REACHED',
      'At most 20 active other notes are allowed.',
      '22023'
    );
  END IF;

  INSERT INTO public.member_directory_notes (
    user_id,
    note_type,
    label,
    custom_title,
    contact_name,
    phone_number,
    details,
    photo_path
  )
  VALUES (
    v_user,
    v_note_type,
    v_label,
    v_custom_title,
    v_contact_name,
    v_phone_number,
    v_details,
    v_photo_path
  )
  RETURNING * INTO v_row;

  RETURN jsonb_build_object(
    'ok', true,
    'note', jsonb_build_object(
      'id', v_row.id,
      'note_type', v_row.note_type,
      'label', v_row.label,
      'custom_title', v_row.custom_title,
      'contact_name', v_row.contact_name,
      'phone_number', v_row.phone_number,
      'details', v_row.details,
      'photo_path', v_row.photo_path,
      'created_at', v_row.created_at,
      'updated_at', v_row.updated_at
    )
  );

EXCEPTION
  WHEN unique_violation THEN
    IF v_note_type = 'emergency_contact' THEN
      PERFORM public.api_error(
        'MEMBER_DIRECTORY_NOTE_TYPE_CONFLICT',
        'An active emergency_contact note already exists.',
        '23505'
      );
    END IF;
    RAISE;
END;
$_$;


