CREATE OR REPLACE FUNCTION "public"."dismiss_home_directory_reminder"("p_home_id" "uuid", "p_reminder_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_today_utc date := public._house_directory_today_utc();
  v_row public.home_directory_service_reminders%ROWTYPE;
  v_existing public.home_directory_service_reminders%ROWTYPE;
  v_exists_for_home boolean := false;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_active(p_home_id);
  PERFORM public._house_directory_assert_owner(p_home_id);

  SELECT true
    INTO v_exists_for_home
  FROM public.home_directory_service_reminders r
  JOIN public.home_directory_services s
    ON s.id = r.service_id
  WHERE r.id = p_reminder_id
    AND s.home_id = p_home_id
  LIMIT 1;

  IF NOT COALESCE(v_exists_for_home, false) THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_REMINDER_NOT_FOUND',
      'The reminder was not found for this home.',
      'P0002',
      jsonb_build_object(
        'home_id', p_home_id,
        'reminder_id', p_reminder_id
      )
    );
  END IF;

  UPDATE public.home_directory_service_reminders r
     SET status = 'dismissed',
         dismissed_at = now(),
         dismissed_by_user_id = v_user
  FROM public.home_directory_services s
  WHERE r.service_id = s.id
    AND r.id = p_reminder_id
    AND s.home_id = p_home_id
    AND r.reminder_kind = 'renewal'
    AND r.status = 'active'
    AND s.archived_at IS NULL
    AND s.term_start_date = r.term_start_date
    AND s.term_end_date = r.term_end_date
    AND v_today_utc >= r.due_at
  RETURNING r.* INTO v_row;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'ok', true,
      'already_dismissed', false,
      'reminder', jsonb_build_object(
        'id', v_row.id,
        'service_id', v_row.service_id,
        'reminder_kind', v_row.reminder_kind,
        'status', v_row.status,
        'term_start_date', v_row.term_start_date,
        'term_end_date', v_row.term_end_date,
        'due_at', v_row.due_at,
        'dismissed_at', v_row.dismissed_at,
        'dismissed_by_user_id', v_row.dismissed_by_user_id,
        'created_at', v_row.created_at,
        'updated_at', v_row.updated_at
      )
    );
  END IF;

  SELECT r.*
    INTO v_existing
  FROM public.home_directory_service_reminders r
  JOIN public.home_directory_services s
    ON s.id = r.service_id
  WHERE r.id = p_reminder_id
    AND s.home_id = p_home_id;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_REMINDER_NOT_FOUND',
      'The reminder was not found for this home.',
      'P0002',
      jsonb_build_object(
        'home_id', p_home_id,
        'reminder_id', p_reminder_id
      )
    );
  END IF;

  IF v_existing.status = 'dismissed' THEN
    RETURN jsonb_build_object(
      'ok', true,
      'already_dismissed', true,
      'reminder', jsonb_build_object(
        'id', v_existing.id,
        'service_id', v_existing.service_id,
        'reminder_kind', v_existing.reminder_kind,
        'status', v_existing.status,
        'term_start_date', v_existing.term_start_date,
        'term_end_date', v_existing.term_end_date,
        'due_at', v_existing.due_at,
        'dismissed_at', v_existing.dismissed_at,
        'dismissed_by_user_id', v_existing.dismissed_by_user_id,
        'created_at', v_existing.created_at,
        'updated_at', v_existing.updated_at
      )
    );
  END IF;

  PERFORM public.api_error(
    'HOUSE_DIRECTORY_REMINDER_NOT_ACTIONABLE',
    'Reminder cannot be dismissed because it is not currently actionable for this home.',
    '22023',
    jsonb_build_object(
      'home_id', p_home_id,
      'reminder_id', p_reminder_id,
      'status', v_existing.status
    )
  );
END;
$$;


ALTER FUNCTION "public"."dismiss_home_directory_reminder"("p_home_id" "uuid", "p_reminder_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dismiss_member_directory_nudge"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_home_id uuid;
  v_already_dismissed boolean := false;
  v_dismissed_at timestamptz;
BEGIN
  PERFORM public._assert_authenticated();

  v_home_id := public._member_directory_get_current_active_home_id(v_user);

  SELECT d.dismissed_at
    INTO v_dismissed_at
  FROM public.member_directory_nudge_dismissals d
  WHERE d.user_id = v_user
    AND d.home_id = v_home_id;

  IF FOUND THEN
    v_already_dismissed := true;
  ELSE
    INSERT INTO public.member_directory_nudge_dismissals (
      user_id,
      home_id
    )
    VALUES (
      v_user,
      v_home_id
    )
    RETURNING dismissed_at INTO v_dismissed_at;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'home_id', v_home_id,
    'already_dismissed', v_already_dismissed,
    'dismissed_at', v_dismissed_at
  );
END;
$$;


ALTER FUNCTION "public"."dismiss_member_directory_nudge"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."dismiss_member_directory_nudge"() IS 'Dismisses the optional member-directory completeness nudge for the authenticated user in their current active home.';



CREATE OR REPLACE FUNCTION "public"."expense_plans_generate_due_cycles"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_plan        public.expense_plans%ROWTYPE;
  v_cycle_date  date;
  v_next_date   date;

  v_cycles_done integer;
  v_cap constant integer := 31;   -- max cycles per plan per run

  v_total_cycles_done integer := 0;
  v_total_cap constant integer := 500; -- global max cycles per run
BEGIN
  FOR v_plan IN
    SELECT *
      FROM public.expense_plans
     WHERE status = 'active'
       AND next_cycle_date <= current_date
     FOR UPDATE SKIP LOCKED
  LOOP
    EXIT WHEN v_total_cycles_done >= v_total_cap;

    v_cycle_date := v_plan.next_cycle_date;
    v_next_date := v_plan.next_cycle_date;

    v_cycles_done := 0;

    WHILE v_cycle_date <= current_date AND v_cycles_done < v_cap LOOP
      EXIT WHEN v_total_cycles_done >= v_total_cap;

      PERFORM public._expense_plan_generate_cycle(v_plan.id, v_cycle_date);

      v_next_date := public._expense_plan_next_cycle_date_v2(
        v_plan.recurrence_every,
        v_plan.recurrence_unit,
        v_cycle_date
      );

      v_cycle_date  := v_next_date;
      v_cycles_done := v_cycles_done + 1;
      v_total_cycles_done := v_total_cycles_done + 1;
    END LOOP;

    UPDATE public.expense_plans
       SET next_cycle_date = v_next_date,
           updated_at      = now()
     WHERE id = v_plan.id;
  END LOOP;

  RETURN;
END;
$$;


ALTER FUNCTION "public"."expense_plans_generate_due_cycles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expense_plans_terminate"("p_plan_id" "uuid") RETURNS "public"."expense_plans"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user  uuid := auth.uid();
  v_plan  public.expense_plans%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_plan_id IS NULL THEN
    PERFORM public.api_error('INVALID_PLAN', 'Plan id is required.', '22023');
  END IF;

  SELECT *
    INTO v_plan
    FROM public.expense_plans ep
   WHERE ep.id = p_plan_id
   FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_FOUND',
      'Expense plan not found.',
      'P0002',
      jsonb_build_object('planId', p_plan_id)
    );
  END IF;

  IF v_plan.created_by_user_id <> v_user THEN
    PERFORM public.api_error(
      'NOT_CREATOR',
      'Only the plan creator can terminate this plan.',
      '42501'
    );
  END IF;

  PERFORM public._assert_home_member(v_plan.home_id);
  PERFORM public._assert_home_active(v_plan.home_id);

  IF v_plan.status = 'terminated' THEN
    RETURN v_plan;
  END IF;

  UPDATE public.expense_plans
     SET status        = 'terminated',
         terminated_at = now(),
         updated_at    = now()
   WHERE id = p_plan_id
  RETURNING * INTO v_plan;

  RETURN v_plan;
END;
$$;


ALTER FUNCTION "public"."expense_plans_terminate"("p_plan_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_cancel"("p_expense_id" "uuid") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_expense        public.expenses%ROWTYPE;
  v_home_is_active boolean;
  v_has_paid       boolean := FALSE;
  v_was_active     boolean := FALSE;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error(
      'INVALID_EXPENSE',
      'Expense id is required.',
      '22023'
    );
  END IF;

  SELECT *
  INTO v_expense
  FROM public.expenses e
  WHERE e.id = p_expense_id
  FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_FOUND',
      'Expense not found.',
      'P0002',
      jsonb_build_object('expenseId', p_expense_id)
    );
  END IF;

  IF v_expense.created_by_user_id <> v_user THEN
    PERFORM public.api_error(
      'NOT_CREATOR',
      'Only the creator can cancel this expense.',
      '42501',
      jsonb_build_object('expenseId', p_expense_id, 'userId', v_user)
    );
  END IF;

  IF v_expense.status = 'cancelled' THEN
    RETURN v_expense;
  END IF;

  IF v_expense.status NOT IN ('draft', 'active') THEN
    PERFORM public.api_error(
      'INVALID_STATE',
      'Only draft or active expenses can be cancelled.',
      'P0003'
    );
  END IF;

  v_was_active := (v_expense.status = 'active');

  PERFORM 1
  FROM public.memberships m
  WHERE m.home_id    = v_expense.home_id
    AND m.user_id    = v_user
    AND m.is_current = TRUE
  LIMIT 1;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a member of this home.',
      '42501',
      jsonb_build_object('homeId', v_expense.home_id)
    );
  END IF;

  SELECT h.is_active
  INTO v_home_is_active
  FROM public.homes h
  WHERE h.id = v_expense.home_id
  FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error(
      'HOME_INACTIVE',
      'This home is no longer active.',
      'P0004'
    );
  END IF;

  PERFORM 1
  FROM public.expense_splits s
  WHERE s.expense_id = v_expense.id
  FOR UPDATE;

  SELECT EXISTS (
    SELECT 1
    FROM public.expense_splits s
    WHERE s.expense_id = v_expense.id
      AND s.status     = 'paid'
      AND s.debtor_user_id <> v_expense.created_by_user_id
  )
  INTO v_has_paid;

  IF v_has_paid THEN
    PERFORM public.api_error(
      'EXPENSE_LOCKED_AFTER_PAYMENT',
      'Expenses with paid shares cannot be cancelled.',
      'P0004',
      jsonb_build_object('expenseId', p_expense_id)
    );
  END IF;

  UPDATE public.expenses
  SET status     = 'cancelled',
      updated_at = now()
  WHERE id = v_expense.id
  RETURNING * INTO v_expense;

  IF v_was_active THEN
    PERFORM public._home_usage_apply_delta(
      v_expense.home_id,
      jsonb_build_object('active_expenses', -1)
    );
  END IF;

  RETURN v_expense;
END;
$$;


ALTER FUNCTION "public"."expenses_cancel"("p_expense_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_create"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_home_id        uuid := p_home_id;
  v_home_is_active boolean;
  v_result         public.expenses%ROWTYPE;

  v_new_status     public.expense_status;
  v_target_split   public.expense_split_type;
  v_has_splits     boolean := FALSE;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF v_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_HOME', 'Home id is required.', '22023');
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error(
      'INVALID_DESCRIPTION',
      format('Description must be %s characters or fewer.', v_desc_max),
      '22023'
    );
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error(
      'INVALID_NOTES',
      format('Notes must be %s characters or fewer.', v_notes_max),
      '22023'
    );
  END IF;

  IF p_split_mode IS NULL THEN
    v_new_status   := 'draft';
    v_target_split := NULL;
    v_has_splits   := FALSE;

    IF p_amount_cents IS NOT NULL THEN
      IF p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
        PERFORM public.api_error(
          'INVALID_AMOUNT',
          format('Amount must be between 1 and %s cents.', v_amount_cap),
          '22023'
        );
      END IF;
    END IF;
  ELSE
    v_new_status   := 'active';
    v_target_split := p_split_mode;
    v_has_splits   := TRUE;

    IF p_amount_cents IS NULL
       OR p_amount_cents <= 0
       OR p_amount_cents > v_amount_cap THEN
      PERFORM public.api_error(
        'INVALID_AMOUNT',
        format('Amount must be between 1 and %s cents.', v_amount_cap),
        '22023'
      );
    END IF;
  END IF;

  PERFORM 1
  FROM public.memberships m
  WHERE m.home_id    = v_home_id
    AND m.user_id    = v_user
    AND m.is_current = TRUE
  LIMIT 1;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a member of this home.',
      '42501',
      jsonb_build_object('homeId', v_home_id)
    );
  END IF;

  SELECT h.is_active
  INTO v_home_is_active
  FROM public.homes h
  WHERE h.id = v_home_id
  FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004');
  END IF;

  PERFORM public._home_assert_quota(
    v_home_id,
    jsonb_build_object('active_expenses', 1)
  );

  IF v_has_splits THEN
    PERFORM public._expenses_prepare_split_buffer(
      v_home_id,
      v_user,
      p_amount_cents,
      v_target_split,
      p_member_ids,
      p_splits
    );
  END IF;

  INSERT INTO public.expenses (
    home_id,
    created_by_user_id,
    status,
    split_type,
    amount_cents,
    description,
    notes
  )
  VALUES (
    v_home_id,
    v_user,
    v_new_status,
    v_target_split,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), '')
  )
  RETURNING * INTO v_result;

  IF v_has_splits THEN
    INSERT INTO public.expense_splits (
      expense_id,
      debtor_user_id,
      amount_cents,
      status,
      marked_paid_at
    )
    SELECT v_result.id,
           debtor_user_id,
           amount_cents,
           CASE
             WHEN debtor_user_id = v_user
               THEN 'paid'::public.expense_share_status
             ELSE 'unpaid'::public.expense_share_status
           END,
           CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
    FROM pg_temp.expense_split_buffer;
  END IF;

  PERFORM public._home_usage_apply_delta(
    v_home_id,
    jsonb_build_object('active_expenses', 1)
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_create"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint, "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_create"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence" "public"."recurrence_interval" DEFAULT 'none'::"public"."recurrence_interval", "p_start_date" "date" DEFAULT CURRENT_DATE) RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_home_id        uuid := p_home_id;
  v_home_is_active boolean;

  v_result         public.expenses%ROWTYPE;
  v_plan           public.expense_plans%ROWTYPE;

  v_new_status     public.expense_status;
  v_target_split   public.expense_split_type;
  v_has_splits     boolean := FALSE;
  v_is_recurring   boolean := FALSE;

  v_recur_every    integer := NULL;
  v_recur_unit     text := NULL;

  v_split_count    integer := 0;
  v_split_sum      bigint  := 0;
  v_split_min      bigint  := 0;

  v_join_date      date;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF v_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_HOME', 'Home id is required.', '22023');
  END IF;

  IF p_start_date IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF p_recurrence IS NULL THEN
    PERFORM public.api_error('INVALID_RECURRENCE', 'Recurrence is required.', '22023');
  END IF;

  v_is_recurring := p_recurrence <> 'none';

  IF v_is_recurring AND p_recurrence NOT IN ('weekly', 'every_2_weeks', 'monthly', 'every_2_months', 'annual') THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence interval must be weekly, every_2_weeks, monthly, every_2_months, or annual.',
      '22023'
    );
  END IF;

  IF v_is_recurring THEN
    CASE p_recurrence
      WHEN 'weekly' THEN
        v_recur_every := 1;
        v_recur_unit := 'week';
      WHEN 'every_2_weeks' THEN
        v_recur_every := 2;
        v_recur_unit := 'week';
      WHEN 'monthly' THEN
        v_recur_every := 1;
        v_recur_unit := 'month';
      WHEN 'every_2_months' THEN
        v_recur_every := 2;
        v_recur_unit := 'month';
      WHEN 'annual' THEN
        v_recur_every := 1;
        v_recur_unit := 'year';
      ELSE
        PERFORM public.api_error(
          'INVALID_RECURRENCE',
          'Recurrence interval is not supported.',
          '22023'
        );
    END CASE;
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error(
      'INVALID_DESCRIPTION',
      format('Description must be %s characters or fewer.', v_desc_max),
      '22023'
    );
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error(
      'INVALID_NOTES',
      format('Notes must be %s characters or fewer.', v_notes_max),
      '22023'
    );
  END IF;

  -- Draft vs active based on splits presence (p_split_mode)
  IF p_split_mode IS NULL THEN
    -- Draft
    IF v_is_recurring THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE_DRAFT',
        'Recurring expenses must be activated with splits; drafts cannot be recurring.',
        '22023'
      );
    END IF;

    -- UPDATED: draft may optionally include amount, but if present must be valid.
    IF p_amount_cents IS NOT NULL THEN
      IF p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
        PERFORM public.api_error(
          'INVALID_AMOUNT',
          format('Amount must be between 1 and %s cents when provided.', v_amount_cap),
          '22023',
          jsonb_build_object('amountCents', p_amount_cents)
        );
      END IF;
    END IF;

    v_new_status   := 'draft';
    v_target_split := NULL;
    v_has_splits   := FALSE;
  ELSE
    -- Activating (one-off active) OR recurring activation (plan + first cycle)
    v_new_status   := 'active';
    v_target_split := p_split_mode;
    v_has_splits   := TRUE;

    IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
      PERFORM public.api_error(
        'INVALID_AMOUNT',
        format('Amount must be between 1 and %s cents.', v_amount_cap),
        '22023'
      );
    END IF;
  END IF;

  -- Membership join date for start_date validation
  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a current member of this home.',
      '42501',
      jsonb_build_object('homeId', v_home_id, 'userId', v_user)
    );
  END IF;

  IF p_start_date < v_join_date OR p_start_date < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  p_start_date
      )
    );
  END IF;

  -- Lock home (global order: homes -> ...)
  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004');
  END IF;

  -- If activating (splits present), build/validate split buffer (also validates members + sums)
  IF v_has_splits THEN
    PERFORM public._expenses_prepare_split_buffer(
      v_home_id,
      v_user,
      p_amount_cents,
      v_target_split,
      p_member_ids,
      p_splits
    );

    SELECT COUNT(*)::int,
           COALESCE(SUM(amount_cents), 0),
           COALESCE(MIN(amount_cents), 0)
      INTO v_split_count, v_split_sum, v_split_min
      FROM pg_temp.expense_split_buffer;

    IF v_split_count < 2 THEN
      PERFORM public.api_error('INVALID_DEBTOR', 'At least two debtors are required.', '22023');
    END IF;

    IF v_split_min <= 0 THEN
      PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
    END IF;

    IF v_split_sum <> p_amount_cents THEN
      PERFORM public.api_error(
        'INVALID_SPLITS_SUM',
        'Split amounts must sum to the expense amount.',
        '22023',
        jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
      );
    END IF;
  END IF;
  -- One-off path (non-recurring)
  IF NOT v_is_recurring THEN
    -- Paywall only if we are creating an ACTIVE expense (splits present)
    IF v_new_status = 'active' THEN
      PERFORM public._home_assert_quota(v_home_id, jsonb_build_object('active_expenses', 1));
    END IF;

    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      split_type,
      amount_cents,
      description,
      notes,
      recurrence_interval,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      v_home_id,
      v_user,
      v_new_status,
      v_target_split,
      p_amount_cents,                 -- may be NULL (draft) or >0
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      'none',
      NULL,
      NULL,
      p_start_date
    )
    RETURNING * INTO v_result;

    -- Create splits only for active
    IF v_has_splits THEN
      INSERT INTO public.expense_splits (
        expense_id,
        debtor_user_id,
        amount_cents,
        status,
        marked_paid_at
      )
      SELECT v_result.id,
             debtor_user_id,
             amount_cents,
             CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
                  ELSE 'unpaid'::public.expense_share_status
             END,
             CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
        FROM pg_temp.expense_split_buffer;
    END IF;

    -- Usage only for active
    IF v_new_status = 'active' THEN
      PERFORM public._home_usage_apply_delta(v_home_id, jsonb_build_object('active_expenses', 1));
    END IF;

    RETURN v_result;
  END IF;

  -- Recurring activation path (user-generated): enforce quota for FIRST cycle intent
  -- (cron later ignores quota by design)
  PERFORM public._home_assert_quota(v_home_id, jsonb_build_object('active_expenses', 1));

  INSERT INTO public.expense_plans (
    home_id,
    created_by_user_id,
    split_type,
    amount_cents,
    description,
    notes,
    recurrence_interval,
    recurrence_every,
    recurrence_unit,
    start_date,
    next_cycle_date,
    status
  )
  VALUES (
    v_home_id,
    v_user,
    v_target_split,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), ''),
    p_recurrence,
    v_recur_every,
    v_recur_unit,
    p_start_date,
    public._expense_plan_next_cycle_date_v2(v_recur_every, v_recur_unit, p_start_date),
    'active'
  )
  RETURNING * INTO v_plan;

  INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
  SELECT v_plan.id, debtor_user_id, amount_cents
    FROM pg_temp.expense_split_buffer;

  -- First cycle creation increments usage inside _expense_plan_generate_cycle (canonical)
  v_result := public._expense_plan_generate_cycle(v_plan.id, p_start_date);
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_create"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint, "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence" "public"."recurrence_interval", "p_start_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_create_v2"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT CURRENT_DATE) RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_home_id        uuid := p_home_id;
  v_home_is_active boolean;

  v_result         public.expenses%ROWTYPE;
  v_plan           public.expense_plans%ROWTYPE;

  v_new_status     public.expense_status;
  v_target_split   public.expense_split_type;
  v_has_splits     boolean := FALSE;
  v_is_recurring   boolean := FALSE;

  v_recur_every    integer := p_recurrence_every;
  v_recur_unit     text := p_recurrence_unit;

  v_split_count    integer := 0;
  v_split_sum      bigint  := 0;
  v_split_min      bigint  := 0;

  v_join_date      date;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF v_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_HOME', 'Home id is required.', '22023');
  END IF;

  IF p_start_date IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF (p_recurrence_every IS NULL) <> (p_recurrence_unit IS NULL) THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence every and unit must both be set or both be null.',
      '22023'
    );
  END IF;

  v_is_recurring := p_recurrence_every IS NOT NULL;

  IF v_is_recurring THEN
    IF p_recurrence_every < 1 THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence every must be >= 1.',
        '22023'
      );
    END IF;

    IF p_recurrence_unit NOT IN ('day', 'week', 'month', 'year') THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence unit must be day, week, month, or year.',
        '22023'
      );
    END IF;
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error(
      'INVALID_DESCRIPTION',
      format('Description must be %s characters or fewer.', v_desc_max),
      '22023'
    );
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error(
      'INVALID_NOTES',
      format('Notes must be %s characters or fewer.', v_notes_max),
      '22023'
    );
  END IF;

  -- Draft vs active based on splits presence (p_split_mode)
  IF p_split_mode IS NULL THEN
    -- Draft
    IF v_is_recurring THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE_DRAFT',
        'Recurring expenses must be activated with splits; drafts cannot be recurring.',
        '22023'
      );
    END IF;

    -- Draft may optionally include amount, but if present must be valid.
    IF p_amount_cents IS NOT NULL THEN
      IF p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
        PERFORM public.api_error(
          'INVALID_AMOUNT',
          format('Amount must be between 1 and %s cents when provided.', v_amount_cap),
          '22023',
          jsonb_build_object('amountCents', p_amount_cents)
        );
      END IF;
    END IF;

    v_new_status   := 'draft';
    v_target_split := NULL;
    v_has_splits   := FALSE;
  ELSE
    -- Activating (one-off active) OR recurring activation (plan + first cycle)
    v_new_status   := 'active';
    v_target_split := p_split_mode;
    v_has_splits   := TRUE;

    IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
      PERFORM public.api_error(
        'INVALID_AMOUNT',
        format('Amount must be between 1 and %s cents.', v_amount_cap),
        '22023'
      );
    END IF;
  END IF;

  -- Membership join date for start_date validation
  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a current member of this home.',
      '42501',
      jsonb_build_object('homeId', v_home_id, 'userId', v_user)
    );
  END IF;

  IF p_start_date < v_join_date OR p_start_date < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  p_start_date
      )
    );
  END IF;

  -- Lock home (global order: homes -> ...)
  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004');
  END IF;

  -- If activating (splits present), build/validate split buffer (also validates members + sums)
  IF v_has_splits THEN
    PERFORM public._expenses_prepare_split_buffer(
      v_home_id,
      v_user,
      p_amount_cents,
      v_target_split,
      p_member_ids,
      p_splits
    );

    SELECT COUNT(*)::int,
           COALESCE(SUM(amount_cents), 0),
           COALESCE(MIN(amount_cents), 0)
      INTO v_split_count, v_split_sum, v_split_min
      FROM pg_temp.expense_split_buffer;

    IF v_split_count < 1 THEN
      PERFORM public.api_error('INVALID_DEBTOR', 'At least one debtor is required.', '22023');
    END IF;

    IF v_split_min <= 0 THEN
      PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
    END IF;

    IF v_split_sum <> p_amount_cents THEN
      PERFORM public.api_error(
        'INVALID_SPLITS_SUM',
        'Split amounts must sum to the expense amount.',
        '22023',
        jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
      );
    END IF;
  END IF;
  -- One-off path (non-recurring)
  IF NOT v_is_recurring THEN
    -- Paywall only if we are creating an ACTIVE expense (splits present)
    IF v_new_status = 'active' THEN
      PERFORM public._home_assert_quota(v_home_id, jsonb_build_object('active_expenses', 1));
    END IF;

    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      split_type,
      amount_cents,
      description,
      notes,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      v_home_id,
      v_user,
      v_new_status,
      v_target_split,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      NULL,
      NULL,
      p_start_date
    )
    RETURNING * INTO v_result;

    -- Create splits only for active
    IF v_has_splits THEN
      INSERT INTO public.expense_splits (
        expense_id,
        debtor_user_id,
        amount_cents,
        status,
        marked_paid_at
      )
      SELECT v_result.id,
             debtor_user_id,
             amount_cents,
             CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
                  ELSE 'unpaid'::public.expense_share_status
             END,
             CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
        FROM pg_temp.expense_split_buffer;
    END IF;

    -- Usage only for active
    IF v_new_status = 'active' THEN
      PERFORM public._home_usage_apply_delta(v_home_id, jsonb_build_object('active_expenses', 1));
    END IF;

    RETURN v_result;
  END IF;

  -- Recurring activation path (user-generated): enforce quota for FIRST cycle intent
  -- (cron later ignores quota by design)
  PERFORM public._home_assert_quota(v_home_id, jsonb_build_object('active_expenses', 1));

  INSERT INTO public.expense_plans (
    home_id,
    created_by_user_id,
    split_type,
    amount_cents,
    description,
    notes,
    recurrence_every,
    recurrence_unit,
    start_date,
    next_cycle_date,
    status
  )
  VALUES (
    v_home_id,
    v_user,
    v_target_split,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), ''),
    v_recur_every,
    v_recur_unit,
    p_start_date,
    public._expense_plan_next_cycle_date_v2(v_recur_every, v_recur_unit, p_start_date),
    'active'
  )
  RETURNING * INTO v_plan;

  INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
  SELECT v_plan.id, debtor_user_id, amount_cents
    FROM pg_temp.expense_split_buffer;

  -- First cycle creation increments usage inside _expense_plan_generate_cycle (canonical)
  v_result := public._expense_plan_generate_cycle(v_plan.id, p_start_date);
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_create_v2"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint, "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_create_v3"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT CURRENT_DATE, "p_evidence_photo_path" "text" DEFAULT NULL::"text") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_home_id        uuid := p_home_id;
  v_home_is_active boolean;

  v_result         public.expenses%ROWTYPE;
  v_plan           public.expense_plans%ROWTYPE;

  v_new_status     public.expense_status;
  v_target_split   public.expense_split_type;
  v_has_splits     boolean := FALSE;
  v_is_recurring   boolean := FALSE;

  v_recur_every    integer := p_recurrence_every;
  v_recur_unit     text := p_recurrence_unit;

  v_split_count    integer := 0;
  v_split_sum      bigint  := 0;
  v_split_min      bigint  := 0;

  v_join_date      date;

  v_evidence_photo_path text := NULLIF(btrim(p_evidence_photo_path), '');
  v_photo_delta integer := 0;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF v_home_id IS NULL THEN
    PERFORM public.api_error('INVALID_HOME', 'Home id is required.', '22023');
  END IF;

  IF p_start_date IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF (p_recurrence_every IS NULL) <> (p_recurrence_unit IS NULL) THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence every and unit must both be set or both be null.',
      '22023'
    );
  END IF;

  IF v_evidence_photo_path IS NOT NULL
     AND v_evidence_photo_path NOT LIKE 'households/%' THEN
    PERFORM public.api_error(
      'INVALID_EVIDENCE_PHOTO_PATH',
      'Evidence photo path must start with households/.',
      '22023',
      jsonb_build_object('field', 'evidencePhotoPath')
    );
  END IF;

  v_is_recurring := p_recurrence_every IS NOT NULL;

  IF v_is_recurring THEN
    IF p_recurrence_every < 1 THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence every must be >= 1.',
        '22023'
      );
    END IF;

    IF p_recurrence_unit NOT IN ('day', 'week', 'month', 'year') THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence unit must be day, week, month, or year.',
        '22023'
      );
    END IF;
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error(
      'INVALID_DESCRIPTION',
      format('Description must be %s characters or fewer.', v_desc_max),
      '22023'
    );
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error(
      'INVALID_NOTES',
      format('Notes must be %s characters or fewer.', v_notes_max),
      '22023'
    );
  END IF;

  IF p_split_mode IS NULL THEN
    IF v_is_recurring THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE_DRAFT',
        'Recurring expenses must be activated with splits; drafts cannot be recurring.',
        '22023'
      );
    END IF;

    IF p_amount_cents IS NOT NULL THEN
      IF p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
        PERFORM public.api_error(
          'INVALID_AMOUNT',
          format('Amount must be between 1 and %s cents when provided.', v_amount_cap),
          '22023',
          jsonb_build_object('amountCents', p_amount_cents)
        );
      END IF;
    END IF;

    v_new_status   := 'draft';
    v_target_split := NULL;
    v_has_splits   := FALSE;
  ELSE
    v_new_status   := 'active';
    v_target_split := p_split_mode;
    v_has_splits   := TRUE;

    IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
      PERFORM public.api_error(
        'INVALID_AMOUNT',
        format('Amount must be between 1 and %s cents.', v_amount_cap),
        '22023'
      );
    END IF;
  END IF;

  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a current member of this home.',
      '42501',
      jsonb_build_object('homeId', v_home_id, 'userId', v_user)
    );
  END IF;

  IF p_start_date < v_join_date OR p_start_date < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  p_start_date
      )
    );
  END IF;

  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004');
  END IF;

  IF v_has_splits THEN
    PERFORM public._expenses_prepare_split_buffer(
      v_home_id,
      v_user,
      p_amount_cents,
      v_target_split,
      p_member_ids,
      p_splits
    );

    SELECT COUNT(*)::int,
           COALESCE(SUM(amount_cents), 0),
           COALESCE(MIN(amount_cents), 0)
      INTO v_split_count, v_split_sum, v_split_min
      FROM pg_temp.expense_split_buffer;

    IF v_split_count < 1 THEN
      PERFORM public.api_error('INVALID_DEBTOR', 'At least one debtor is required.', '22023');
    END IF;

    IF v_split_min <= 0 THEN
      PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
    END IF;

    IF v_split_sum <> p_amount_cents THEN
      PERFORM public.api_error(
        'INVALID_SPLITS_SUM',
        'Split amounts must sum to the expense amount.',
        '22023',
        jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
      );
    END IF;
  END IF;

  IF NOT v_is_recurring THEN
    v_photo_delta := CASE
      WHEN v_new_status = 'active' AND v_evidence_photo_path IS NOT NULL THEN 1
      ELSE 0
    END;

    IF v_new_status = 'active' THEN
      PERFORM public._home_assert_quota(
        v_home_id,
        jsonb_build_object(
          'active_expenses', 1,
          'expense_photos', v_photo_delta
        )
      );
    END IF;

    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      v_home_id,
      v_user,
      v_new_status,
      v_target_split,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_evidence_photo_path,
      NULL,
      NULL,
      p_start_date
    )
    RETURNING * INTO v_result;

    IF v_has_splits THEN
      INSERT INTO public.expense_splits (
        expense_id,
        debtor_user_id,
        amount_cents,
        status,
        marked_paid_at
      )
      SELECT v_result.id,
             debtor_user_id,
             amount_cents,
             CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
                  ELSE 'unpaid'::public.expense_share_status
             END,
             CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
        FROM pg_temp.expense_split_buffer;
    END IF;

    IF v_new_status = 'active' THEN
      PERFORM public._home_usage_apply_delta(
        v_home_id,
        jsonb_build_object(
          'active_expenses', 1,
          'expense_photos', v_photo_delta
        )
      );
    END IF;

    RETURN v_result;
  END IF;

  v_photo_delta := CASE WHEN v_evidence_photo_path IS NOT NULL THEN 1 ELSE 0 END;

  PERFORM public._home_assert_quota(
    v_home_id,
    jsonb_build_object(
      'active_expenses', 1,
      'expense_photos', v_photo_delta
    )
  );

  INSERT INTO public.expense_plans (
    home_id,
    created_by_user_id,
    split_type,
    amount_cents,
    description,
    notes,
    evidence_photo_path,
    recurrence_every,
    recurrence_unit,
    start_date,
    next_cycle_date,
    status
  )
  VALUES (
    v_home_id,
    v_user,
    v_target_split,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), ''),
    v_evidence_photo_path,
    v_recur_every,
    v_recur_unit,
    p_start_date,
    public._expense_plan_next_cycle_date_v2(v_recur_every, v_recur_unit, p_start_date),
    'active'
  )
  RETURNING * INTO v_plan;

  INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
  SELECT v_plan.id, debtor_user_id, amount_cents
    FROM pg_temp.expense_split_buffer;

  IF v_photo_delta > 0 THEN
    PERFORM public._home_usage_apply_delta(
      v_home_id,
      jsonb_build_object('expense_photos', 1)
    );
  END IF;

  v_result := public._expense_plan_generate_cycle(v_plan.id, p_start_date);
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_create_v3"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint, "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date", "p_evidence_photo_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_create_v5"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_notes" "text" DEFAULT NULL::"text", "p_allocation_target_type" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_unit_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_unit_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT CURRENT_DATE, "p_evidence_photo_path" "text" DEFAULT NULL::"text") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_photo_path text;
  v_photo_delta integer := 0;
  v_is_recurring boolean := FALSE;
  v_result public.expenses%ROWTYPE;
  v_plan public.expense_plans%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._expense_lock_home_active(p_home_id);
  PERFORM public._expense_require_current_membership(p_home_id, v_user);

  v_photo_path := public._expense_validate_evidence_photo_path(p_evidence_photo_path);
  v_photo_delta := public._expense_validate_photo_transition(NULL, v_photo_path);
  PERFORM public._expense_validate_recurrence_fields(p_recurrence_every, p_recurrence_unit);
  v_is_recurring := p_recurrence_every IS NOT NULL;

  IF p_split_mode IS NULL THEN
    IF p_allocation_target_type IS NOT NULL THEN
      PERFORM public.api_error(
        'INVALID_ALLOCATION_TARGET',
        'Draft expenses must not set allocation target type.',
        '22023'
      );
    END IF;

    IF v_is_recurring THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE_DRAFT',
        'Recurring expenses must be activated with splits; drafts cannot be recurring.',
        '22023'
      );
    END IF;

    PERFORM public._expense_validate_common_fields(p_description, p_notes, p_amount_cents, TRUE);
    PERFORM public._expense_validate_start_date_range(p_home_id, v_user, p_start_date);

    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      allocation_target_type,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      p_home_id,
      v_user,
      'draft',
      NULL,
      NULL,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_photo_path,
      NULL,
      NULL,
      p_start_date
    )
    RETURNING * INTO v_result;

    RETURN v_result;
  END IF;

  IF p_allocation_target_type IS NULL THEN
    PERFORM public.api_error(
      'INVALID_ALLOCATION_TARGET',
      'Active expense creation requires an allocation target type.',
      '22023'
    );
  END IF;

  IF p_allocation_target_type NOT IN ('debtor_based', 'unit_based') THEN
    PERFORM public.api_error(
      'INVALID_ALLOCATION_TARGET',
      'Unknown allocation target type.',
      '22023'
    );
  END IF;

  IF p_allocation_target_type = 'debtor_based' AND (p_unit_ids IS NOT NULL OR p_unit_splits IS NOT NULL) THEN
    PERFORM public.api_error(
      'INVALID_ALLOCATION_TARGET',
      'Debtor-based expenses must not include unit split payloads.',
      '22023'
    );
  END IF;

  IF p_allocation_target_type = 'unit_based' AND (p_member_ids IS NOT NULL OR p_splits IS NOT NULL) THEN
    PERFORM public.api_error(
      'INVALID_ALLOCATION_TARGET',
      'Unit-based expenses must not include debtor-based split payloads.',
      '22023'
    );
  END IF;

  PERFORM public._expense_validate_common_fields(p_description, p_notes, p_amount_cents, FALSE);
  PERFORM public._expense_validate_start_date_range(p_home_id, v_user, p_start_date);

  IF NOT v_is_recurring THEN
    PERFORM public._expense_quota_assert_activate_one_off(p_home_id, v_photo_delta);

    INSERT INTO public.expenses (
      home_id,
      created_by_user_id,
      status,
      allocation_target_type,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      recurrence_every,
      recurrence_unit,
      start_date
    )
    VALUES (
      p_home_id,
      v_user,
      'active',
      p_allocation_target_type,
      p_split_mode,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_photo_path,
      NULL,
      NULL,
      p_start_date
    )
    RETURNING * INTO v_result;

    IF p_allocation_target_type = 'debtor_based' THEN
      PERFORM public._expense_persist_debtor_splits(
        v_result.id,
        v_user,
        p_amount_cents,
        p_split_mode,
        p_member_ids,
        p_splits
      );
    ELSE
      PERFORM public._expense_persist_unit_splits(
        v_result.id,
        v_user,
        p_amount_cents,
        p_split_mode,
        p_unit_ids,
        p_unit_splits
      );
    END IF;

    PERFORM public._expense_quota_apply_activate_one_off(p_home_id, v_photo_delta);
    RETURN v_result;
  END IF;

  PERFORM public._expense_quota_assert_activate_plan_with_first_cycle(p_home_id, v_photo_delta);

  INSERT INTO public.expense_plans (
    home_id,
    created_by_user_id,
    allocation_target_type,
    split_type,
    amount_cents,
    description,
    notes,
    evidence_photo_path,
    recurrence_every,
    recurrence_unit,
    start_date,
    next_cycle_date,
    status,
    termination_reason
  )
  VALUES (
    p_home_id,
    v_user,
    p_allocation_target_type,
    p_split_mode,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), ''),
    v_photo_path,
    p_recurrence_every,
    p_recurrence_unit,
    p_start_date,
    public._expense_plan_next_cycle_date_v2(p_recurrence_every, p_recurrence_unit, p_start_date),
    'active',
    NULL
  )
  RETURNING * INTO v_plan;

  IF p_allocation_target_type = 'debtor_based' THEN
    PERFORM public._expense_persist_plan_debtor_targets(
      v_plan.id,
      v_user,
      p_amount_cents,
      p_split_mode,
      p_member_ids,
      p_splits
    );
  ELSE
    PERFORM public._expense_persist_plan_unit_targets(
      v_plan.id,
      v_user,
      p_amount_cents,
      p_split_mode,
      p_unit_ids,
      p_unit_splits
    );
  END IF;

  v_result := public._expense_plan_generate_cycle_v3(v_plan.id, p_start_date, FALSE);
  PERFORM public._expense_quota_apply_activate_plan_with_first_cycle(p_home_id, v_photo_delta);

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_create_v5"("p_home_id" "uuid", "p_description" "text", "p_amount_cents" bigint, "p_notes" "text", "p_allocation_target_type" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_unit_ids" "uuid"[], "p_unit_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date", "p_evidence_photo_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_edit"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_home_id        uuid;
  v_home_is_active boolean;

  v_existing       public.expenses%ROWTYPE;
  v_result         public.expenses%ROWTYPE;

  v_has_paid       boolean := FALSE;
  v_new_status     public.expense_status;
  v_target_split   public.expense_split_type;
  v_should_replace boolean := FALSE;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  IF p_amount_cents IS NULL
     OR p_amount_cents <= 0
     OR p_amount_cents > v_amount_cap THEN
    PERFORM public.api_error(
      'INVALID_AMOUNT',
      format('Amount must be between 1 and %s cents.', v_amount_cap),
      '22023'
    );
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error(
      'INVALID_DESCRIPTION',
      format('Description must be %s characters or fewer.', v_desc_max),
      '22023'
    );
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error(
      'INVALID_NOTES',
      format('Notes must be %s characters or fewer.', v_notes_max),
      '22023'
    );
  END IF;

  -- Load existing expense and lock it
  SELECT *
  INTO v_existing
  FROM public.expenses e
  WHERE e.id = p_expense_id
  FOR UPDATE;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_FOUND',
      'Expense not found.',
      'P0002',
      jsonb_build_object('expenseId', p_expense_id)
    );
  END IF;

  v_home_id := v_existing.home_id;

  IF v_existing.created_by_user_id <> v_user THEN
    PERFORM public.api_error(
      'NOT_CREATOR',
      'Only the creator can modify this expense.',
      '42501'
    );
  END IF;

  IF v_existing.status = 'cancelled' THEN
    PERFORM public.api_error(
      'INVALID_STATE',
      'Cancelled expenses cannot be edited.',
      'P0003'
    );
  END IF;

  -- Lock splits rowset for this expense to avoid races
  PERFORM 1
  FROM public.expense_splits s
  WHERE s.expense_id = v_existing.id
  FOR UPDATE;

  -- Check if any share is paid
  SELECT EXISTS (
    SELECT 1
    FROM public.expense_splits s
    WHERE s.expense_id = v_existing.id
      AND s.status     = 'paid'
      AND s.debtor_user_id <> v_existing.created_by_user_id
  )
  INTO v_has_paid;

  -- Determine new status + split_type
  IF v_existing.status = 'draft' THEN
    -- New rule: editing a draft MUST choose a split and becomes active
    IF p_split_mode IS NULL THEN
      PERFORM public.api_error(
        'SPLIT_REQUIRED',
        'Draft edits must choose a split; editing will activate the expense.',
        '22023'
      );
    END IF;

    v_target_split   := p_split_mode;
    v_new_status     := 'active';
    v_should_replace := TRUE;

  ELSE
    -- Existing is active (cancelled already rejected)
    v_new_status := 'active';

    IF v_has_paid THEN
      -- Lock amount and split once any share is paid
      IF p_split_mode IS NOT NULL THEN
        PERFORM public.api_error(
          'EXPENSE_LOCKED_AFTER_PAYMENT',
          'Split settings cannot change after a payment.',
          'P0004'
        );
      END IF;

      IF p_amount_cents <> v_existing.amount_cents THEN
        PERFORM public.api_error(
          'EXPENSE_LOCKED_AFTER_PAYMENT',
          'Amount cannot change after a payment.',
          'P0004'
        );
      END IF;

      v_target_split   := v_existing.split_type;
      v_should_replace := FALSE;
    ELSE
      -- No paid shares yet on an active expense
      IF p_split_mode IS NULL THEN
        -- Keep current split_type
        IF p_amount_cents <> v_existing.amount_cents THEN
          PERFORM public.api_error(
            'SPLIT_REQUIRED',
            'Provide split details when changing the amount of an active expense.',
            '22023'
          );
        END IF;

        v_target_split   := v_existing.split_type;
        v_should_replace := FALSE;
      ELSE
        -- Update split_type and rebuild splits
        v_target_split   := p_split_mode;
        v_should_replace := TRUE;
      END IF;
    END IF;
  END IF;

  IF v_new_status = 'active' AND v_target_split IS NULL THEN
    PERFORM public.api_error(
      'INVALID_STATE',
      'Active expenses must keep a split.',
      'P0003'
    );
  END IF;

  -- Membership + home state
  PERFORM 1
  FROM public.memberships m
  WHERE m.home_id    = v_home_id
    AND m.user_id    = v_user
    AND m.is_current = TRUE
  LIMIT 1;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a member of this home.',
      '42501',
      jsonb_build_object('homeId', v_home_id)
    );
  END IF;

  SELECT h.is_active
  INTO v_home_is_active
  FROM public.homes h
  WHERE h.id = v_home_id
  FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error(
      'HOME_INACTIVE',
      'This home is no longer active.',
      'P0004'
    );
  END IF;

  -- Prepare split buffer if we need to rebuild splits
  IF v_should_replace THEN
    PERFORM public._expenses_prepare_split_buffer(
      v_home_id,
      v_user,
      p_amount_cents,
      v_target_split,
      p_member_ids,
      p_splits
    );
  END IF;

  -- Persist UPDATE
  UPDATE public.expenses
  SET amount_cents = p_amount_cents,
      description  = btrim(p_description),
      notes        = NULLIF(btrim(p_notes), ''),
      status       = v_new_status,
      split_type   = v_target_split,
      updated_at   = now()
  WHERE id = v_existing.id
  RETURNING * INTO v_result;

  -- Rebuild splits if required
  IF v_should_replace THEN
    DELETE FROM public.expense_splits
    WHERE expense_id = v_result.id;

    INSERT INTO public.expense_splits (
      expense_id,
      debtor_user_id,
      amount_cents,
      status,
      marked_paid_at
    )
    SELECT v_result.id,
           debtor_user_id,
           amount_cents,
           CASE
             WHEN debtor_user_id = v_user
               THEN 'paid'::public.expense_share_status
             ELSE 'unpaid'::public.expense_share_status
           END,
           CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
    FROM pg_temp.expense_split_buffer;
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_edit"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_edit"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence" "public"."recurrence_interval" DEFAULT NULL::"public"."recurrence_interval", "p_start_date" "date" DEFAULT NULL::"date") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user            uuid := auth.uid();

  v_existing_unsafe public.expenses%ROWTYPE;
  v_existing        public.expenses%ROWTYPE;

  v_result          public.expenses%ROWTYPE;
  v_plan            public.expense_plans%ROWTYPE;

  v_home_is_active  boolean;

  v_target_split    public.expense_split_type;
  v_target_recur    public.recurrence_interval;
  v_target_recur_every integer;
  v_target_recur_unit  text;
  v_target_start    date;
  v_is_recurring    boolean := FALSE;

  v_split_count     integer := 0;
  v_split_sum       bigint  := 0;
  v_split_min       bigint  := 0;

  v_join_date       date;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  -- Activation requires amount
  IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
    PERFORM public.api_error('INVALID_AMOUNT', format('Amount must be between 1 and %s cents.', v_amount_cap), '22023');
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', format('Description must be %s characters or fewer.', v_desc_max), '22023');
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error('INVALID_NOTES', format('Notes must be %s characters or fewer.', v_notes_max), '22023');
  END IF;

  IF p_split_mode IS NULL THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Splits are required. Editing an expense always activates it.', '22023');
  END IF;

  SELECT *
    INTO v_existing_unsafe
    FROM public.expenses e
   WHERE e.id = p_expense_id;

  IF NOT FOUND THEN
    PERFORM public.api_error('NOT_FOUND', 'Expense not found.', 'P0002', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  -- Lock home first (global order: homes -> ...)
  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_existing_unsafe.home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004', jsonb_build_object('homeId', v_existing_unsafe.home_id));
  END IF;

  -- Lock expense row next (homes -> expenses)
  SELECT *
    INTO v_existing
    FROM public.expenses e
   WHERE e.id = p_expense_id
   FOR UPDATE;

  IF v_existing.home_id <> v_existing_unsafe.home_id THEN
    PERFORM public.api_error('CONCURRENT_MODIFICATION', 'Expense changed while editing. Please retry.', '40001', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  IF v_existing.created_by_user_id <> v_user THEN
    PERFORM public.api_error('NOT_CREATOR', 'Only the creator can modify this expense.', '42501');
  END IF;

  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_existing.home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error('NOT_HOME_MEMBER', 'You are not a current member of this home.', '42501',
      jsonb_build_object('homeId', v_existing.home_id, 'userId', v_user)
    );
  END IF;

  IF v_existing.plan_id IS NOT NULL THEN
    PERFORM public.api_error('IMMUTABLE_CYCLE', 'Expenses generated from a recurring plan cannot be edited.', '42501');
  END IF;

  IF v_existing.status = 'active' THEN
    PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Active expenses cannot be edited.', '42501',
      jsonb_build_object('expenseId', v_existing.id, 'status', v_existing.status)
    );
  END IF;

  IF v_existing.status <> 'draft' THEN
    PERFORM public.api_error('INVALID_STATE', 'Only draft expenses can be edited.', '42501',
      jsonb_build_object('expenseId', v_existing.id, 'status', v_existing.status)
    );
  END IF;

  v_target_split := p_split_mode;
  v_target_recur := COALESCE(p_recurrence, 'none');
  v_target_start := COALESCE(p_start_date, v_existing.start_date);

  IF v_target_start IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF v_target_start < v_join_date OR v_target_start < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  v_target_start
      )
    );
  END IF;

  v_is_recurring := v_target_recur <> 'none';

  IF v_is_recurring AND v_target_recur NOT IN ('weekly', 'every_2_weeks', 'monthly', 'every_2_months', 'annual') THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence interval must be weekly, every_2_weeks, monthly, every_2_months, or annual.',
      '22023'
    );
  END IF;

  IF v_is_recurring THEN
    CASE v_target_recur
      WHEN 'weekly' THEN
        v_target_recur_every := 1;
        v_target_recur_unit := 'week';
      WHEN 'every_2_weeks' THEN
        v_target_recur_every := 2;
        v_target_recur_unit := 'week';
      WHEN 'monthly' THEN
        v_target_recur_every := 1;
        v_target_recur_unit := 'month';
      WHEN 'every_2_months' THEN
        v_target_recur_every := 2;
        v_target_recur_unit := 'month';
      WHEN 'annual' THEN
        v_target_recur_every := 1;
        v_target_recur_unit := 'year';
      ELSE
        PERFORM public.api_error(
          'INVALID_RECURRENCE',
          'Recurrence interval is not supported.',
          '22023'
        );
    END CASE;
  ELSE
    v_target_recur_every := NULL;
    v_target_recur_unit := NULL;
  END IF;

  -- Build splits (this truncates pg_temp buffer itself)
  PERFORM public._expenses_prepare_split_buffer(
    v_existing.home_id,
    v_user,
    p_amount_cents,
    v_target_split,
    p_member_ids,
    p_splits
  );

  SELECT COUNT(*)::int,
         COALESCE(SUM(amount_cents), 0),
         COALESCE(MIN(amount_cents), 0)
    INTO v_split_count, v_split_sum, v_split_min
    FROM pg_temp.expense_split_buffer;

  IF v_split_count < 2 THEN
    PERFORM public.api_error('INVALID_DEBTOR', 'At least two debtors are required.', '22023');
  END IF;

  IF v_split_min <= 0 THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
  END IF;

  IF v_split_sum <> p_amount_cents THEN
    PERFORM public.api_error('INVALID_SPLITS_SUM', 'Split amounts must sum to the expense amount.', '22023',
      jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
    );
  END IF;

  -- Lock order convention: expense already locked; now safe to mutate splits
  DELETE FROM public.expense_splits s
   WHERE s.expense_id = v_existing.id;
  IF v_is_recurring THEN
    -- User-generated recurring activation consumes quota for the first cycle intent
    PERFORM public._home_assert_quota(v_existing.home_id, jsonb_build_object('active_expenses', 1));

    INSERT INTO public.expense_plans (
      home_id,
      created_by_user_id,
      split_type,
      amount_cents,
      description,
      notes,
      recurrence_interval,
      recurrence_every,
      recurrence_unit,
      start_date,
      next_cycle_date,
      status
    )
    VALUES (
      v_existing.home_id,
      v_user,
      v_target_split,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_target_recur,
      v_target_recur_every,
      v_target_recur_unit,
      v_target_start,
      public._expense_plan_next_cycle_date_v2(v_target_recur_every, v_target_recur_unit, v_target_start),
      'active'
    )
    RETURNING * INTO v_plan;

    INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
    SELECT v_plan.id, debtor_user_id, amount_cents
      FROM pg_temp.expense_split_buffer;

    -- Mark original draft as converted; do NOT increment usage here
    UPDATE public.expenses
       SET status              = 'converted',
           plan_id             = v_plan.id,
           recurrence_interval = v_target_recur,
           recurrence_every    = v_target_recur_every,
           recurrence_unit     = v_target_recur_unit,
           start_date          = v_target_start,
           updated_at          = now()
     WHERE id = v_existing.id;

    -- First cycle creation increments usage inside _expense_plan_generate_cycle
    v_result := public._expense_plan_generate_cycle(v_plan.id, v_target_start);
    RETURN v_result;
  END IF;

  -- One-off activation path
  PERFORM public._home_assert_quota(v_existing.home_id, jsonb_build_object('active_expenses', 1));

  UPDATE public.expenses
     SET status              = 'active',
         split_type          = v_target_split,
         amount_cents        = p_amount_cents,
         description         = btrim(p_description),
         notes               = NULLIF(btrim(p_notes), ''),
         recurrence_interval = 'none',
         recurrence_every    = NULL,
         recurrence_unit     = NULL,
         start_date          = v_target_start,
         updated_at          = now()
   WHERE id = v_existing.id
   RETURNING * INTO v_result;

  INSERT INTO public.expense_splits (
    expense_id,
    debtor_user_id,
    amount_cents,
    status,
    marked_paid_at
  )
  SELECT v_result.id,
         debtor_user_id,
         amount_cents,
         CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
              ELSE 'unpaid'::public.expense_share_status
         END,
         CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
    FROM pg_temp.expense_split_buffer;

  PERFORM public._home_usage_apply_delta(v_existing.home_id, jsonb_build_object('active_expenses', 1));

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_edit"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence" "public"."recurrence_interval", "p_start_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_edit_v2"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT NULL::"date") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user            uuid := auth.uid();

  v_existing_unsafe public.expenses%ROWTYPE;
  v_existing        public.expenses%ROWTYPE;

  v_result          public.expenses%ROWTYPE;
  v_plan            public.expense_plans%ROWTYPE;

  v_home_is_active  boolean;

  v_target_split       public.expense_split_type;
  v_target_recur_every integer;
  v_target_recur_unit  text;
  v_target_start       date;
  v_is_recurring       boolean := FALSE;

  v_split_count     integer := 0;
  v_split_sum       bigint  := 0;
  v_split_min       bigint  := 0;

  v_join_date       date;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  SELECT *
    INTO v_existing_unsafe
    FROM public.expenses e
   WHERE e.id = p_expense_id;

  IF NOT FOUND THEN
    PERFORM public.api_error('NOT_FOUND', 'Expense not found.', 'P0002', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  -- Lock home first (global order: homes -> ...)
  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_existing_unsafe.home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004', jsonb_build_object('homeId', v_existing_unsafe.home_id));
  END IF;

  -- Lock expense row next (homes -> expenses)
  SELECT *
    INTO v_existing
    FROM public.expenses e
   WHERE e.id = p_expense_id
   FOR UPDATE;

  IF v_existing.home_id <> v_existing_unsafe.home_id THEN
    PERFORM public.api_error('CONCURRENT_MODIFICATION', 'Expense changed while editing. Please retry.', '40001', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_existing.home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error('NOT_HOME_MEMBER', 'You are not a current member of this home.', '42501',
      jsonb_build_object('homeId', v_existing.home_id, 'userId', v_user)
    );
  END IF;

  IF v_existing.plan_id IS NOT NULL THEN
    PERFORM public.api_error('IMMUTABLE_CYCLE', 'Expenses generated from a recurring plan cannot be edited.', '42501');
  END IF;

  IF v_existing.status = 'active' THEN
    IF v_existing.created_by_user_id <> v_user THEN
      PERFORM public.api_error(
        'NOT_CREATOR',
        'Only the creator can edit this active expense.',
        '42501'
      );
    END IF;

    IF p_amount_cents IS DISTINCT FROM v_existing.amount_cents THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Amount is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'amountCents', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_split_mode IS NOT NULL AND p_split_mode IS DISTINCT FROM v_existing.split_type THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Split mode is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'splitMode', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_member_ids IS NOT NULL OR p_splits IS NOT NULL THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Splits are immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'splits', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_recurrence_every IS NOT NULL OR p_recurrence_unit IS NOT NULL THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Recurrence is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'recurrence', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_start_date IS NOT NULL AND p_start_date IS DISTINCT FROM v_existing.start_date THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Start date is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'startDate', 'expenseId', v_existing.id)
      );
    END IF;

    IF btrim(COALESCE(p_description, '')) = '' THEN
      PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
    END IF;

    IF char_length(btrim(p_description)) > v_desc_max THEN
      PERFORM public.api_error('INVALID_DESCRIPTION', format('Description must be %s characters or fewer.', v_desc_max), '22023');
    END IF;

    IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
      PERFORM public.api_error('INVALID_NOTES', format('Notes must be %s characters or fewer.', v_notes_max), '22023');
    END IF;

    UPDATE public.expenses
       SET description = btrim(p_description),
           notes = NULLIF(btrim(p_notes), ''),
           updated_at = now()
     WHERE id = v_existing.id
     RETURNING * INTO v_result;

    RETURN v_result;
  END IF;

  IF v_existing.created_by_user_id <> v_user THEN
    PERFORM public.api_error('NOT_CREATOR', 'Only the creator can modify this expense.', '42501');
  END IF;

  IF v_existing.status <> 'draft' THEN
    PERFORM public.api_error('INVALID_STATE', 'Only draft expenses can be edited.', '42501',
      jsonb_build_object('expenseId', v_existing.id, 'status', v_existing.status)
    );
  END IF;

  -- Draft editing path always activates and requires full payload.
  IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
    PERFORM public.api_error('INVALID_AMOUNT', format('Amount must be between 1 and %s cents.', v_amount_cap), '22023');
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', format('Description must be %s characters or fewer.', v_desc_max), '22023');
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error('INVALID_NOTES', format('Notes must be %s characters or fewer.', v_notes_max), '22023');
  END IF;

  IF p_split_mode IS NULL THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Splits are required. Editing an expense always activates it.', '22023');
  END IF;

  IF (p_recurrence_every IS NULL) <> (p_recurrence_unit IS NULL) THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence every and unit must both be set or both be null.',
      '22023'
    );
  END IF;

  v_target_split := p_split_mode;
  v_target_recur_every := p_recurrence_every;
  v_target_recur_unit := p_recurrence_unit;
  v_is_recurring := v_target_recur_every IS NOT NULL;

  IF v_is_recurring THEN
    IF v_target_recur_every < 1 THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence every must be >= 1.',
        '22023'
      );
    END IF;

    IF v_target_recur_unit NOT IN ('day', 'week', 'month', 'year') THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence unit must be day, week, month, or year.',
        '22023'
      );
    END IF;
  END IF;

  v_target_start := COALESCE(p_start_date, v_existing.start_date);

  IF v_target_start IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF v_target_start < v_join_date OR v_target_start < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  v_target_start
      )
    );
  END IF;

  -- Build splits (this truncates pg_temp buffer itself)
  PERFORM public._expenses_prepare_split_buffer(
    v_existing.home_id,
    v_user,
    p_amount_cents,
    v_target_split,
    p_member_ids,
    p_splits
  );

  SELECT COUNT(*)::int,
         COALESCE(SUM(amount_cents), 0),
         COALESCE(MIN(amount_cents), 0)
    INTO v_split_count, v_split_sum, v_split_min
    FROM pg_temp.expense_split_buffer;

  IF v_split_count < 1 THEN
    PERFORM public.api_error('INVALID_DEBTOR', 'At least one debtor is required.', '22023');
  END IF;

  IF v_split_min <= 0 THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
  END IF;

  IF v_split_sum <> p_amount_cents THEN
    PERFORM public.api_error('INVALID_SPLITS_SUM', 'Split amounts must sum to the expense amount.', '22023',
      jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
    );
  END IF;

  -- Lock order convention: expense already locked; now safe to mutate splits
  DELETE FROM public.expense_splits s
   WHERE s.expense_id = v_existing.id;
  IF v_is_recurring THEN
    -- User-generated recurring activation consumes quota for the first cycle intent
    PERFORM public._home_assert_quota(v_existing.home_id, jsonb_build_object('active_expenses', 1));

    INSERT INTO public.expense_plans (
      home_id,
      created_by_user_id,
      split_type,
      amount_cents,
      description,
      notes,
      recurrence_every,
      recurrence_unit,
      start_date,
      next_cycle_date,
      status
    )
    VALUES (
      v_existing.home_id,
      v_user,
      v_target_split,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_target_recur_every,
      v_target_recur_unit,
      v_target_start,
      public._expense_plan_next_cycle_date_v2(v_target_recur_every, v_target_recur_unit, v_target_start),
      'active'
    )
    RETURNING * INTO v_plan;

    INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
    SELECT v_plan.id, debtor_user_id, amount_cents
      FROM pg_temp.expense_split_buffer;

    -- Mark original draft as converted; do NOT increment usage here
    UPDATE public.expenses
       SET status           = 'converted',
           plan_id          = v_plan.id,
           recurrence_every = v_target_recur_every,
           recurrence_unit  = v_target_recur_unit,
           start_date       = v_target_start,
           updated_at       = now()
     WHERE id = v_existing.id;

    -- First cycle creation increments usage inside _expense_plan_generate_cycle
    v_result := public._expense_plan_generate_cycle(v_plan.id, v_target_start);
    RETURN v_result;
  END IF;

  -- One-off activation path
  PERFORM public._home_assert_quota(v_existing.home_id, jsonb_build_object('active_expenses', 1));

  UPDATE public.expenses
     SET status           = 'active',
         split_type       = v_target_split,
         amount_cents     = p_amount_cents,
         description      = btrim(p_description),
         notes            = NULLIF(btrim(p_notes), ''),
         recurrence_every = NULL,
         recurrence_unit  = NULL,
         start_date       = v_target_start,
         updated_at       = now()
   WHERE id = v_existing.id
   RETURNING * INTO v_result;

  INSERT INTO public.expense_splits (
    expense_id,
    debtor_user_id,
    amount_cents,
    status,
    marked_paid_at
  )
  SELECT v_result.id,
         debtor_user_id,
         amount_cents,
         CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
              ELSE 'unpaid'::public.expense_share_status
         END,
         CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
    FROM pg_temp.expense_split_buffer;

  PERFORM public._home_usage_apply_delta(v_existing.home_id, jsonb_build_object('active_expenses', 1));

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_edit_v2"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_edit_v3"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT NULL::"date", "p_evidence_photo_path" "text" DEFAULT NULL::"text") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user            uuid := auth.uid();

  v_existing_unsafe public.expenses%ROWTYPE;
  v_existing        public.expenses%ROWTYPE;

  v_result          public.expenses%ROWTYPE;
  v_plan            public.expense_plans%ROWTYPE;

  v_home_is_active  boolean;

  v_target_split       public.expense_split_type;
  v_target_recur_every integer;
  v_target_recur_unit  text;
  v_target_start       date;
  v_is_recurring       boolean := FALSE;

  v_split_count     integer := 0;
  v_split_sum       bigint  := 0;
  v_split_min       bigint  := 0;

  v_join_date       date;

  v_has_evidence_arg boolean := p_evidence_photo_path IS NOT NULL;
  v_requested_evidence_path text := NULLIF(btrim(p_evidence_photo_path), '');
  v_target_evidence_path text;
  v_photo_delta integer := 0;

  v_amount_cap constant bigint  := 900000000000;
  v_desc_max   constant integer := 280;
  v_notes_max  constant integer := 2000;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  IF v_requested_evidence_path IS NOT NULL
     AND v_requested_evidence_path NOT LIKE 'households/%' THEN
    PERFORM public.api_error(
      'INVALID_EVIDENCE_PHOTO_PATH',
      'Evidence photo path must start with households/.',
      '22023',
      jsonb_build_object('field', 'evidencePhotoPath')
    );
  END IF;

  SELECT *
    INTO v_existing_unsafe
    FROM public.expenses e
   WHERE e.id = p_expense_id;

  IF NOT FOUND THEN
    PERFORM public.api_error('NOT_FOUND', 'Expense not found.', 'P0002', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_existing_unsafe.home_id
   FOR UPDATE;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004', jsonb_build_object('homeId', v_existing_unsafe.home_id));
  END IF;

  SELECT *
    INTO v_existing
    FROM public.expenses e
   WHERE e.id = p_expense_id
   FOR UPDATE;

  IF v_existing.home_id <> v_existing_unsafe.home_id THEN
    PERFORM public.api_error('CONCURRENT_MODIFICATION', 'Expense changed while editing. Please retry.', '40001', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  SELECT m.valid_from::date
    INTO v_join_date
    FROM public.memberships m
   WHERE m.home_id    = v_existing.home_id
     AND m.user_id    = v_user
     AND m.is_current = TRUE
     AND m.valid_to IS NULL
   LIMIT 1;

  IF v_join_date IS NULL THEN
    PERFORM public.api_error('NOT_HOME_MEMBER', 'You are not a current member of this home.', '42501',
      jsonb_build_object('homeId', v_existing.home_id, 'userId', v_user)
    );
  END IF;

  IF v_existing.plan_id IS NOT NULL THEN
    PERFORM public.api_error('IMMUTABLE_CYCLE', 'Expenses generated from a recurring plan cannot be edited.', '42501');
  END IF;

  IF v_existing.status = 'active' THEN
    IF v_existing.created_by_user_id <> v_user THEN
      PERFORM public.api_error(
        'NOT_CREATOR',
        'Only the creator can edit this active expense.',
        '42501'
      );
    END IF;

    IF p_amount_cents IS DISTINCT FROM v_existing.amount_cents THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Amount is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'amountCents', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_split_mode IS NOT NULL AND p_split_mode IS DISTINCT FROM v_existing.split_type THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Split mode is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'splitMode', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_member_ids IS NOT NULL OR p_splits IS NOT NULL THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Splits are immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'splits', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_recurrence_every IS NOT NULL OR p_recurrence_unit IS NOT NULL THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Recurrence is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'recurrence', 'expenseId', v_existing.id)
      );
    END IF;

    IF p_start_date IS NOT NULL AND p_start_date IS DISTINCT FROM v_existing.start_date THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Start date is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'startDate', 'expenseId', v_existing.id)
      );
    END IF;

    IF v_has_evidence_arg
       AND v_requested_evidence_path IS DISTINCT FROM v_existing.evidence_photo_path THEN
      PERFORM public.api_error(
        'EDIT_NOT_ALLOWED',
        'Evidence photo is immutable for active expenses.',
        '42501',
        jsonb_build_object('field', 'evidencePhotoPath', 'expenseId', v_existing.id)
      );
    END IF;

    IF btrim(COALESCE(p_description, '')) = '' THEN
      PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
    END IF;

    IF char_length(btrim(p_description)) > v_desc_max THEN
      PERFORM public.api_error('INVALID_DESCRIPTION', format('Description must be %s characters or fewer.', v_desc_max), '22023');
    END IF;

    IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
      PERFORM public.api_error('INVALID_NOTES', format('Notes must be %s characters or fewer.', v_notes_max), '22023');
    END IF;

    UPDATE public.expenses
       SET description = btrim(p_description),
           notes = NULLIF(btrim(p_notes), ''),
           updated_at = now()
     WHERE id = v_existing.id
     RETURNING * INTO v_result;

    RETURN v_result;
  END IF;

  IF v_existing.created_by_user_id <> v_user THEN
    PERFORM public.api_error('NOT_CREATOR', 'Only the creator can modify this expense.', '42501');
  END IF;

  IF v_existing.status <> 'draft' THEN
    PERFORM public.api_error('INVALID_STATE', 'Only draft expenses can be edited.', '42501',
      jsonb_build_object('expenseId', v_existing.id, 'status', v_existing.status)
    );
  END IF;

  IF p_amount_cents IS NULL OR p_amount_cents <= 0 OR p_amount_cents > v_amount_cap THEN
    PERFORM public.api_error('INVALID_AMOUNT', format('Amount must be between 1 and %s cents.', v_amount_cap), '22023');
  END IF;

  IF btrim(COALESCE(p_description, '')) = '' THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', 'Description is required.', '22023');
  END IF;

  IF char_length(btrim(p_description)) > v_desc_max THEN
    PERFORM public.api_error('INVALID_DESCRIPTION', format('Description must be %s characters or fewer.', v_desc_max), '22023');
  END IF;

  IF p_notes IS NOT NULL AND char_length(p_notes) > v_notes_max THEN
    PERFORM public.api_error('INVALID_NOTES', format('Notes must be %s characters or fewer.', v_notes_max), '22023');
  END IF;

  IF p_split_mode IS NULL THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Splits are required. Editing an expense always activates it.', '22023');
  END IF;

  IF (p_recurrence_every IS NULL) <> (p_recurrence_unit IS NULL) THEN
    PERFORM public.api_error(
      'INVALID_RECURRENCE',
      'Recurrence every and unit must both be set or both be null.',
      '22023'
    );
  END IF;

  IF v_has_evidence_arg THEN
    v_target_evidence_path := v_requested_evidence_path;
  ELSE
    v_target_evidence_path := v_existing.evidence_photo_path;
  END IF;

  v_target_split := p_split_mode;
  v_target_recur_every := p_recurrence_every;
  v_target_recur_unit := p_recurrence_unit;
  v_is_recurring := v_target_recur_every IS NOT NULL;

  IF v_is_recurring THEN
    IF v_target_recur_every < 1 THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence every must be >= 1.',
        '22023'
      );
    END IF;

    IF v_target_recur_unit NOT IN ('day', 'week', 'month', 'year') THEN
      PERFORM public.api_error(
        'INVALID_RECURRENCE',
        'Recurrence unit must be day, week, month, or year.',
        '22023'
      );
    END IF;
  END IF;

  v_target_start := COALESCE(p_start_date, v_existing.start_date);

  IF v_target_start IS NULL THEN
    PERFORM public.api_error('INVALID_START_DATE', 'Start date is required.', '22023');
  END IF;

  IF v_target_start < v_join_date OR v_target_start < (current_date - 90) THEN
    PERFORM public.api_error(
      'INVALID_START_DATE_RANGE',
      'Start date is outside the allowed range.',
      '22023',
      jsonb_build_object(
        'minStartDate',        GREATEST(v_join_date, current_date - 90),
        'joinDate',            v_join_date,
        'maxBackdateDays',     90,
        'attemptedStartDate',  v_target_start
      )
    );
  END IF;

  PERFORM public._expenses_prepare_split_buffer(
    v_existing.home_id,
    v_user,
    p_amount_cents,
    v_target_split,
    p_member_ids,
    p_splits
  );

  SELECT COUNT(*)::int,
         COALESCE(SUM(amount_cents), 0),
         COALESCE(MIN(amount_cents), 0)
    INTO v_split_count, v_split_sum, v_split_min
    FROM pg_temp.expense_split_buffer;

  IF v_split_count < 1 THEN
    PERFORM public.api_error('INVALID_DEBTOR', 'At least one debtor is required.', '22023');
  END IF;

  IF v_split_min <= 0 THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Split amounts must be positive.', '22023');
  END IF;

  IF v_split_sum <> p_amount_cents THEN
    PERFORM public.api_error('INVALID_SPLITS_SUM', 'Split amounts must sum to the expense amount.', '22023',
      jsonb_build_object('amountCents', p_amount_cents, 'splitSumCents', v_split_sum)
    );
  END IF;

  DELETE FROM public.expense_splits s
   WHERE s.expense_id = v_existing.id;

  IF v_is_recurring THEN
    v_photo_delta := CASE WHEN v_target_evidence_path IS NOT NULL THEN 1 ELSE 0 END;

    PERFORM public._home_assert_quota(
      v_existing.home_id,
      jsonb_build_object(
        'active_expenses', 1,
        'expense_photos', v_photo_delta
      )
    );

    INSERT INTO public.expense_plans (
      home_id,
      created_by_user_id,
      split_type,
      amount_cents,
      description,
      notes,
      evidence_photo_path,
      recurrence_every,
      recurrence_unit,
      start_date,
      next_cycle_date,
      status
    )
    VALUES (
      v_existing.home_id,
      v_user,
      v_target_split,
      p_amount_cents,
      btrim(p_description),
      NULLIF(btrim(p_notes), ''),
      v_target_evidence_path,
      v_target_recur_every,
      v_target_recur_unit,
      v_target_start,
      public._expense_plan_next_cycle_date_v2(v_target_recur_every, v_target_recur_unit, v_target_start),
      'active'
    )
    RETURNING * INTO v_plan;

    INSERT INTO public.expense_plan_debtors (plan_id, debtor_user_id, share_amount_cents)
    SELECT v_plan.id, debtor_user_id, amount_cents
      FROM pg_temp.expense_split_buffer;

    UPDATE public.expenses
       SET status              = 'converted',
           plan_id             = v_plan.id,
           recurrence_every    = v_target_recur_every,
           recurrence_unit     = v_target_recur_unit,
           evidence_photo_path = v_target_evidence_path,
           start_date          = v_target_start,
           updated_at          = now()
     WHERE id = v_existing.id;

    IF v_photo_delta > 0 THEN
      PERFORM public._home_usage_apply_delta(
        v_existing.home_id,
        jsonb_build_object('expense_photos', 1)
      );
    END IF;

    v_result := public._expense_plan_generate_cycle(v_plan.id, v_target_start);
    RETURN v_result;
  END IF;

  v_photo_delta := CASE WHEN v_target_evidence_path IS NOT NULL THEN 1 ELSE 0 END;

  PERFORM public._home_assert_quota(
    v_existing.home_id,
    jsonb_build_object(
      'active_expenses', 1,
      'expense_photos', v_photo_delta
    )
  );

  UPDATE public.expenses
     SET status              = 'active',
         split_type          = v_target_split,
         amount_cents        = p_amount_cents,
         description         = btrim(p_description),
         notes               = NULLIF(btrim(p_notes), ''),
         evidence_photo_path = v_target_evidence_path,
         recurrence_every    = NULL,
         recurrence_unit     = NULL,
         start_date          = v_target_start,
         updated_at          = now()
   WHERE id = v_existing.id
   RETURNING * INTO v_result;

  INSERT INTO public.expense_splits (
    expense_id,
    debtor_user_id,
    amount_cents,
    status,
    marked_paid_at
  )
  SELECT v_result.id,
         debtor_user_id,
         amount_cents,
         CASE WHEN debtor_user_id = v_user THEN 'paid'::public.expense_share_status
              ELSE 'unpaid'::public.expense_share_status
         END,
         CASE WHEN debtor_user_id = v_user THEN now() ELSE NULL END
    FROM pg_temp.expense_split_buffer;

  PERFORM public._home_usage_apply_delta(
    v_existing.home_id,
    jsonb_build_object(
      'active_expenses', 1,
      'expense_photos', v_photo_delta
    )
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_edit_v3"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date", "p_evidence_photo_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_edit_v5"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text" DEFAULT NULL::"text", "p_allocation_target_type" "text" DEFAULT NULL::"text", "p_split_mode" "public"."expense_split_type" DEFAULT NULL::"public"."expense_split_type", "p_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_splits" "jsonb" DEFAULT NULL::"jsonb", "p_unit_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_unit_splits" "jsonb" DEFAULT NULL::"jsonb", "p_recurrence_every" integer DEFAULT NULL::integer, "p_recurrence_unit" "text" DEFAULT NULL::"text", "p_start_date" "date" DEFAULT NULL::"date", "p_evidence_photo_path" "text" DEFAULT NULL::"text") RETURNS "public"."expenses"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_existing public.expenses%ROWTYPE;
  v_target_start date;
  v_target_photo_path text;
  v_photo_delta integer := 0;
  v_has_evidence_arg boolean := p_evidence_photo_path IS NOT NULL;
  v_is_recurring boolean := FALSE;
  v_plan public.expense_plans%ROWTYPE;
  v_result public.expenses%ROWTYPE;
  v_editability jsonb;
BEGIN
  PERFORM public._assert_authenticated();

  v_existing := public._expense_lock_expense_with_home_active(p_expense_id);
  PERFORM public._expense_require_current_membership(v_existing.home_id, v_user);

  v_editability := public._expense_get_editability(p_expense_id, v_user);

  IF COALESCE((v_editability ->> 'canEdit')::boolean, FALSE) IS NOT TRUE THEN
    PERFORM public.api_error(
      'EDIT_NOT_ALLOWED',
      'This expense cannot be edited.',
      '42501',
      jsonb_build_object(
        'expenseId', p_expense_id,
        'reason', v_editability ->> 'reason'
      )
    );
  END IF;

  IF v_existing.status = 'active' THEN
    IF p_amount_cents IS DISTINCT FROM v_existing.amount_cents THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Amount is immutable for active expenses.', '42501', jsonb_build_object('field', 'amountCents', 'expenseId', v_existing.id));
    END IF;

    IF p_allocation_target_type IS NOT NULL AND p_allocation_target_type IS DISTINCT FROM v_existing.allocation_target_type THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Allocation target type is immutable for active expenses.', '42501', jsonb_build_object('field', 'allocationTargetType', 'expenseId', v_existing.id));
    END IF;

    IF p_split_mode IS NOT NULL AND p_split_mode IS DISTINCT FROM v_existing.split_type THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Split mode is immutable for active expenses.', '42501', jsonb_build_object('field', 'splitMode', 'expenseId', v_existing.id));
    END IF;

    IF p_member_ids IS NOT NULL OR p_splits IS NOT NULL OR p_unit_ids IS NOT NULL OR p_unit_splits IS NOT NULL THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Splits are immutable for active expenses.', '42501', jsonb_build_object('field', 'splits', 'expenseId', v_existing.id));
    END IF;

    IF p_recurrence_every IS NOT NULL OR p_recurrence_unit IS NOT NULL THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Recurrence is immutable for active expenses.', '42501', jsonb_build_object('field', 'recurrence', 'expenseId', v_existing.id));
    END IF;

    IF p_start_date IS NOT NULL AND p_start_date IS DISTINCT FROM v_existing.start_date THEN
      PERFORM public.api_error('EDIT_NOT_ALLOWED', 'Start date is immutable for active expenses.', '42501', jsonb_build_object('field', 'startDate', 'expenseId', v_existing.id));
    END IF;

    PERFORM public._expense_validate_common_fields(p_description, p_notes, v_existing.amount_cents, FALSE);

    IF v_has_evidence_arg THEN
      v_target_photo_path := public._expense_validate_evidence_photo_path(p_evidence_photo_path);
    ELSE
      v_target_photo_path := v_existing.evidence_photo_path;
    END IF;

    v_photo_delta := public._expense_validate_photo_transition(v_existing.evidence_photo_path, v_target_photo_path);

    IF v_photo_delta = 1 THEN
      PERFORM public._home_assert_quota(
        v_existing.home_id,
        jsonb_build_object('expense_photos', 1)
      );
    END IF;

    UPDATE public.expenses
    SET description = btrim(p_description),
        notes = NULLIF(btrim(p_notes), ''),
        evidence_photo_path = v_target_photo_path,
        updated_at = now()
    WHERE id = v_existing.id
    RETURNING * INTO v_result;

    IF v_photo_delta = 1 THEN
      PERFORM public._home_usage_apply_delta(
        v_existing.home_id,
        jsonb_build_object('expense_photos', 1)
      );
    END IF;

    RETURN v_result;
  END IF;

  IF p_allocation_target_type IS NULL THEN
    PERFORM public.api_error('INVALID_ALLOCATION_TARGET', 'Editing a draft to active requires allocation target type.', '22023');
  END IF;

  IF p_allocation_target_type NOT IN ('debtor_based', 'unit_based') THEN
    PERFORM public.api_error('INVALID_ALLOCATION_TARGET', 'Unknown allocation target type.', '22023');
  END IF;

  IF p_split_mode IS NULL THEN
    PERFORM public.api_error('INVALID_SPLITS', 'Splits are required. Editing an expense always activates it.', '22023');
  END IF;

  IF p_allocation_target_type = 'debtor_based' AND (p_unit_ids IS NOT NULL OR p_unit_splits IS NOT NULL) THEN
    PERFORM public.api_error('INVALID_ALLOCATION_TARGET', 'Debtor-based expenses must not include unit split payloads.', '22023');
  END IF;

  IF p_allocation_target_type = 'unit_based' AND (p_member_ids IS NOT NULL OR p_splits IS NOT NULL) THEN
    PERFORM public.api_error('INVALID_ALLOCATION_TARGET', 'Unit-based expenses must not include debtor-based split payloads.', '22023');
  END IF;

  PERFORM public._expense_validate_common_fields(p_description, p_notes, p_amount_cents, FALSE);
  PERFORM public._expense_validate_recurrence_fields(p_recurrence_every, p_recurrence_unit);
  v_target_start := COALESCE(p_start_date, v_existing.start_date);
  PERFORM public._expense_validate_start_date_range(v_existing.home_id, v_user, v_target_start);

  IF v_has_evidence_arg THEN
    v_target_photo_path := public._expense_validate_evidence_photo_path(p_evidence_photo_path);
  ELSE
    v_target_photo_path := v_existing.evidence_photo_path;
  END IF;

  v_photo_delta := public._expense_validate_photo_transition(v_existing.evidence_photo_path, v_target_photo_path);
  v_is_recurring := p_recurrence_every IS NOT NULL;

  IF NOT v_is_recurring THEN
    PERFORM public._expense_quota_assert_activate_one_off(v_existing.home_id, v_photo_delta);

    UPDATE public.expenses
    SET status = 'active',
        allocation_target_type = p_allocation_target_type,
        split_type = p_split_mode,
        amount_cents = p_amount_cents,
        description = btrim(p_description),
        notes = NULLIF(btrim(p_notes), ''),
        evidence_photo_path = v_target_photo_path,
        recurrence_every = NULL,
        recurrence_unit = NULL,
        start_date = v_target_start,
        updated_at = now()
    WHERE id = v_existing.id
    RETURNING * INTO v_result;

    IF p_allocation_target_type = 'debtor_based' THEN
      PERFORM public._expense_persist_debtor_splits(
        v_result.id,
        v_user,
        p_amount_cents,
        p_split_mode,
        p_member_ids,
        p_splits
      );
    ELSE
      PERFORM public._expense_persist_unit_splits(
        v_result.id,
        v_user,
        p_amount_cents,
        p_split_mode,
        p_unit_ids,
        p_unit_splits
      );
    END IF;

    PERFORM public._expense_quota_apply_activate_one_off(v_existing.home_id, v_photo_delta);
    RETURN v_result;
  END IF;

  PERFORM public._expense_quota_assert_activate_plan_with_first_cycle(v_existing.home_id, v_photo_delta);

  INSERT INTO public.expense_plans (
    home_id,
    created_by_user_id,
    allocation_target_type,
    split_type,
    amount_cents,
    description,
    notes,
    evidence_photo_path,
    recurrence_every,
    recurrence_unit,
    start_date,
    next_cycle_date,
    status,
    termination_reason
  )
  VALUES (
    v_existing.home_id,
    v_user,
    p_allocation_target_type,
    p_split_mode,
    p_amount_cents,
    btrim(p_description),
    NULLIF(btrim(p_notes), ''),
    v_target_photo_path,
    p_recurrence_every,
    p_recurrence_unit,
    v_target_start,
    public._expense_plan_next_cycle_date_v2(p_recurrence_every, p_recurrence_unit, v_target_start),
    'active',
    NULL
  )
  RETURNING * INTO v_plan;

  IF p_allocation_target_type = 'debtor_based' THEN
    PERFORM public._expense_persist_plan_debtor_targets(
      v_plan.id,
      v_user,
      p_amount_cents,
      p_split_mode,
      p_member_ids,
      p_splits
    );
  ELSE
    PERFORM public._expense_persist_plan_unit_targets(
      v_plan.id,
      v_user,
      p_amount_cents,
      p_split_mode,
      p_unit_ids,
      p_unit_splits
    );
  END IF;

  UPDATE public.expenses
  SET status = 'converted',
      plan_id = v_plan.id,
      allocation_target_type = p_allocation_target_type,
      recurrence_every = p_recurrence_every,
      recurrence_unit = p_recurrence_unit,
      evidence_photo_path = v_target_photo_path,
      start_date = v_target_start,
      updated_at = now()
  WHERE id = v_existing.id;

  v_result := public._expense_plan_generate_cycle_v3(v_plan.id, v_target_start, FALSE);
  PERFORM public._expense_quota_apply_activate_plan_with_first_cycle(v_existing.home_id, v_photo_delta);

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_edit_v5"("p_expense_id" "uuid", "p_amount_cents" bigint, "p_description" "text", "p_notes" "text", "p_allocation_target_type" "text", "p_split_mode" "public"."expense_split_type", "p_member_ids" "uuid"[], "p_splits" "jsonb", "p_unit_ids" "uuid"[], "p_unit_splits" "jsonb", "p_recurrence_every" integer, "p_recurrence_unit" "text", "p_start_date" "date", "p_evidence_photo_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_created_by_me"("p_home_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid;
  v_result         jsonb;
  v_home_is_active boolean;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  IF p_home_id IS NULL THEN
    PERFORM public.api_error(
      'INVALID_HOME',
      'Home id is required.',
      '22023'
    );
  END IF;

  PERFORM 1
  FROM public.memberships m
  WHERE m.home_id    = p_home_id
    AND m.user_id    = v_user
    AND m.is_current = TRUE
  LIMIT 1;

  IF NOT FOUND THEN
    PERFORM public.api_error(
      'NOT_HOME_MEMBER',
      'You are not a member of this home.',
      '42501',
      jsonb_build_object('homeId', p_home_id, 'userId', v_user)
    );
  END IF;

  SELECT h.is_active
  INTO v_home_is_active
  FROM public.homes h
  WHERE h.id = p_home_id;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error(
      'HOME_INACTIVE',
      'This home is no longer active.',
      'P0004'
    );
  END IF;

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'expenseId',         e.id,
               'homeId',            e.home_id,
               'createdByUserId',   e.created_by_user_id,
               'description',       e.description,
               'amountCents',       e.amount_cents,
               'status',            e.status,
               'splitType',         e.split_type,
               'evidencePhotoPath', e.evidence_photo_path,
               'createdAt',         e.created_at,
               'recurrenceEvery',   e.recurrence_every,
               'recurrenceUnit',    e.recurrence_unit,
               'startDate',         e.start_date,
               'totalShares',       COALESCE(stats.total_shares, 0)::int,
               'paidShares',        COALESCE(stats.paid_shares, 0)::int,
               'paidAmountCents',   COALESCE(stats.paid_amount_cents, 0),
               'allPaid',
                 CASE
                   WHEN COALESCE(stats.total_shares, 0) = 0 THEN FALSE
                   ELSE COALESCE(stats.total_shares, 0) = COALESCE(stats.paid_shares, 0)
                 END,
               'fullyPaidAt',
                 CASE
                   WHEN COALESCE(stats.total_shares, 0) = 0 THEN NULL
                   WHEN COALESCE(stats.total_shares, 0) = COALESCE(stats.paid_shares, 0)
                     THEN stats.max_paid_at
                   ELSE NULL
                 END
             )
             ORDER BY
               CASE
                 WHEN COALESCE(stats.total_shares, 0) = 0 THEN 0
                 WHEN COALESCE(stats.paid_shares, 0) = 0 THEN 0
                 WHEN COALESCE(stats.total_shares, 0) = COALESCE(stats.paid_shares, 0)
                   THEN 2
                 ELSE 1
               END,
               e.created_at DESC,
               e.id
           ),
           '[]'::jsonb
         )
  INTO v_result
  FROM public.expenses e
    LEFT JOIN LATERAL (
      SELECT
        COUNT(*) AS total_shares,
        COUNT(*) FILTER (WHERE s.status = 'paid') AS paid_shares,
        COALESCE(
          SUM(s.amount_cents) FILTER (WHERE s.status = 'paid'),
          0
        ) AS paid_amount_cents,
        MAX(s.marked_paid_at) FILTER (WHERE s.status = 'paid') AS max_paid_at
      FROM public.expense_splits s
      WHERE s.expense_id = e.id
    ) stats ON TRUE
  WHERE e.home_id            = p_home_id
    AND e.created_by_user_id = v_user
    AND e.status IN ('draft', 'active')
    AND NOT (
      COALESCE(stats.total_shares, 0) > 0
      AND COALESCE(stats.total_shares, 0) = COALESCE(stats.paid_shares, 0)
      AND e.created_at < (CURRENT_TIMESTAMP - INTERVAL '14 days')
    );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_get_created_by_me"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_current_owed"("p_home_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user   uuid;
  v_result jsonb;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'payerUserId',     payer_user_id,
               'payerDisplay',    payer_display,
               'payerAvatarUrl',  payer_avatar_url,
               'totalOwedCents',  total_owed_cents,
               'items',           items
             )
             ORDER BY payer_display NULLS LAST, payer_user_id
           ),
           '[]'::jsonb
         )
  INTO v_result
  FROM (
    SELECT
      e.created_by_user_id                          AS payer_user_id,
      COALESCE(p.username, p.full_name, p.email)    AS payer_display,
      a.storage_path                                AS payer_avatar_url,
      SUM(s.amount_cents)                           AS total_owed_cents,
      jsonb_agg(
        jsonb_build_object(
          'expenseId',         e.id,
          'description',       e.description,
          'amountCents',       s.amount_cents,
          'notes',             e.notes,
          'evidencePhotoPath', e.evidence_photo_path,
          'recurrenceEvery',   e.recurrence_every,
          'recurrenceUnit',    e.recurrence_unit,
          'startDate',         e.start_date
        )
        ORDER BY e.created_at DESC, e.id
      ) AS items
    FROM public.expense_splits s
    JOIN public.expenses e
      ON e.id = s.expense_id
    JOIN public.profiles p
      ON p.id = e.created_by_user_id
    JOIN public.avatars a
      ON a.id = p.avatar_id
    WHERE e.home_id        = p_home_id
      AND e.status         = 'active'
      AND s.debtor_user_id = v_user
      AND s.status         = 'unpaid'
    GROUP BY e.created_by_user_id, payer_display, payer_avatar_url
  ) owed;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_get_current_owed"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_current_owed_v3"("p_home_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid;
  v_result jsonb;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'payerUserId', payer_user_id,
               'payerDisplay', payer_display,
               'payerAvatarUrl', payer_avatar_url,
               'totalOwedCents', total_owed_cents,
               'containsSharedUnitBalance', contains_shared_unit_balance,
               'items', items
             )
             ORDER BY payer_display NULLS LAST, payer_user_id
           ),
           '[]'::jsonb
         )
  INTO v_result
  FROM (
    SELECT
      payer_user_id,
      payer_display,
      payer_avatar_url,
      SUM(remaining_cents) AS total_owed_cents,
      BOOL_OR(contains_shared_unit_balance) AS contains_shared_unit_balance,
      jsonb_agg(item ORDER BY created_at DESC, expense_id) AS items
    FROM (
      SELECT
        e.created_by_user_id AS payer_user_id,
        COALESCE(p.username, p.full_name, p.email) AS payer_display,
        a.storage_path AS payer_avatar_url,
        e.created_at,
        e.id AS expense_id,
        s.amount_cents AS remaining_cents,
        FALSE AS contains_shared_unit_balance,
        jsonb_build_object(
          'expenseId', e.id,
          'allocationTargetType', 'debtor_based',
          'liabilityKind', 'personal',
          'liabilityScope', 'user',
          'displayMode', 'personal_balance',
          'description', e.description,
          'amountCents', s.amount_cents,
          'paidCents', 0,
          'remainingCents', s.amount_cents,
          'notes', e.notes,
          'evidencePhotoPath', e.evidence_photo_path,
          'recurrenceEvery', e.recurrence_every,
          'recurrenceUnit', e.recurrence_unit,
          'startDate', e.start_date
        ) AS item
      FROM public.expense_splits s
      JOIN public.expenses e
        ON e.id = s.expense_id
      JOIN public.profiles p
        ON p.id = e.created_by_user_id
      LEFT JOIN public.avatars a
        ON a.id = p.avatar_id
      WHERE e.home_id = p_home_id
        AND e.status = 'active'
        AND COALESCE(e.allocation_target_type, 'debtor_based') = 'debtor_based'
        AND s.debtor_user_id = v_user
        AND s.status = 'unpaid'

      UNION ALL

      SELECT
        e.created_by_user_id AS payer_user_id,
        COALESCE(p.username, p.full_name, p.email) AS payer_display,
        a.storage_path AS payer_avatar_url,
        e.created_at,
        e.id AS expense_id,
        (s.amount_cents - s.paid_cents) AS remaining_cents,
        (hu.unit_type = 'shared') AS contains_shared_unit_balance,
        jsonb_build_object(
          'expenseId', e.id,
          'allocationTargetType', 'unit_based',
          'liabilityKind', CASE WHEN hu.unit_type = 'shared' THEN 'shared' ELSE 'personal' END,
          'liabilityScope', 'unit',
          'displayMode', CASE WHEN hu.unit_type = 'shared' THEN 'shared_unit_balance' ELSE 'unit_balance' END,
          'unitId', s.unit_id,
          'unitName', hu.name,
          'description', e.description,
          'amountCents', s.amount_cents,
          'paidCents', s.paid_cents,
          'remainingCents', (s.amount_cents - s.paid_cents),
          'notes', e.notes,
          'evidencePhotoPath', e.evidence_photo_path,
          'recurrenceEvery', e.recurrence_every,
          'recurrenceUnit', e.recurrence_unit,
          'startDate', e.start_date
        ) AS item
      FROM public.expense_unit_splits s
      JOIN public.expenses e
        ON e.id = s.expense_id
      JOIN public.home_units hu
        ON hu.id = s.unit_id
       AND hu.home_id = s.home_id
      JOIN public.profiles p
        ON p.id = e.created_by_user_id
      LEFT JOIN public.avatars a
        ON a.id = p.avatar_id
      WHERE e.home_id = p_home_id
        AND e.status = 'active'
        AND e.allocation_target_type = 'unit_based'
        AND s.paid_cents < s.amount_cents
        AND EXISTS (
          SELECT 1
          FROM public.home_unit_members hum
          JOIN public.memberships m
            ON m.id = hum.membership_id
          WHERE hum.unit_id = s.unit_id
            AND m.user_id = v_user
            AND m.home_id = p_home_id
            AND m.valid_to IS NULL
        )
    ) unioned
    GROUP BY payer_user_id, payer_display, payer_avatar_url
  ) grouped;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_get_current_owed_v3"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_current_paid_to_me_by_debtor_details"("p_home_id" "uuid", "p_debtor_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user   uuid;
  v_result jsonb;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  IF p_debtor_user_id IS NULL THEN
    PERFORM public.api_error(
      'INVALID_DEBTOR',
      'Debtor id is required.',
      '22023'
    );
  END IF;

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'expenseId',       expense_id,
               'description',     description,
               'notes',           notes,
               'amountCents',     amount_cents,
               'markedPaidAt',    marked_paid_at,
               'debtorUsername',  debtor_username,
               'debtorAvatarUrl', debtor_avatar_url,
               'isOwner',         debtor_is_owner,
               'recurrenceEvery', recurrence_every,
               'recurrenceUnit',  recurrence_unit,
               'startDate',       start_date
             )
             ORDER BY marked_paid_at DESC, expense_id
           ),
           '[]'::jsonb
         )
  INTO v_result
  FROM (
    SELECT
      e.id                                      AS expense_id,
      e.description                             AS description,
      e.notes                                   AS notes,
      s.amount_cents                            AS amount_cents,
      s.marked_paid_at                          AS marked_paid_at,
      p.username                                AS debtor_username,
      a.storage_path                            AS debtor_avatar_url,
      (h.owner_user_id = s.debtor_user_id)      AS debtor_is_owner,
      e.recurrence_every                        AS recurrence_every,
      e.recurrence_unit                         AS recurrence_unit,
      e.start_date                              AS start_date
    FROM public.expense_splits s
    JOIN public.expenses e
      ON e.id = s.expense_id
    JOIN public.homes h
      ON h.id = e.home_id
    JOIN public.profiles p
      ON p.id = s.debtor_user_id
    LEFT JOIN public.avatars a
      ON a.id = p.avatar_id
    WHERE e.home_id            = p_home_id
      AND e.created_by_user_id = v_user
      AND s.debtor_user_id     = p_debtor_user_id
      AND s.status             = 'paid'
      AND s.marked_paid_at     IS NOT NULL
      AND s.recipient_viewed_at IS NULL
      AND s.debtor_user_id    <> e.created_by_user_id
  ) details;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_get_current_paid_to_me_by_debtor_details"("p_home_id" "uuid", "p_debtor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_current_paid_to_me_debtors"("p_home_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user   uuid;
  v_result jsonb;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'debtorUserId',   debtor_user_id,
                'debtorUsername', debtor_username,
               'debtorAvatarUrl', debtor_avatar_url,
               'isOwner',        debtor_is_owner,
               'totalPaidCents', total_paid_cents,
               'unseenCount',    unseen_count,
               'latestPaidAt',   latest_paid_at
             )
             ORDER BY latest_paid_at DESC,
                      debtor_username,
                      debtor_user_id
           ),
           '[]'::jsonb
         )
  INTO v_result
  FROM (
    SELECT
      s.debtor_user_id                                      AS debtor_user_id,
      p.username                                            AS debtor_username,
      a.storage_path                                        AS debtor_avatar_url,
      (h.owner_user_id = s.debtor_user_id)                  AS debtor_is_owner,
      SUM(s.amount_cents)                                   AS total_paid_cents,
      COUNT(*) FILTER (WHERE s.recipient_viewed_at IS NULL) AS unseen_count,
      MAX(s.marked_paid_at)                                 AS latest_paid_at
    FROM public.expense_splits s
    JOIN public.expenses e
      ON e.id = s.expense_id
    JOIN public.profiles p
      ON p.id = s.debtor_user_id
    LEFT JOIN public.avatars a
      ON a.id = p.avatar_id
    JOIN public.homes h
      ON h.id = e.home_id
    WHERE e.home_id            = p_home_id
      AND e.created_by_user_id = v_user
      AND s.status             = 'paid'
      AND s.marked_paid_at     IS NOT NULL
      AND s.recipient_viewed_at IS NULL
      AND s.debtor_user_id    <> e.created_by_user_id
    GROUP BY s.debtor_user_id, p.username, a.storage_path, h.owner_user_id
  ) debtors
  WHERE unseen_count > 0;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."expenses_get_current_paid_to_me_debtors"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_for_edit"("p_expense_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user               uuid := auth.uid();
  v_expense            public.expenses%ROWTYPE;
  v_home_is_active     boolean;
  v_plan_status        public.expense_plan_status;
  v_splits             jsonb := '[]'::jsonb;
  v_can_edit           boolean := FALSE;
  v_edit_disabled      text := NULL;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  SELECT e.*
    INTO v_expense
    FROM public.expenses e
   WHERE e.id = p_expense_id
     AND EXISTS (
       SELECT 1
         FROM public.memberships m
        WHERE m.home_id    = e.home_id
          AND m.user_id    = v_user
          AND m.is_current = TRUE
          AND m.valid_to IS NULL
     );

  IF NOT FOUND THEN
    PERFORM public.api_error('NOT_FOUND', 'Expense not found.', 'P0002', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  SELECT h.is_active
    INTO v_home_is_active
    FROM public.homes h
   WHERE h.id = v_expense.home_id;

  IF v_home_is_active IS DISTINCT FROM TRUE THEN
    PERFORM public.api_error('HOME_INACTIVE', 'This home is no longer active.', 'P0004', jsonb_build_object('homeId', v_expense.home_id));
  END IF;

  IF v_expense.created_by_user_id <> v_user THEN
    PERFORM public.api_error('NOT_CREATOR', 'Only the creator can edit this expense.', '42501',
      jsonb_build_object('expenseId', p_expense_id, 'userId', v_user)
    );
  END IF;

  IF v_expense.plan_id IS NOT NULL THEN
    SELECT ep.status
      INTO v_plan_status
      FROM public.expense_plans ep
     WHERE ep.id = v_expense.plan_id
     LIMIT 1;
  END IF;

  v_can_edit := (
    v_expense.status = 'draft'::public.expense_status
    OR (
      v_expense.status = 'active'::public.expense_status
      AND v_expense.plan_id IS NULL
    )
  );

  IF NOT v_can_edit THEN
    IF v_expense.plan_id IS NOT NULL THEN
      IF v_expense.status = 'converted'::public.expense_status THEN
        v_edit_disabled := 'CONVERTED_TO_PLAN';
      ELSE
        v_edit_disabled := 'RECURRING_CYCLE_IMMUTABLE';
      END IF;
    ELSE
      CASE v_expense.status
        WHEN 'active'::public.expense_status THEN v_edit_disabled := 'ACTIVE_IMMUTABLE';
        WHEN 'converted'::public.expense_status THEN v_edit_disabled := 'CONVERTED_TO_PLAN';
        ELSE v_edit_disabled := 'NOT_EDITABLE';
      END CASE;
    END IF;
  END IF;

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'expenseId',    s.expense_id,
               'debtorUserId', s.debtor_user_id,
               'amountCents',  s.amount_cents,
               'status',       s.status,
               'markedPaidAt', s.marked_paid_at
             )
             ORDER BY s.debtor_user_id
           ),
           '[]'::jsonb
         )
    INTO v_splits
    FROM public.expense_splits s
   WHERE s.expense_id = v_expense.id;

  RETURN jsonb_build_object(
    'expenseId',          v_expense.id,
    'homeId',             v_expense.home_id,
    'createdByUserId',    v_expense.created_by_user_id,
    'status',             v_expense.status,
    'splitType',          v_expense.split_type,
    'amountCents',        v_expense.amount_cents,
    'description',        v_expense.description,
    'notes',              v_expense.notes,
    'evidencePhotoPath',  v_expense.evidence_photo_path,
    'createdAt',          v_expense.created_at,
    'updatedAt',          v_expense.updated_at,
    'planId',             v_expense.plan_id,
    'planStatus',         v_plan_status,
    'recurrenceEvery',    v_expense.recurrence_every,
    'recurrenceUnit',     v_expense.recurrence_unit,
    'startDate',          v_expense.start_date,
    'canEdit',            v_can_edit,
    'editDisabledReason', v_edit_disabled,
    'splits',             v_splits
  );
END;
$$;


ALTER FUNCTION "public"."expenses_get_for_edit"("p_expense_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_get_for_edit_v3"("p_expense_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_expense public.expenses%ROWTYPE;
  v_plan_status public.expense_plan_status;
  v_splits jsonb := '[]'::jsonb;
  v_unit_splits jsonb := '[]'::jsonb;
  v_editability jsonb;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id is required.', '22023');
  END IF;

  SELECT e.*
  INTO v_expense
  FROM public.expenses e
  WHERE e.id = p_expense_id;

  IF NOT FOUND THEN
    PERFORM public.api_error('NOT_FOUND', 'Expense not found.', 'P0002', jsonb_build_object('expenseId', p_expense_id));
  END IF;

  PERFORM public._assert_home_active(v_expense.home_id);
  PERFORM public._expense_require_current_membership(v_expense.home_id, v_user);

  IF v_expense.created_by_user_id <> v_user THEN
    PERFORM public.api_error('NOT_CREATOR', 'Only the creator can edit this expense.', '42501', jsonb_build_object('expenseId', p_expense_id, 'userId', v_user));
  END IF;

  v_editability := public._expense_get_editability(p_expense_id, v_user);
  v_plan_status := NULLIF(v_editability ->> 'planStatus', '')::public.expense_plan_status;

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'expenseId', s.expense_id,
               'debtorUserId', s.debtor_user_id,
               'amountCents', s.amount_cents,
               'status', s.status,
               'markedPaidAt', s.marked_paid_at
             )
             ORDER BY s.debtor_user_id
           ),
           '[]'::jsonb
         )
  INTO v_splits
  FROM public.expense_splits s
  WHERE s.expense_id = v_expense.id;

  SELECT COALESCE(
           jsonb_agg(
             jsonb_build_object(
               'expenseId', s.expense_id,
               'unitId', s.unit_id,
               'unitName', hu.name,
               'unitType', hu.unit_type,
               'amountCents', s.amount_cents,
               'paidCents', s.paid_cents,
               'remainingCents', s.amount_cents - s.paid_cents,
               'fullyPaidAt', s.fully_paid_at
             )
             ORDER BY hu.name, s.unit_id
           ),
           '[]'::jsonb
         )
  INTO v_unit_splits
  FROM public.expense_unit_splits s
  JOIN public.home_units hu
    ON hu.id = s.unit_id
   AND hu.home_id = s.home_id
  WHERE s.expense_id = v_expense.id;

  RETURN jsonb_build_object(
    'expenseId', v_expense.id,
    'homeId', v_expense.home_id,
    'createdByUserId', v_expense.created_by_user_id,
    'status', v_expense.status,
    'allocationTargetType', v_expense.allocation_target_type,
    'splitType', v_expense.split_type,
    'amountCents', v_expense.amount_cents,
    'description', v_expense.description,
    'notes', v_expense.notes,
    'evidencePhotoPath', v_expense.evidence_photo_path,
    'createdAt', v_expense.created_at,
    'updatedAt', v_expense.updated_at,
    'planId', v_expense.plan_id,
    'planStatus', v_plan_status,
    'recurrenceEvery', v_expense.recurrence_every,
    'recurrenceUnit', v_expense.recurrence_unit,
    'startDate', v_expense.start_date,
    'canEdit', COALESCE((v_editability ->> 'canEdit')::boolean, FALSE),
    'editDisabledReason', v_editability ->> 'reason',
    'splits', v_splits,
    'unitSplits', v_unit_splits
  );
END;
$$;


ALTER FUNCTION "public"."expenses_get_for_edit_v3"("p_expense_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_mark_paid_received_viewed_for_debtor"("p_home_id" "uuid", "p_debtor_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user    uuid;
  v_updated integer := 0;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  PERFORM public._assert_home_member(p_home_id);
  PERFORM public._assert_home_active(p_home_id);

  IF p_debtor_user_id IS NULL THEN
    PERFORM public.api_error(
      'INVALID_DEBTOR',
      'Debtor id is required.',
      '22023'
    );
  END IF;

  UPDATE public.expense_splits s
  SET recipient_viewed_at = now()
  FROM public.expenses e
  WHERE s.expense_id          = e.id
    AND e.home_id             = p_home_id
    AND e.created_by_user_id  = v_user
    AND s.debtor_user_id      = p_debtor_user_id
    AND s.status              = 'paid'
    AND s.marked_paid_at      IS NOT NULL
    AND s.debtor_user_id     <> e.created_by_user_id
    AND s.recipient_viewed_at IS NULL;

  GET DIAGNOSTICS v_updated = ROW_COUNT;

  RETURN jsonb_build_object('updated', COALESCE(v_updated, 0));
END;
$$;


