CREATE OR REPLACE FUNCTION "public"."expenses_pay_my_due"("p_recipient_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user                 uuid := auth.uid();
  v_split_count          integer := 0;
  v_expense_count        integer := 0;
  v_newly_fully_paid_cnt integer := 0;
  v_touched_count        integer := 0;
  v_newly_photo_cnt      integer := 0;
  r                      record;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_recipient_user_id IS NULL THEN
    PERFORM public.api_error(
      'INVALID_RECIPIENT',
      'Recipient (expense creator) is required.',
      '22023'
    );
  END IF;

  CREATE TEMP TABLE IF NOT EXISTS pg_temp.expenses_touched (
    expense_id uuid PRIMARY KEY
  ) ON COMMIT DROP;
  TRUNCATE TABLE pg_temp.expenses_touched;

  CREATE TEMP TABLE IF NOT EXISTS pg_temp.expenses_newly_paid (
    home_id uuid NOT NULL,
    expense_photo_dec integer NOT NULL DEFAULT 0
  ) ON COMMIT DROP;
  TRUNCATE TABLE pg_temp.expenses_newly_paid;

  WITH target_expenses AS (
    SELECT DISTINCT e.id, e.home_id
      FROM public.expense_splits s
      JOIN public.expenses e ON e.id = s.expense_id
      JOIN public.homes h ON h.id = e.home_id
      JOIN public.memberships m
        ON m.home_id    = e.home_id
       AND m.user_id    = v_user
       AND m.is_current = TRUE
       AND m.valid_to IS NULL
     WHERE s.debtor_user_id = v_user
       AND s.status = 'unpaid'
       AND e.status = 'active'
       AND e.created_by_user_id = p_recipient_user_id
       AND h.is_active = TRUE
  ),
  locked_homes AS (
    SELECT h.id
      FROM public.homes h
     WHERE h.id IN (SELECT home_id FROM target_expenses)
     ORDER BY h.id
     FOR UPDATE
  ),
  locked_expenses AS (
    SELECT e.id, e.home_id
      FROM public.expenses e
      JOIN locked_homes lh ON lh.id = e.home_id
      JOIN public.homes h ON h.id = e.home_id
     WHERE e.id IN (SELECT id FROM target_expenses)
       AND e.status = 'active'
       AND h.is_active = TRUE
     ORDER BY e.id
     FOR UPDATE
  ),
  updated AS (
    UPDATE public.expense_splits s
       SET status              = 'paid',
           marked_paid_at      = now(),
           recipient_viewed_at = NULL
     WHERE s.debtor_user_id = v_user
       AND s.expense_id IN (SELECT id FROM locked_expenses)
       AND s.status = 'unpaid'
    RETURNING s.expense_id
  ),
  aggregates AS (
    SELECT
      COUNT(*)::int AS split_count,
      COUNT(DISTINCT expense_id)::int AS expense_count
    FROM updated
  ),
  inserted AS (
    INSERT INTO pg_temp.expenses_touched (expense_id)
    SELECT DISTINCT expense_id FROM updated
    RETURNING 1
  )
  SELECT
    COALESCE(a.split_count, 0),
    COALESCE(a.expense_count, 0),
    COALESCE((SELECT COUNT(*) FROM inserted), 0)
  INTO
    v_split_count,
    v_expense_count,
    v_touched_count
  FROM aggregates a;

  WITH newly_paid AS (
    UPDATE public.expenses e
       SET fully_paid_at = now()
     WHERE e.id IN (SELECT expense_id FROM pg_temp.expenses_touched)
       AND e.fully_paid_at IS NULL
       AND NOT EXISTS (
         SELECT 1
           FROM public.expense_splits s
          WHERE s.expense_id = e.id
            AND s.status = 'unpaid'
       )
    RETURNING
      e.home_id,
      0 AS expense_photo_dec
  )
  INSERT INTO pg_temp.expenses_newly_paid (home_id, expense_photo_dec)
  SELECT home_id, expense_photo_dec FROM newly_paid;

  SELECT
    COUNT(*)::int,
    COALESCE(SUM(expense_photo_dec), 0)::int
    INTO v_newly_fully_paid_cnt, v_newly_photo_cnt
    FROM pg_temp.expenses_newly_paid;

  FOR r IN
    SELECT
      home_id,
      COUNT(*)::int AS dec_count,
      COALESCE(SUM(expense_photo_dec), 0)::int AS dec_expense_photo_count
    FROM pg_temp.expenses_newly_paid
    GROUP BY home_id
  LOOP
    PERFORM public._home_usage_apply_delta(
      r.home_id,
      jsonb_build_object(
        'active_expenses', -r.dec_count
      )
    );
  END LOOP;

  RETURN jsonb_build_object(
    'recipientUserId',          p_recipient_user_id,
    'splitsPaid',               v_split_count,
    'expensesTouched',          v_expense_count,
    'expensesNewlyFullyPaid',   v_newly_fully_paid_cnt,
    'expensePhotosFreed',       v_newly_photo_cnt
  );
END;
$$;


ALTER FUNCTION "public"."expenses_pay_my_due"("p_recipient_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."expenses_pay_unit_due_v2"("p_expense_id" "uuid", "p_unit_id" "uuid", "p_amount_cents" bigint) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_remaining bigint;
  v_new_paid bigint;
  v_expense public.expenses%ROWTYPE;
  v_is_current_member boolean := FALSE;
  v_fully_paid boolean := FALSE;
BEGIN
  PERFORM public._assert_authenticated();

  IF p_expense_id IS NULL OR p_unit_id IS NULL THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense id and unit id are required.', '22023');
  END IF;

  IF p_amount_cents IS NULL OR p_amount_cents <= 0 THEN
    PERFORM public.api_error('INVALID_PAYMENT_AMOUNT', 'Payment amount must be positive.', '22023');
  END IF;

  v_expense := public._expense_lock_expense_with_home_active(p_expense_id);

  SELECT TRUE
  INTO v_is_current_member
  FROM public.memberships m
  JOIN public.home_unit_members hum
    ON hum.membership_id = m.id
   AND hum.unit_id = p_unit_id
  WHERE m.home_id = v_expense.home_id
    AND m.user_id = v_user
    AND m.valid_to IS NULL
  LIMIT 1;

  IF COALESCE(v_is_current_member, FALSE) IS NOT TRUE THEN
    PERFORM public.api_error(
      'INVALID_UNIT_SCOPE',
      'Caller is not a current member of the debtor unit.',
      '42501',
      jsonb_build_object('expenseId', p_expense_id, 'unitId', p_unit_id)
    );
  END IF;

  IF v_expense.status <> 'active' OR v_expense.allocation_target_type IS DISTINCT FROM 'unit_based' THEN
    PERFORM public.api_error('INVALID_EXPENSE', 'Expense is not an active unit-based expense.', '22023');
  END IF;

  SELECT (s.amount_cents - s.paid_cents)
  INTO v_remaining
  FROM public.expense_unit_splits s
  WHERE s.expense_id = p_expense_id
    AND s.unit_id = p_unit_id
  FOR UPDATE;

  IF v_remaining IS NULL THEN
    PERFORM public.api_error('INVALID_UNIT_TARGET', 'Unit split not found for this expense.', 'P0002');
  END IF;

  IF p_amount_cents > v_remaining THEN
    PERFORM public.api_error(
      'INVALID_PAYMENT_AMOUNT',
      'Payment exceeds remaining unit balance.',
      '22023',
      jsonb_build_object('remainingCents', v_remaining, 'attemptedAmountCents', p_amount_cents)
    );
  END IF;

  UPDATE public.expense_unit_splits s
  SET paid_cents = s.paid_cents + p_amount_cents,
      fully_paid_at = CASE
        WHEN s.paid_cents + p_amount_cents = s.amount_cents THEN now()
        ELSE NULL
      END
  WHERE s.expense_id = p_expense_id
    AND s.unit_id = p_unit_id
  RETURNING paid_cents INTO v_new_paid;

  INSERT INTO public.expense_unit_payment_events (
    expense_id,
    unit_id,
    payer_user_id,
    amount_cents
  )
  VALUES (
    p_expense_id,
    p_unit_id,
    v_user,
    p_amount_cents
  );

  v_fully_paid := public._expense_finalize_if_fully_paid_v2(p_expense_id);

  RETURN jsonb_build_object(
    'expenseId', p_expense_id,
    'unitId', p_unit_id,
    'payerUserId', v_user,
    'amountPaidCents', p_amount_cents,
    'paidCents', v_new_paid,
    'remainingCents', GREATEST(0, v_remaining - p_amount_cents),
    'expenseFullyPaid', v_fully_paid
  );
END;
$$;


ALTER FUNCTION "public"."expenses_pay_unit_due_v2"("p_expense_id" "uuid", "p_unit_id" "uuid", "p_amount_cents" bigint) OWNER TO "postgres";


