COMMENT ON FUNCTION "public"."get_member_directory_notes"("p_target_user_id" "uuid") IS 'Returns active member-directory notes for the target user when the caller is the same user or shares the same active home. Includes reference_url and photo_path when present. Client owns localization for note_type labels.';



CREATE OR REPLACE FUNCTION "public"."get_member_directory_nudge"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_home_id uuid;
  v_missing text[] := ARRAY[]::text[];
  v_show boolean := false;
BEGIN
  PERFORM public._assert_authenticated();

  v_home_id := public._member_directory_get_current_active_home_id(v_user);

  IF NOT EXISTS (
    SELECT 1
    FROM public.member_directory_bank_accounts b
    WHERE b.user_id = v_user
  ) THEN
    v_missing := array_append(v_missing, 'bank_account');
  END IF;

  v_show := array_length(v_missing, 1) IS NOT NULL
    AND NOT EXISTS (
      SELECT 1
      FROM public.member_directory_nudge_dismissals d
      WHERE d.user_id = v_user
        AND d.home_id = v_home_id
    );

  RETURN jsonb_build_object(
    'ok', true,
    'home_id', v_home_id,
    'show', v_show,
    'missing', to_jsonb(CASE WHEN v_show THEN v_missing ELSE ARRAY[]::text[] END)
  );
END;
$$;


