CREATE TABLE IF NOT EXISTS "public"."notification_preferences" (
    "user_id" "uuid" NOT NULL,
    "wants_daily" boolean DEFAULT false NOT NULL,
    "preferred_hour" integer DEFAULT 9 NOT NULL,
    "timezone" "text" NOT NULL,
    "locale" "text" NOT NULL,
    "os_permission" "text" DEFAULT 'unknown'::"text" NOT NULL,
    "last_os_sync_at" timestamp with time zone,
    "last_sent_local_date" "date",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "preferred_minute" integer DEFAULT 0 NOT NULL,
    CONSTRAINT "chk_notification_preferences_preferred_minute" CHECK ((("preferred_minute" >= 0) AND ("preferred_minute" < 60)))
);


ALTER TABLE "public"."notification_preferences" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notifications_sync_client_state"("p_token" "text", "p_platform" "text", "p_locale" "text", "p_timezone" "text", "p_os_permission" "text", "p_wants_daily" boolean DEFAULT NULL::boolean, "p_preferred_hour" integer DEFAULT NULL::integer, "p_preferred_minute" integer DEFAULT NULL::integer) RETURNS "public"."notification_preferences"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id     uuid := auth.uid();
  v_current     public.notification_preferences;
  v_effective_wants_daily      boolean;
  v_effective_preferred_hour   integer;
  v_effective_preferred_minute integer;
  v_should_upsert boolean;
  v_max_active_per_platform integer := 2;

  v_prev_os_permission text := 'unknown';
  v_permission_became_allowed boolean := FALSE;
BEGIN
  PERFORM public._assert_authenticated();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'NOT_AUTHENTICATED';
  END IF;

  SELECT *
  INTO v_current
  FROM public.notification_preferences
  WHERE user_id = v_user_id;

  v_prev_os_permission := COALESCE(v_current.os_permission, 'unknown');
  v_permission_became_allowed :=
    p_os_permission = 'allowed'
    AND v_prev_os_permission IS DISTINCT FROM 'allowed';

  -- wants_daily resolution:
  -- 1) explicit client value wins
  -- 2) blocked/unknown always forced false
  -- 3) first allowed (new row) or transition to allowed auto-enables true
  -- 4) otherwise preserve existing choice while allowed
  IF p_wants_daily IS NOT NULL THEN
    v_effective_wants_daily := p_wants_daily;
  ELSIF p_os_permission IS DISTINCT FROM 'allowed' THEN
    v_effective_wants_daily := FALSE;
  ELSIF v_current.user_id IS NULL OR v_permission_became_allowed THEN
    v_effective_wants_daily := TRUE;
  ELSE
    v_effective_wants_daily := COALESCE(v_current.wants_daily, TRUE);
  END IF;

  v_effective_preferred_hour :=
    COALESCE(
      p_preferred_hour,
      v_current.preferred_hour,
      9
    );

  v_effective_preferred_minute :=
    COALESCE(
      p_preferred_minute,
      v_current.preferred_minute,
      0
    );

  -- Upsert only when we have an explicit change, an existing row, or OS is allowed.
  -- Do NOT upsert just because a token is present if permission is blocked/unknown.
  v_should_upsert :=
       v_current.user_id IS NOT NULL
    OR p_wants_daily IS NOT NULL
    OR p_preferred_hour IS NOT NULL
    OR p_preferred_minute IS NOT NULL
    OR p_os_permission = 'allowed';

  IF NOT v_should_upsert THEN
    RETURN (
      v_user_id,
      v_effective_wants_daily,
      v_effective_preferred_hour,
      COALESCE(p_timezone, 'UTC'),
      COALESCE(p_locale, 'en'),
      p_os_permission,
      now(),
      v_current.last_sent_local_date,
      COALESCE(v_current.created_at, now()),
      now(),
      v_effective_preferred_minute
    )::public.notification_preferences;
  END IF;

  INSERT INTO public.notification_preferences (
    user_id,
    wants_daily,
    preferred_hour,
    preferred_minute,
    timezone,
    locale,
    os_permission,
    last_os_sync_at,
    last_sent_local_date,
    created_at,
    updated_at
  )
  VALUES (
    v_user_id,
    v_effective_wants_daily,
    v_effective_preferred_hour,
    v_effective_preferred_minute,
    p_timezone,
    p_locale,
    p_os_permission,
    now(),
    COALESCE(v_current.last_sent_local_date, NULL),
    COALESCE(v_current.created_at, now()),
    now()
  )
  ON CONFLICT (user_id) DO UPDATE
    SET wants_daily      = EXCLUDED.wants_daily,
        preferred_hour   = EXCLUDED.preferred_hour,
        preferred_minute = EXCLUDED.preferred_minute,
        timezone         = EXCLUDED.timezone,
        locale           = EXCLUDED.locale,
        os_permission    = EXCLUDED.os_permission,
        last_os_sync_at  = EXCLUDED.last_os_sync_at,
        updated_at       = EXCLUDED.updated_at
  RETURNING * INTO v_current;

  IF p_token IS NOT NULL THEN
    INSERT INTO public.device_tokens (
      user_id, token, provider, platform, status,
      last_seen_at, created_at, updated_at
    )
    VALUES (
      v_user_id, p_token, 'fcm', p_platform, 'active',
      now(), now(), now()
    )
    ON CONFLICT (token) DO UPDATE
      SET user_id      = EXCLUDED.user_id,
          platform     = EXCLUDED.platform,
          provider     = EXCLUDED.provider,
          status       = 'active',
          last_seen_at = now(),
          updated_at   = now();

    -- Cap active tokens per platform by expiring the oldest seen tokens.
    IF p_platform IS NOT NULL THEN
      WITH ranked AS (
        SELECT
          id,
          ROW_NUMBER() OVER (
            ORDER BY last_seen_at DESC, updated_at DESC
          ) AS rn
        FROM public.device_tokens
        WHERE user_id = v_user_id
          AND platform = p_platform
          AND provider = 'fcm'
          AND status = 'active'
      )
      UPDATE public.device_tokens
      SET status = 'expired',
          updated_at = now()
      WHERE id IN (
        SELECT id FROM ranked WHERE rn > v_max_active_per_platform
      );
    END IF;
  END IF;

  RETURN v_current;
END;
$$;


ALTER FUNCTION "public"."notifications_sync_client_state"("p_token" "text", "p_platform" "text", "p_locale" "text", "p_timezone" "text", "p_os_permission" "text", "p_wants_daily" boolean, "p_preferred_hour" integer, "p_preferred_minute" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notifications_update_preferences"("p_wants_daily" boolean, "p_preferred_hour" integer, "p_preferred_minute" integer) RETURNS "public"."notification_preferences"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_pref    public.notification_preferences;
BEGIN
  PERFORM public._assert_authenticated();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'NOT_AUTHENTICATED';
  END IF;

  INSERT INTO public.notification_preferences (
    user_id,
    wants_daily,
    preferred_hour,
    preferred_minute,
    timezone,
    locale,
    os_permission,
    last_os_sync_at,
    last_sent_local_date,
    created_at,
    updated_at
  )
  SELECT
    v_user_id,
    p_wants_daily,
    p_preferred_hour,
    p_preferred_minute,
    COALESCE(np.timezone, 'UTC'),
    COALESCE(np.locale, 'en'),
    COALESCE(np.os_permission, 'unknown'),
    np.last_os_sync_at,
    np.last_sent_local_date,
    COALESCE(np.created_at, now()),
    now()
  FROM public.notification_preferences np
  WHERE np.user_id = v_user_id
  UNION ALL
  SELECT
    v_user_id,
    p_wants_daily,
    p_preferred_hour,
    p_preferred_minute,
    'UTC',
    'en',
    'unknown',
    NULL,
    NULL,
    now(),
    now()
  WHERE NOT EXISTS (
    SELECT 1 FROM public.notification_preferences WHERE user_id = v_user_id
  )
  ON CONFLICT (user_id) DO UPDATE
    SET wants_daily     = EXCLUDED.wants_daily,
        preferred_hour  = EXCLUDED.preferred_hour,
        preferred_minute = EXCLUDED.preferred_minute,
        updated_at      = EXCLUDED.updated_at
  RETURNING * INTO v_pref;

  RETURN v_pref;
END;
$$;


ALTER FUNCTION "public"."notifications_update_preferences"("p_wants_daily" boolean, "p_preferred_hour" integer, "p_preferred_minute" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notifications_update_send_status"("p_send_id" "uuid", "p_status" "text", "p_error" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  UPDATE public.notification_sends
  SET status    = p_status,
      error     = p_error,
      failed_at = CASE WHEN p_status = 'failed' THEN now() ELSE failed_at END,
      updated_at = now()
  WHERE id = p_send_id;
END;
$$;


ALTER FUNCTION "public"."notifications_update_send_status"("p_send_id" "uuid", "p_status" "text", "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_event_logs_cleanup"("p_keep" interval DEFAULT '180 days'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_deleted integer;
BEGIN
  DELETE FROM public.outreach_event_logs
   WHERE created_at < (now() - p_keep);

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


ALTER FUNCTION "public"."outreach_event_logs_cleanup"("p_keep" interval) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_log_event"("p_event" "text", "p_app_key" "text", "p_page_key" "text", "p_utm_campaign" "text", "p_utm_source" "text", "p_utm_medium" "text", "p_session_id" "text", "p_store" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT NULL::"text", "p_ui_locale" "text" DEFAULT NULL::"text", "p_client_event_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
declare
  v_event text := lower(trim(p_event));
  v_app_key text := trim(p_app_key);
  v_page_key text := trim(p_page_key);

  v_utm_campaign text := coalesce(nullif(trim(p_utm_campaign), ''), 'unknown');
  v_utm_source   text := coalesce(nullif(lower(trim(p_utm_source)), ''), 'unknown');
  v_utm_medium   text := coalesce(nullif(lower(trim(p_utm_medium)), ''), 'unknown');

  v_store text := coalesce(nullif(lower(trim(p_store)), ''), 'unknown');

  v_session_id text := trim(p_session_id);
  v_country text := nullif(upper(trim(p_country)), '');
  v_ui_locale text := nullif(trim(p_ui_locale), '');

  v_resolved text := 'unknown';
  v_id uuid;

  v_global_bucket timestamptz := date_trunc('minute', now());
  v_session_bucket timestamptz := date_trunc('hour', now());
begin
  perform public.api_assert(
    v_session_id ~ '^anon_[A-Za-z0-9_-]{16,32}$',
    'INVALID_SESSION',
    'session_id format invalid',
    '22023'
  );
  perform public.api_assert(
    v_event in ('page_view', 'cta_click', 'poll_page_view', 'poll_vote', 'poll_results_view'),
    'INVALID_EVENT',
    'event must be page_view, cta_click, poll_page_view, poll_vote, or poll_results_view',
    '22023'
  );
  perform public.api_assert(
    v_store in ('web', 'ios_app_store', 'google_play', 'unknown'),
    'INVALID_STORE',
    'store must be web, ios_app_store, google_play, or unknown',
    '22023'
  );

  perform public.api_assert(
    v_app_key is not null and v_app_key <> '' and char_length(v_app_key) <= 40,
    'INVALID_INPUT',
    'app_key is required',
    '22023'
  );
  perform public.api_assert(
    v_page_key is not null and v_page_key <> '' and char_length(v_page_key) <= 80,
    'INVALID_INPUT',
    'page_key is required',
    '22023'
  );

  perform public.api_assert(char_length(v_utm_campaign) <= 128, 'INVALID_INPUT', 'utm_campaign too long', '22023');
  perform public.api_assert(char_length(v_utm_source)   <= 128, 'INVALID_INPUT', 'utm_source too long', '22023');
  perform public.api_assert(char_length(v_utm_medium)   <= 128, 'INVALID_INPUT', 'utm_medium too long', '22023');
  perform public.api_assert(
    v_session_id is not null and v_session_id <> '' and char_length(v_session_id) <= 40,
    'INVALID_INPUT',
    'session_id is required',
    '22023'
  );

  if v_country is not null and v_country !~ '^[A-Z]{2}$' then
    v_country := null;
  end if;

  if v_ui_locale is not null and (length(v_ui_locale) < 2 or length(v_ui_locale) > 35 or v_ui_locale ~ '\s') then
    v_ui_locale := null;
  end if;

  perform public.api_assert(
    public._outreach_rate_limit_bucketed('global', v_global_bucket, 500),
    'RATE_LIMIT_GLOBAL',
    'Global outreach logging rate limit exceeded',
    '42901'
  );

  perform public.api_assert(
    public._outreach_rate_limit_bucketed('session:' || v_session_id, v_session_bucket, 100),
    'RATE_LIMIT_SESSION',
    'Session outreach logging rate limit exceeded',
    '42901'
  );

  select s.source_id
    into v_resolved
    from public.outreach_sources s
   where s.source_id = v_utm_source
     and s.active = true
   limit 1;

  if v_resolved is null then
    select s.source_id
      into v_resolved
      from public.outreach_source_aliases a
      join public.outreach_sources s on s.source_id = a.source_id
     where a.alias = v_utm_source
       and a.active = true
       and s.active = true
     limit 1;
  end if;

  if v_resolved is null then
    v_resolved := 'unknown';
  end if;

  begin
    insert into public.outreach_event_logs (
      event, app_key, page_key, utm_campaign, utm_source, utm_medium,
      source_id_resolved, store, session_id, country, ui_locale, client_event_id
    ) values (
      v_event, v_app_key, v_page_key, v_utm_campaign, v_utm_source, v_utm_medium,
      v_resolved, v_store, v_session_id, v_country, v_ui_locale, p_client_event_id
    )
    returning id into v_id;
  exception when unique_violation then
    if p_client_event_id is not null then
      select id
        into v_id
        from public.outreach_event_logs
       where client_event_id = p_client_event_id
       limit 1;

      if v_id is not null then
        return jsonb_build_object('ok', true, 'id', v_id);
      end if;
    end if;

    raise;
  end;

  return jsonb_build_object('ok', true, 'id', v_id);
end;
$_$;


ALTER FUNCTION "public"."outreach_log_event"("p_event" "text", "p_app_key" "text", "p_page_key" "text", "p_utm_campaign" "text", "p_utm_source" "text", "p_utm_medium" "text", "p_session_id" "text", "p_store" "text", "p_country" "text", "p_ui_locale" "text", "p_client_event_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_poll_get_v1"("p_app_key" "text", "p_page_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_app_key text := trim(coalesce(p_app_key, ''));
  v_page_key text := trim(coalesce(p_page_key, ''));
  v_poll public.outreach_polls%rowtype;
  v_options jsonb;
begin
  perform public.api_assert(
    v_app_key <> '' and char_length(v_app_key) <= 40,
    'INVALID_INPUT',
    'app_key is required',
    '22023'
  );

  perform public.api_assert(
    v_page_key <> '' and char_length(v_page_key) <= 80,
    'INVALID_INPUT',
    'page_key is required',
    '22023'
  );

  select *
    into v_poll
    from public.outreach_polls p
   where p.app_key = v_app_key
     and p.page_key = v_page_key
     and p.active = true
   limit 1;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'POLL_NOT_FOUND');
  end if;

  select coalesce(
           jsonb_agg(
             jsonb_build_object(
               'id', o.id,
               'option_key', o.option_key,
               'label', o.label,
               'position', o.position
             )
             order by o.position asc, o.id asc
           ),
           '[]'::jsonb
         )
    into v_options
    from public.outreach_poll_options o
   where o.poll_id = v_poll.id
     and o.active = true;

  return jsonb_build_object(
    'ok', true,
    'poll', jsonb_build_object(
      'id', v_poll.id,
      'app_key', v_poll.app_key,
      'page_key', v_poll.page_key,
      'title', v_poll.title,
      'question', v_poll.question,
      'description', v_poll.description
    ),
    'options', v_options
  );
end;
$$;


ALTER FUNCTION "public"."outreach_poll_get_v1"("p_app_key" "text", "p_page_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_poll_vote_submit_v1"("p_short_code" "text", "p_option_key" "text", "p_session_id" "text", "p_store" "text" DEFAULT 'unknown'::"text", "p_client_vote_id" "uuid" DEFAULT NULL::"uuid", "p_country" "text" DEFAULT NULL::"text", "p_ui_locale" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
declare
  v_short_code text := lower(trim(coalesce(p_short_code, '')));
  v_option_key text := lower(trim(coalesce(p_option_key, '')));
  v_session_id text := trim(coalesce(p_session_id, ''));
  v_store text := coalesce(nullif(lower(trim(p_store)), ''), 'unknown');
  v_country text := nullif(upper(trim(p_country)), '');
  v_ui_locale text := nullif(trim(p_ui_locale), '');

  v_short_link public.outreach_short_links%rowtype;
  v_poll public.outreach_polls%rowtype;
  v_option public.outreach_poll_options%rowtype;
  v_vote public.outreach_poll_votes%rowtype;
  v_existing_vote public.outreach_poll_votes%rowtype;
  v_counts jsonb;
  v_total_votes bigint;
begin
  perform public.api_assert(
    v_short_code ~ '^[a-z0-9_-]{4,24}$',
    'INVALID_SHORT_CODE',
    'short_code must match ^[a-z0-9_-]{4,24}$',
    '22023'
  );

  perform public.api_assert(
    v_option_key ~ '^[a-z0-9_]{1,40}$',
    'INVALID_OPTION',
    'option_key format invalid',
    '22023'
  );

  perform public.api_assert(
    v_session_id ~ '^anon_[A-Za-z0-9_-]{16,32}$',
    'INVALID_SESSION',
    'session_id format invalid',
    '22023'
  );

  perform public.api_assert(
    v_store in ('web', 'ios_app_store', 'google_play', 'unknown'),
    'INVALID_STORE',
    'store must be web, ios_app_store, google_play, or unknown',
    '22023'
  );

  if v_country is not null and v_country !~ '^[A-Z]{2}$' then
    v_country := null;
  end if;

  if v_ui_locale is not null and (length(v_ui_locale) < 2 or length(v_ui_locale) > 35 or v_ui_locale ~ '\s') then
    v_ui_locale := null;
  end if;

  if p_client_vote_id is not null then
    select *
      into v_existing_vote
      from public.outreach_poll_votes v
     where v.client_vote_id = p_client_vote_id
     limit 1;

    if found then
      select o.option_key
        into v_option_key
        from public.outreach_poll_options o
       where o.id = v_existing_vote.option_id
       limit 1;

      select
        coalesce(sum(x.vote_count), 0)::bigint,
        coalesce(
          jsonb_agg(
            jsonb_build_object('option_key', x.option_key, 'vote_count', x.vote_count)
            order by x.position asc, x.option_id asc
          ),
          '[]'::jsonb
        )
      into v_total_votes, v_counts
      from (
        select
          o.id as option_id,
          o.option_key,
          o.position,
          count(v.id)::bigint as vote_count
        from public.outreach_poll_options o
        left join public.outreach_poll_votes v
          on v.option_id = o.id
         and v.poll_id = v_existing_vote.poll_id
        where o.poll_id = v_existing_vote.poll_id
          and o.active = true
        group by o.id, o.option_key, o.position
      ) x;

      return jsonb_build_object(
        'ok', true,
        'poll_id', v_existing_vote.poll_id,
        'selected_option_key', v_option_key,
        'results', jsonb_build_object(
          'total_votes', v_total_votes,
          'option_counts', v_counts
        )
      );
    end if;
  end if;

  select s.*
    into v_short_link
    from public.outreach_short_links s
    join public.outreach_short_links_effective l on l.id = s.id
   where l.short_code = v_short_code::public.citext
     and l.effective_active = true
   limit 1;

  if not found then
    select l.*
      into v_short_link
      from public.outreach_short_links l
     where l.short_code = v_short_code::public.citext
     limit 1;

    if not found then
      perform public.api_error('SHORT_CODE_NOT_FOUND', 'short_code was not found', 'P0002');
    else
      perform public.api_error('SHORT_CODE_INACTIVE', 'short_code is inactive or expired', 'P0001');
    end if;
  end if;

  select p.*
    into v_poll
    from public.outreach_polls p
   where p.app_key = v_short_link.app_key
     and p.page_key = v_short_link.page_key
     and p.active = true
   limit 1;

  if not found then
    perform public.api_error('POLL_NOT_FOUND', 'No active poll found for short_code destination', 'P0002');
  end if;

  select o.*
    into v_option
    from public.outreach_poll_options o
   where o.poll_id = v_poll.id
     and o.option_key = v_option_key
     and o.active = true
   limit 1;

  if not found then
    perform public.api_error('INVALID_OPTION', 'option_key is not valid for poll', '22023');
  end if;

  begin
    insert into public.outreach_poll_votes (
      poll_id,
      option_id,
      session_id,
      client_vote_id,
      short_link_id,
      page_key,
      source_id_resolved,
      utm_campaign,
      utm_source,
      utm_medium,
      store,
      country,
      ui_locale
    ) values (
      v_poll.id,
      v_option.id,
      v_session_id,
      p_client_vote_id,
      v_short_link.id,
      v_short_link.page_key,
      v_short_link.source_id_resolved,
      v_short_link.utm_campaign,
      v_short_link.utm_source,
      v_short_link.utm_medium,
      v_store,
      v_country,
      v_ui_locale
    )
    on conflict (poll_id, session_id) do update
      set option_id = excluded.option_id,
          client_vote_id = coalesce(public.outreach_poll_votes.client_vote_id, excluded.client_vote_id),
          short_link_id = excluded.short_link_id,
          page_key = excluded.page_key,
          source_id_resolved = excluded.source_id_resolved,
          utm_campaign = excluded.utm_campaign,
          utm_source = excluded.utm_source,
          utm_medium = excluded.utm_medium,
          store = excluded.store,
          country = excluded.country,
          ui_locale = excluded.ui_locale,
          updated_at = now()
    returning * into v_vote;
  exception when unique_violation then
    if p_client_vote_id is not null then
      select *
        into v_vote
        from public.outreach_poll_votes v
       where v.client_vote_id = p_client_vote_id
       limit 1;

      if found then
        select o.option_key
          into v_option_key
          from public.outreach_poll_options o
         where o.id = v_vote.option_id
         limit 1;

        select
          coalesce(sum(x.vote_count), 0)::bigint,
          coalesce(
            jsonb_agg(
              jsonb_build_object('option_key', x.option_key, 'vote_count', x.vote_count)
              order by x.position asc, x.option_id asc
            ),
            '[]'::jsonb
          )
        into v_total_votes, v_counts
        from (
          select
            o.id as option_id,
            o.option_key,
            o.position,
            count(v2.id)::bigint as vote_count
          from public.outreach_poll_options o
          left join public.outreach_poll_votes v2
            on v2.option_id = o.id
           and v2.poll_id = v_vote.poll_id
          where o.poll_id = v_vote.poll_id
            and o.active = true
          group by o.id, o.option_key, o.position
        ) x;

        return jsonb_build_object(
          'ok', true,
          'poll_id', v_vote.poll_id,
          'selected_option_key', v_option_key,
          'results', jsonb_build_object(
            'total_votes', v_total_votes,
            'option_counts', v_counts
          )
        );
      end if;
    end if;

    raise;
  end;

  perform public.outreach_log_event(
    'poll_vote',
    v_short_link.app_key,
    v_short_link.page_key,
    v_short_link.utm_campaign,
    v_short_link.utm_source,
    v_short_link.utm_medium,
    v_session_id,
    v_store,
    v_country,
    v_ui_locale,
    null
  );

  select
    coalesce(sum(x.vote_count), 0)::bigint,
    coalesce(
      jsonb_agg(
        jsonb_build_object('option_key', x.option_key, 'vote_count', x.vote_count)
        order by x.position asc, x.option_id asc
      ),
      '[]'::jsonb
    )
  into v_total_votes, v_counts
  from (
    select
      o.id as option_id,
      o.option_key,
      o.position,
      count(v.id)::bigint as vote_count
    from public.outreach_poll_options o
    left join public.outreach_poll_votes v
      on v.option_id = o.id
     and v.poll_id = v_poll.id
    where o.poll_id = v_poll.id
      and o.active = true
    group by o.id, o.option_key, o.position
  ) x;

  return jsonb_build_object(
    'ok', true,
    'poll_id', v_poll.id,
    'selected_option_key', v_option.option_key,
    'results', jsonb_build_object(
      'total_votes', v_total_votes,
      'option_counts', v_counts
    )
  );
end;
$_$;


ALTER FUNCTION "public"."outreach_poll_vote_submit_v1"("p_short_code" "text", "p_option_key" "text", "p_session_id" "text", "p_store" "text", "p_client_vote_id" "uuid", "p_country" "text", "p_ui_locale" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_rate_limits_cleanup"("p_keep" interval DEFAULT '14 days'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_deleted integer;
BEGIN
  DELETE FROM public.outreach_rate_limits
   WHERE bucket_start < (now() - p_keep);

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


ALTER FUNCTION "public"."outreach_rate_limits_cleanup"("p_keep" interval) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_short_links_disable"("p_short_code" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
declare
  v_short_code text := lower(trim(coalesce(p_short_code, '')));
  v_row public.outreach_short_links%rowtype;
begin
  perform public.api_assert(
    v_short_code ~ '^[a-z0-9_-]{4,24}$',
    'INVALID_SHORT_CODE',
    'short_code must match ^[a-z0-9_-]{4,24}$',
    '22023'
  );

  update public.outreach_short_links
     set active = false,
         updated_at = now()
   where short_code = v_short_code::public.citext
     and active = true
  returning * into v_row;

  if found then
    return jsonb_build_object(
      'ok', true,
      'disabled', true,
      'id', v_row.id,
      'short_code', v_row.short_code::text
    );
  end if;

  select *
    into v_row
    from public.outreach_short_links
   where short_code = v_short_code::public.citext
   limit 1;

  if not found then
    perform public.api_error(
      'SHORT_CODE_NOT_FOUND',
      'short_code was not found',
      'P0002'
    );

    return null;
  end if;

  return jsonb_build_object(
    'ok', true,
    'disabled', false,
    'id', v_row.id,
    'short_code', v_row.short_code::text
  );
end;
$_$;


ALTER FUNCTION "public"."outreach_short_links_disable"("p_short_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."outreach_short_links_get_or_create"("p_short_code" "text" DEFAULT NULL::"text", "p_target_path" "text" DEFAULT NULL::"text", "p_target_query" "jsonb" DEFAULT '{}'::"jsonb", "p_utm_campaign" "text" DEFAULT NULL::"text", "p_utm_source" "text" DEFAULT NULL::"text", "p_utm_medium" "text" DEFAULT NULL::"text", "p_app_key" "text" DEFAULT 'kinly-web'::"text", "p_page_key" "text" DEFAULT NULL::"text", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
declare
  v_short_code text := nullif(lower(trim(coalesce(p_short_code, ''))), '');
  v_target_path text := trim(coalesce(p_target_path, ''));
  v_target_query jsonb := coalesce(p_target_query, '{}'::jsonb);
  v_utm_campaign text := trim(coalesce(p_utm_campaign, ''));
  v_utm_source text := lower(trim(coalesce(p_utm_source, '')));
  v_utm_medium text := lower(trim(coalesce(p_utm_medium, '')));
  v_app_key text := trim(coalesce(p_app_key, ''));
  v_page_key text := trim(coalesce(p_page_key, ''));
  v_source_id_resolved text;
  v_fingerprint text;
  v_row public.outreach_short_links%rowtype;
  v_attempt integer := 0;
  c_max_attempts constant integer := 8;
begin
  perform public.api_assert(
    v_target_path like '/kinly/%',
    'INVALID_TARGET_PATH',
    'target_path must start with /kinly/',
    '22023'
  );

  perform public.api_assert(
    jsonb_typeof(v_target_query) = 'object',
    'INVALID_TARGET_QUERY',
    'target_query must be a JSON object',
    '22023'
  );

  perform public.api_assert(
    v_utm_campaign <> '' and v_utm_source <> '' and v_utm_medium <> '',
    'INVALID_UTM',
    'utm_campaign, utm_source, and utm_medium are required',
    '22023'
  );

  perform public.api_assert(
    v_app_key <> '' and v_page_key <> '',
    'INVALID_INPUT',
    'app_key and page_key are required',
    '22023'
  );

  if v_short_code is not null then
    perform public.api_assert(
      v_short_code ~ '^[a-z0-9_-]{4,24}$',
      'INVALID_SHORT_CODE',
      'short_code must match ^[a-z0-9_-]{4,24}$',
      '22023'
    );
  end if;

  v_source_id_resolved := public._outreach_short_links_resolve_source(v_utm_source);
  v_fingerprint := public._outreach_short_links_fingerprint(
    v_target_path,
    v_target_query,
    v_utm_campaign,
    v_utm_source,
    v_utm_medium,
    v_app_key,
    v_page_key
  );

  select *
    into v_row
    from public.outreach_short_links
   where destination_fingerprint = v_fingerprint
   limit 1;

  if found then
    return jsonb_build_object(
      'ok', true,
      'created', false,
      'id', v_row.id,
      'short_code', v_row.short_code::text,
      'short_url', 'https://go.makinglifeeasie.com/' || v_row.short_code::text,
      'destination_fingerprint', v_row.destination_fingerprint
    );
  end if;

  if v_short_code is not null then
    begin
      insert into public.outreach_short_links (
        short_code,
        target_path,
        target_query,
        utm_campaign,
        utm_source,
        utm_medium,
        source_id_resolved,
        app_key,
        page_key,
        destination_fingerprint,
        expires_at
      ) values (
        v_short_code::public.citext,
        v_target_path,
        v_target_query,
        v_utm_campaign,
        v_utm_source,
        v_utm_medium,
        v_source_id_resolved,
        v_app_key,
        v_page_key,
        v_fingerprint,
        p_expires_at
      )
      returning * into v_row;

      return jsonb_build_object(
        'ok', true,
        'created', true,
        'id', v_row.id,
        'short_code', v_row.short_code::text,
        'short_url', 'https://go.makinglifeeasie.com/' || v_row.short_code::text,
        'destination_fingerprint', v_row.destination_fingerprint
      );
    exception
      when unique_violation then
        select *
          into v_row
          from public.outreach_short_links
         where destination_fingerprint = v_fingerprint
         limit 1;

        if found then
          return jsonb_build_object(
            'ok', true,
            'created', false,
            'id', v_row.id,
            'short_code', v_row.short_code::text,
            'short_url', 'https://go.makinglifeeasie.com/' || v_row.short_code::text,
            'destination_fingerprint', v_row.destination_fingerprint
          );
        end if;

        perform public.api_error(
          'SHORT_CODE_ALREADY_EXISTS',
          'Requested short_code is already bound to a different destination',
          '23505'
        );
    end;
  end if;

  while v_attempt < c_max_attempts loop
    v_attempt := v_attempt + 1;
    v_short_code := public._outreach_short_links_generate_code(6)::text;

    begin
      insert into public.outreach_short_links (
        short_code,
        target_path,
        target_query,
        utm_campaign,
        utm_source,
        utm_medium,
        source_id_resolved,
        app_key,
        page_key,
        destination_fingerprint,
        expires_at
      ) values (
        v_short_code::public.citext,
        v_target_path,
        v_target_query,
        v_utm_campaign,
        v_utm_source,
        v_utm_medium,
        v_source_id_resolved,
        v_app_key,
        v_page_key,
        v_fingerprint,
        p_expires_at
      )
      returning * into v_row;

      return jsonb_build_object(
        'ok', true,
        'created', true,
        'id', v_row.id,
        'short_code', v_row.short_code::text,
        'short_url', 'https://go.makinglifeeasie.com/' || v_row.short_code::text,
        'destination_fingerprint', v_row.destination_fingerprint
      );
    exception
      when unique_violation then
        select *
          into v_row
          from public.outreach_short_links
         where destination_fingerprint = v_fingerprint
         limit 1;

        if found then
          return jsonb_build_object(
            'ok', true,
            'created', false,
            'id', v_row.id,
            'short_code', v_row.short_code::text,
            'short_url', 'https://go.makinglifeeasie.com/' || v_row.short_code::text,
            'destination_fingerprint', v_row.destination_fingerprint
          );
        end if;
    end;
  end loop;

  perform public.api_error(
    'SHORT_CODE_COLLISION_EXHAUSTED',
    'Could not allocate a unique short code after bounded retries',
    '23505'
  );

  return null;
end;
$_$;


ALTER FUNCTION "public"."outreach_short_links_get_or_create"("p_short_code" "text", "p_target_path" "text", "p_target_query" "jsonb", "p_utm_campaign" "text", "p_utm_source" "text", "p_utm_medium" "text", "p_app_key" "text", "p_page_key" "text", "p_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."paywall_log_event"("p_home_id" "uuid", "p_event_type" "text", "p_source" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
BEGIN
  PERFORM public._assert_authenticated();

  IF p_event_type NOT IN ('impression', 'cta_click', 'dismiss', 'restore_attempt') THEN
    PERFORM public.api_error(
      'INVALID_EVENT',
      'Unsupported paywall event type.',
      '22023'
    );
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.memberships m
    WHERE m.user_id = v_user
      AND m.home_id = p_home_id
      AND m.is_current = TRUE
  ) THEN
    PERFORM public.api_error(
      'HOME_NOT_MEMBER',
      'You are not a current member of this home.',
      '42501'
    );
  END IF;

  INSERT INTO public.paywall_events (user_id, home_id, event_type, source)
  VALUES (v_user, p_home_id, p_event_type, p_source);
END;
$$;


ALTER FUNCTION "public"."paywall_log_event"("p_home_id" "uuid", "p_event_type" "text", "p_source" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."paywall_log_event"("p_home_id" "uuid", "p_event_type" "text", "p_source" "text") IS 'Auth-only helper to log paywall funnel events for a home.';



CREATE OR REPLACE FUNCTION "public"."paywall_record_subscription"("p_idempotency_key" "text", "p_user_id" "uuid", "p_home_id" "uuid", "p_store" "public"."subscription_store", "p_rc_app_user_id" "text", "p_entitlement_id" "text", "p_product_id" "text", "p_status" "public"."subscription_status", "p_current_period_end_at" timestamp with time zone, "p_original_purchase_at" timestamp with time zone, "p_last_purchase_at" timestamp with time zone, "p_latest_transaction_id" "text", "p_entitlement_ids" "text"[] DEFAULT NULL::"text"[], "p_event_timestamp" timestamp with time zone DEFAULT "now"(), "p_environment" "text" DEFAULT 'unknown'::"text", "p_rc_event_id" "text" DEFAULT NULL::"text", "p_original_transaction_id" "text" DEFAULT NULL::"text", "p_raw_event" "jsonb" DEFAULT NULL::"jsonb", "p_warnings" "text"[] DEFAULT NULL::"text"[]) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_status public.revenuecat_processing_status;
  v_home_id uuid;
BEGIN
  -- Prevent concurrent double-runs for the same idempotency key
  PERFORM pg_advisory_xact_lock(hashtext(p_environment || ':' || p_idempotency_key));

  -- Basic validation (defense in depth; webhook already validated)
  IF p_idempotency_key IS NULL OR length(trim(p_idempotency_key)) = 0 THEN
    RAISE EXCEPTION 'Missing p_idempotency_key';
  END IF;

  IF p_user_id IS NULL THEN
    RAISE EXCEPTION 'Missing p_user_id';
  END IF;

  -- home_id may be null (floating sub); allow nullable to align with edge behavior

  -- Acquire processing record (or reuse)
  INSERT INTO public.revenuecat_event_processing AS ep (environment, idempotency_key, status, attempts, updated_at)
  VALUES (p_environment, p_idempotency_key, 'processing'::public.revenuecat_processing_status, 1, now())
  ON CONFLICT (environment, idempotency_key)
  DO UPDATE SET
    attempts   = ep.attempts + 1,
    status     = CASE
                  WHEN ep.status = 'succeeded' THEN 'succeeded'::public.revenuecat_processing_status
                  ELSE 'processing'::public.revenuecat_processing_status
                 END,
    updated_at = now()
  RETURNING status INTO v_status;

  -- If already succeeded, return immediately (idempotent)
  IF v_status = 'succeeded'::public.revenuecat_processing_status THEN
    RETURN true; -- deduped
  END IF;

  ------------------------------------------------------------------
  -- Upsert subscription snapshot
  ------------------------------------------------------------------
  INSERT INTO public.user_subscriptions AS us (
    user_id,
    home_id,
    store,
    rc_app_user_id,
    rc_entitlement_id,
    product_id,
    status,
    current_period_end_at,
    original_purchase_at,
    last_purchase_at,
    latest_transaction_id,
    last_synced_at,
    created_at,
    updated_at
  ) VALUES (
    p_user_id,
    p_home_id,
    p_store,
    p_rc_app_user_id,
    p_entitlement_id,
    p_product_id,
    p_status,
    p_current_period_end_at,
    p_original_purchase_at,
    p_last_purchase_at,
    p_latest_transaction_id,
    now(),
    now(),
    now()
  )
  ON CONFLICT (user_id, rc_entitlement_id) DO UPDATE
  SET
    home_id               = EXCLUDED.home_id,
    store                 = EXCLUDED.store,
    rc_app_user_id        = EXCLUDED.rc_app_user_id,
    product_id            = EXCLUDED.product_id,
    status                = EXCLUDED.status,
    current_period_end_at = EXCLUDED.current_period_end_at,
    original_purchase_at  = EXCLUDED.original_purchase_at,
    last_purchase_at      = EXCLUDED.last_purchase_at,
    latest_transaction_id = EXCLUDED.latest_transaction_id,
    last_synced_at        = now(),
    updated_at            = now()
  RETURNING home_id INTO v_home_id;

  ------------------------------------------------------------------
  -- Optional: log inside RPC too (safe upsert)
  ------------------------------------------------------------------
INSERT INTO public.revenuecat_webhook_events (
  created_at,
  event_timestamp,
  environment,
  idempotency_key,
  rc_event_id,
  original_transaction_id,
  latest_transaction_id,
  rc_app_user_id,
  home_id,
  entitlement_id,
  entitlement_ids,
  product_id,
  store,
  status,
  current_period_end_at,
  original_purchase_at,
  last_purchase_at,
  warnings,
  raw
) VALUES (
  now(),
  p_event_timestamp,
  p_environment,
  p_idempotency_key,
  p_rc_event_id,
  p_original_transaction_id,
  p_latest_transaction_id,
  p_rc_app_user_id,
  COALESCE(p_home_id, v_home_id),
  p_entitlement_id,
  p_entitlement_ids,
  p_product_id,
  p_store,
  p_status,
  p_current_period_end_at,
  p_original_purchase_at,
  p_last_purchase_at,
  p_warnings,
  p_raw_event
)
ON CONFLICT (environment, idempotency_key)
WHERE idempotency_key IS NOT NULL
DO NOTHING;

  ------------------------------------------------------------------
  -- Refresh home entitlements
  ------------------------------------------------------------------
  PERFORM public.home_entitlements_refresh(COALESCE(p_home_id, v_home_id));

  -- Mark succeeded
  UPDATE public.revenuecat_event_processing
  SET status = 'succeeded'::public.revenuecat_processing_status, last_error = NULL, updated_at = now()
  WHERE environment = p_environment AND idempotency_key = p_idempotency_key;

  RETURN false; -- processed now

EXCEPTION
  WHEN OTHERS THEN
    -- Mark failed (so retries can reattempt)
  UPDATE public.revenuecat_event_processing
  SET status = 'failed'::public.revenuecat_processing_status, last_error = SQLERRM, updated_at = now()
  WHERE environment = p_environment AND idempotency_key = p_idempotency_key;

    RAISE;
END;
$$;


ALTER FUNCTION "public"."paywall_record_subscription"("p_idempotency_key" "text", "p_user_id" "uuid", "p_home_id" "uuid", "p_store" "public"."subscription_store", "p_rc_app_user_id" "text", "p_entitlement_id" "text", "p_product_id" "text", "p_status" "public"."subscription_status", "p_current_period_end_at" timestamp with time zone, "p_original_purchase_at" timestamp with time zone, "p_last_purchase_at" timestamp with time zone, "p_latest_transaction_id" "text", "p_entitlement_ids" "text"[], "p_event_timestamp" timestamp with time zone, "p_environment" "text", "p_rc_event_id" "text", "p_original_transaction_id" "text", "p_raw_event" "jsonb", "p_warnings" "text"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."paywall_record_subscription"("p_idempotency_key" "text", "p_user_id" "uuid", "p_home_id" "uuid", "p_store" "public"."subscription_store", "p_rc_app_user_id" "text", "p_entitlement_id" "text", "p_product_id" "text", "p_status" "public"."subscription_status", "p_current_period_end_at" timestamp with time zone, "p_original_purchase_at" timestamp with time zone, "p_last_purchase_at" timestamp with time zone, "p_latest_transaction_id" "text", "p_entitlement_ids" "text"[], "p_event_timestamp" timestamp with time zone, "p_environment" "text", "p_rc_event_id" "text", "p_original_transaction_id" "text", "p_raw_event" "jsonb", "p_warnings" "text"[]) IS 'Idempotent service-role helper invoked by RevenueCat webhook. Safe for retries via revenuecat_event_processing. Returns deduped boolean.';



CREATE OR REPLACE FUNCTION "public"."paywall_status_get"("p_home_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_plan        text;
  v_expires_at  timestamptz;
  v_now         timestamptz := now();
  v_user_quota  jsonb;
BEGIN
  PERFORM public._assert_home_member(p_home_id);

  SELECT COALESCE(he.plan, 'free'), he.expires_at
    INTO v_plan, v_expires_at
    FROM public.home_entitlements he
   WHERE he.home_id = p_home_id;

  v_plan := COALESCE(v_plan, 'free');
  v_user_quota := public._command_ai_quota_status(p_home_id, auth.uid(), v_now);

  RETURN jsonb_strip_nulls(
    jsonb_build_object(
      'plan', v_plan,
      'expires_at', v_expires_at,
      'is_premium', (v_plan <> 'free' AND (v_expires_at IS NULL OR v_expires_at > v_now)),
      'usage', COALESCE((
        SELECT jsonb_build_object(
          'active_chores',   c.active_chores,
          'chore_photos',    c.chore_photos,
          'active_members',  c.active_members,
          'active_expenses', c.active_expenses,
          'expense_photos',  c.expense_photos,
          'updated_at',      c.updated_at
        )
        FROM public.home_usage_counters c
        WHERE c.home_id = p_home_id
      ), jsonb_build_object(
        'active_chores', 0,
        'chore_photos', 0,
        'active_members', 0,
        'active_expenses', 0,
        'expense_photos', 0,
        'updated_at', v_now
      )),
      'limits', COALESCE((
        SELECT jsonb_agg(
          jsonb_build_object(
            'metric',    x.metric::text,
            'max_value', x.max_value
          )
          ORDER BY x.metric::text
        )
        FROM (
          SELECT l.metric, l.max_value
          FROM public.home_plan_limits l
          WHERE l.plan = v_plan
        ) x
      ), '[]'::jsonb),
      'userQuotas', jsonb_build_object(
        'ai_command_requests', v_user_quota
      )
    )
  );
END;
$$;


ALTER FUNCTION "public"."paywall_status_get"("p_home_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."personal_gratitude_inbox_list_v1"("p_limit" integer DEFAULT 30, "p_before_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "created_at" timestamp with time zone, "home_id" "uuid", "mood" "public"."mood_scale", "message" "text", "source_kind" "text", "source_post_id" "uuid", "source_entry_id" "uuid", "author_user_id" "uuid", "author_username" "public"."citext", "author_avatar_id" "uuid", "author_avatar_path" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
BEGIN
  PERFORM public._assert_authenticated();

  p_limit := GREATEST(1, LEAST(COALESCE(p_limit, 30), 100));

  -- Enforce: both cursor parts must be provided together, or neither.
  PERFORM public.api_assert(
    (p_before_at IS NULL AND p_before_id IS NULL)
    OR (p_before_at IS NOT NULL AND p_before_id IS NOT NULL),
    'INVALID_PAGINATION_CURSOR',
    'Pagination cursor requires both before_at and before_id, or neither.',
    '22023',
    jsonb_build_object('before_at', p_before_at, 'before_id', p_before_id)
  );

  RETURN QUERY
  SELECT
    i.id,
    i.created_at,
    i.home_id,
    i.mood,
    i.message,
    i.source_kind,
    i.source_post_id,
    i.source_entry_id,

    p.id           AS author_user_id,
    p.username     AS author_username,
    p.avatar_id    AS author_avatar_id,
    a.storage_path AS author_avatar_path
  FROM public.gratitude_wall_personal_items i
  JOIN public.profiles p
    ON p.id = i.author_user_id
  LEFT JOIN public.avatars a
    ON a.id = p.avatar_id
  WHERE i.recipient_user_id = v_user_id
    AND i.mood NOT IN ('rainy', 'thunderstorm')
    AND (
      p_before_at IS NULL
      OR i.created_at < p_before_at
      OR (i.created_at = p_before_at AND i.id < p_before_id)
    )
  ORDER BY i.created_at DESC, i.id DESC
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."personal_gratitude_inbox_list_v1"("p_limit" integer, "p_before_at" timestamp with time zone, "p_before_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."personal_gratitude_inbox_list_v1"("p_limit" integer, "p_before_at" timestamp with time zone, "p_before_id" "uuid") IS 'Recipient personal gratitude inbox list (paged). Resolves author username + avatar storage_path at read time. Cursor requires both before_at and before_id. Excludes rainy/thunderstorm moods.';



CREATE OR REPLACE FUNCTION "public"."personal_gratitude_showcase_stats_v1"("p_exclude_self" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_total   bigint;
  v_authors bigint;
  v_homes   bigint;
BEGIN
  PERFORM public._assert_authenticated();

  SELECT
    COUNT(*)::bigint,
    COUNT(DISTINCT i.author_user_id)::bigint,
    COUNT(DISTINCT i.home_id)::bigint
  INTO v_total, v_authors, v_homes
  FROM public.gratitude_wall_personal_items i
  WHERE i.recipient_user_id = v_user_id
    AND i.mood NOT IN ('rainy', 'thunderstorm')
    AND (NOT p_exclude_self OR i.author_user_id <> v_user_id);

  RETURN jsonb_build_object(
    'total_received',     v_total,
    'unique_individuals', v_authors,
    'unique_homes',       v_homes
  );
END;
$$;


ALTER FUNCTION "public"."personal_gratitude_showcase_stats_v1"("p_exclude_self" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."personal_gratitude_showcase_stats_v1"("p_exclude_self" boolean) IS 'Showcase stats for auth.uid() from personal gratitude inbox: total received items, unique authors, unique homes. Excludes rainy/thunderstorm moods.';



CREATE OR REPLACE FUNCTION "public"."personal_gratitude_wall_mark_read_v1"() RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
BEGIN
  PERFORM public._assert_authenticated();

  INSERT INTO public.gratitude_wall_personal_reads (user_id, last_read_at)
  VALUES (v_user_id, now())
  ON CONFLICT (user_id)
  DO UPDATE SET last_read_at = EXCLUDED.last_read_at;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."personal_gratitude_wall_mark_read_v1"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."personal_gratitude_wall_mark_read_v1"() IS 'Self-only marker to record last_read_at for personal gratitude wall.';



CREATE OR REPLACE FUNCTION "public"."personal_gratitude_wall_status_v1"() RETURNS TABLE("has_unread" boolean, "last_read_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id           uuid := auth.uid();
  v_latest_created_at timestamptz;
BEGIN
  PERFORM public._assert_authenticated();

  SELECT r.last_read_at
    INTO last_read_at
  FROM public.gratitude_wall_personal_reads r
  WHERE r.user_id = v_user_id
  LIMIT 1;

  SELECT i.created_at
    INTO v_latest_created_at
  FROM public.gratitude_wall_personal_items i
  WHERE i.recipient_user_id = v_user_id
    AND i.author_user_id <> v_user_id
    AND i.mood NOT IN ('rainy', 'thunderstorm')
  ORDER BY i.created_at DESC, i.id DESC
  LIMIT 1;

  has_unread :=
    CASE
      WHEN v_latest_created_at IS NULL THEN FALSE
      WHEN last_read_at IS NULL THEN TRUE
      ELSE v_latest_created_at > last_read_at
    END;

  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."personal_gratitude_wall_status_v1"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."personal_gratitude_wall_status_v1"() IS 'Self-only unread status for personal gratitude wall. Ignores moods rainy/thunderstorm (not counted as unread).';



CREATE OR REPLACE FUNCTION "public"."preference_reports_acknowledge"("p_report_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_subject uuid;
  v_status text;
BEGIN
  PERFORM public._assert_authenticated();

  SELECT r.subject_user_id, r.status
    INTO v_subject, v_status
  FROM public.preference_reports r
  WHERE r.id = p_report_id
  LIMIT 1;

  IF v_subject IS NULL THEN
    PERFORM public.api_error('REPORT_NOT_FOUND', 'No preference report found to acknowledge.', 'P0001');
  END IF;

  IF v_status <> 'published' THEN
    PERFORM public.api_error('REPORT_NOT_PUBLISHED', 'Only published reports can be acknowledged.', 'P0001');
  END IF;

  PERFORM public.api_assert(
    EXISTS (
      SELECT 1
      FROM public.memberships a
      JOIN public.memberships b
        ON b.home_id = a.home_id
       AND b.user_id = v_subject
       AND b.is_current = true
      WHERE a.user_id = v_user
        AND a.is_current = true
    ),
    'NOT_IN_SAME_HOME',
    'You can only acknowledge reports for someone in a home you share.',
    '22023'
  );

  INSERT INTO public.preference_report_acknowledgements (
    report_id, viewer_user_id, acknowledged_at
  ) VALUES (
    p_report_id, v_user, now()
  )
  ON CONFLICT (report_id, viewer_user_id) DO NOTHING;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."preference_reports_acknowledge"("p_report_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preference_reports_edit_section_text"("p_template_key" "text", "p_locale" "text", "p_section_key" "text", "p_new_text" "text", "p_change_summary" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
DECLARE
  v_user uuid := auth.uid();
  v_report public.preference_reports%ROWTYPE;

  v_sections jsonb;
  v_new_sections jsonb;
  v_match_count int := 0;

  v_new_content jsonb;
  v_old_text text;
BEGIN
  PERFORM public._assert_authenticated();

  PERFORM public.api_assert(
    p_template_key ~ '^[a-z0-9_]{1,64}$',
    'INVALID_TEMPLATE_KEY',
    'Template key format is invalid.',
    '22023'
  );

  PERFORM public.api_assert(
    p_locale ~ '^[a-z]{2}(-[A-Z]{2})?$',
    'INVALID_LOCALE',
    'Locale must be ISO 639-1 (e.g. en) or ISO 639-1 + "-" + ISO 3166-1 (e.g. en-NZ).',
    '22023'
  );

  p_locale := public.locale_base(p_locale);

  PERFORM public.api_assert(
    p_locale IN ('en', 'es', 'ar'),
    'INVALID_LOCALE',
    'Locale must be one of: en, es, ar.',
    '22023'
  );

  PERFORM public.api_assert(
    p_section_key IS NOT NULL AND length(trim(p_section_key)) > 0
      AND p_section_key ~ '^[a-z0-9_]{1,64}$',
    'INVALID_SECTION_KEY',
    'Section key is required and must match ^[a-z0-9_]{1,64}$.',
    '22023'
  );

  PERFORM public.api_assert(
    p_new_text IS NOT NULL,
    'INVALID_TEXT',
    'Section text cannot be null.',
    '22023'
  );

  SELECT *
    INTO v_report
  FROM public.preference_reports r
  WHERE r.subject_user_id = v_user
    AND r.template_key = p_template_key
    AND r.locale = p_locale
    AND r.status = 'published'
  LIMIT 1;

  IF v_report.id IS NULL THEN
    PERFORM public.api_error(
      'REPORT_NOT_FOUND',
      'No published preference report found to edit.',
      'P0001',
      jsonb_build_object('template_key', p_template_key, 'locale', p_locale)
    );
  END IF;

  -- Advisory lock per report
  PERFORM pg_advisory_xact_lock(hashtextextended(v_report.id::text, 0));

  v_sections := v_report.published_content->'sections';

  PERFORM public.api_assert(
    jsonb_typeof(v_sections) = 'array',
    'INVALID_REPORT_SHAPE',
    'published_content.sections must be an array.',
    '22023'
  );

  SELECT COUNT(*)
    INTO v_match_count
  FROM jsonb_array_elements(v_sections) AS s(value)
  WHERE (value->>'section_key') = p_section_key;

  PERFORM public.api_assert(
    v_match_count = 1,
    'SECTION_NOT_FOUND_OR_DUPLICATE',
    'Expected exactly 1 section with the given section_key.',
    '22023',
    jsonb_build_object('section_key', p_section_key, 'match_count', v_match_count)
  );

  -- no-op if unchanged
  SELECT (value->>'text')
    INTO v_old_text
  FROM jsonb_array_elements(v_sections) AS s(value)
  WHERE (value->>'section_key') = p_section_key
  LIMIT 1;

  IF v_old_text IS NOT DISTINCT FROM p_new_text THEN
    RETURN jsonb_build_object('ok', true, 'report_id', v_report.id, 'status', 'unchanged');
  END IF;

  -- rebuild sections
  SELECT COALESCE(
    jsonb_agg(
      CASE
        WHEN (value->>'section_key') = p_section_key THEN
          (value || jsonb_build_object('text', to_jsonb(p_new_text)))
        ELSE
          value
      END
      ORDER BY ord
    ),
    '[]'::jsonb
  )
  INTO v_new_sections
  FROM jsonb_array_elements(v_sections) WITH ORDINALITY AS e(value, ord);

  v_new_content := jsonb_set(v_report.published_content, '{sections}', v_new_sections, true);

  UPDATE public.preference_reports
     SET published_content = v_new_content,
         last_edited_at = now(),
         last_edited_by = v_user
   WHERE id = v_report.id;

  INSERT INTO public.preference_report_revisions (
    report_id, editor_user_id, edited_at, content, change_summary
  ) VALUES (
    v_report.id, v_user, now(), v_new_content,
    COALESCE(p_change_summary, 'Edited section ' || p_section_key)
  );

  RETURN jsonb_build_object('ok', true, 'report_id', v_report.id, 'status', 'edited');
END;
$_$;


ALTER FUNCTION "public"."preference_reports_edit_section_text"("p_template_key" "text", "p_locale" "text", "p_section_key" "text", "p_new_text" "text", "p_change_summary" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preference_reports_generate"("p_template_key" "text", "p_locale" "text", "p_force" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $_$
DECLARE
  v_user uuid := auth.uid();

  v_template public.preference_report_templates%ROWTYPE;
  v_report public.preference_reports%ROWTYPE;

  v_all_pref_ids text[];
  v_answered_pref_ids text[];

  v_responses jsonb;
  v_resolved jsonb;

  v_unresolved_missing jsonb;
  v_unresolved_nulls jsonb;
  v_unresolved jsonb;

  v_sections jsonb;

  v_generated jsonb;
BEGIN
  PERFORM public._assert_authenticated();

  PERFORM public.api_assert(
    p_template_key ~ '^[a-z0-9_]{1,64}$',
    'INVALID_TEMPLATE_KEY',
    'Template key format is invalid.',
    '22023'
  );

  PERFORM public.api_assert(
    p_locale ~ '^[a-z]{2}(-[A-Z]{2})?$',
    'INVALID_LOCALE',
    'Locale must be ISO 639-1 (e.g. en) or ISO 639-1 + "-" + ISO 3166-1 (e.g. en-NZ).',
    '22023'
  );

  -- normalize to base locale for templates/reports
  p_locale := public.locale_base(p_locale);

  PERFORM public.api_assert(
    p_locale IN ('en', 'es', 'ar'),
    'INVALID_LOCALE',
    'Locale must be one of: en, es, ar.',
    '22023'
  );

  -- Collision-safe advisory lock per (user, key, locale)
  PERFORM pg_advisory_xact_lock(
    hashtextextended(v_user::text || ':' || p_template_key || ':' || p_locale, 0)
  );

  SELECT *
    INTO v_template
  FROM public.preference_report_templates t
  WHERE t.template_key = p_template_key
    AND t.locale = p_locale
  LIMIT 1;

  IF v_template.id IS NULL THEN
    PERFORM public.api_error(
      'TEMPLATE_NOT_FOUND',
      'No preference report template found for the requested key/locale.',
      'P0001',
      jsonb_build_object('template_key', p_template_key, 'locale', p_locale)
    );
  END IF;

  SELECT *
    INTO v_report
  FROM public.preference_reports r
  WHERE r.subject_user_id = v_user
    AND r.template_key = p_template_key
    AND r.locale = p_locale
  LIMIT 1;

  IF v_report.id IS NOT NULL
     AND p_force = false
     AND v_report.status <> 'out_of_date' THEN
    RETURN jsonb_build_object('ok', true, 'report_id', v_report.id, 'status', 'unchanged');
  END IF;

  -- all_pref_ids := active taxonomy defs
  SELECT COALESCE(array_agg(t.preference_id ORDER BY t.preference_id), ARRAY[]::text[])
    INTO v_all_pref_ids
  FROM public.preference_taxonomy t
  JOIN public.preference_taxonomy_defs d USING (preference_id)
  WHERE t.is_active = true;

  PERFORM public.api_assert(
    COALESCE(array_length(v_all_pref_ids, 1), 0) > 0,
    'INVALID_TAXONOMY_STATE',
    'No active preference taxonomy defs exist; cannot generate report.',
    '22023'
  );

  -- answered_pref_ids := responses for user
  SELECT COALESCE(array_agg(pr.preference_id ORDER BY pr.preference_id), ARRAY[]::text[])
    INTO v_answered_pref_ids
  FROM public.preference_responses pr
  WHERE pr.user_id = v_user;

  -- responses/resolved for answered only
  WITH resolved_rows AS (
    SELECT
      pr.preference_id,
      pr.option_index,
      (v_template.body->'preferences'->pr.preference_id->(pr.option_index::int)) AS resolved_obj
    FROM public.preference_responses pr
    WHERE pr.user_id = v_user
  )
  SELECT
    COALESCE(jsonb_object_agg(preference_id, option_index), '{}'::jsonb),
    COALESCE(jsonb_object_agg(preference_id, resolved_obj), '{}'::jsonb),
    COALESCE(
      jsonb_agg(preference_id)
        FILTER (WHERE resolved_obj IS NULL OR resolved_obj = 'null'::jsonb),
      '[]'::jsonb
    )
  INTO v_responses, v_resolved, v_unresolved_nulls
  FROM resolved_rows;

  -- unresolved_missing := all_pref_ids EXCEPT answered_pref_ids
  SELECT COALESCE(
    jsonb_agg(x),
    '[]'::jsonb
  )
  INTO v_unresolved_missing
  FROM (
    SELECT unnest(v_all_pref_ids) AS x
    EXCEPT
    SELECT unnest(v_answered_pref_ids) AS x
  ) s;

  -- unresolved := union(missing, nulls), dedup
  SELECT COALESCE(
    jsonb_agg(DISTINCT e.value),
    '[]'::jsonb
  )
  INTO v_unresolved
  FROM jsonb_array_elements(v_unresolved_missing || v_unresolved_nulls) AS e(value);

  -- Build personalized section text from resolved preferences by domain.
  v_sections := v_template.body->'sections';

  WITH section_items AS (
    SELECT value AS section, ord
    FROM jsonb_array_elements(v_sections) WITH ORDINALITY AS e(value, ord)
  ),
  resolved_texts AS (
    SELECT
      d.domain,
      pr.preference_id,
      (v_template.body->'preferences'->pr.preference_id->(pr.option_index::int)->>'text') AS text
    FROM public.preference_responses pr
    JOIN public.preference_taxonomy t USING (preference_id)
    JOIN public.preference_taxonomy_defs d USING (preference_id)
    WHERE pr.user_id = v_user
      AND t.is_active = true
  ),
  per_domain AS (
    SELECT
      domain,
      string_agg(text, ' ' ORDER BY preference_id) AS section_text
    FROM resolved_texts
    WHERE text IS NOT NULL AND btrim(text) <> ''
    GROUP BY domain
  )
  SELECT COALESCE(
    jsonb_agg(
      CASE
        WHEN pd.section_text IS NULL OR btrim(pd.section_text) = '' THEN section
        ELSE jsonb_set(section, '{text}', to_jsonb(pd.section_text), true)
      END
      ORDER BY ord
    ),
    '[]'::jsonb
  )
  INTO v_sections
  FROM section_items si
  LEFT JOIN per_domain pd
    ON pd.domain = (si.section->>'section_key');

  v_generated := jsonb_build_object(
    'template_key', p_template_key,
    'locale', p_locale,
    'summary', v_template.body->'summary',
    'sections', v_sections,
    'responses', v_responses,
    'resolved', v_resolved,
    'unresolved_pref_ids', v_unresolved
  );

  INSERT INTO public.preference_reports (
    subject_user_id,
    template_key,
    locale,
    status,
    generated_content,
    published_content,
    generated_at,
    published_at
  ) VALUES (
    v_user,
    p_template_key,
    p_locale,
    'published',
    v_generated,
    v_generated,
    now(),
    now()
  )
  ON CONFLICT (subject_user_id, template_key, locale)
  DO UPDATE SET
    status            = 'published',
    generated_content = EXCLUDED.generated_content,
    generated_at      = EXCLUDED.generated_at,

    -- never-edited rule
    published_content =
      CASE
        WHEN public.preference_reports.last_edited_at IS NULL
          THEN EXCLUDED.published_content
        ELSE public.preference_reports.published_content
      END,

    published_at =
      CASE
        WHEN public.preference_reports.last_edited_at IS NULL
          THEN EXCLUDED.published_at
        ELSE public.preference_reports.published_at
      END
  RETURNING * INTO v_report;

  RETURN jsonb_build_object(
    'ok', true,
    'report_id', v_report.id,
    'status', 'generated',
    'unresolved_pref_ids', v_unresolved
  );
END;
$_$;


