CREATE OR REPLACE FUNCTION "public"."profiles_request_deactivation"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user           uuid := auth.uid();
  v_home_id        uuid;
  v_deactivated_at timestamptz;
BEGIN
  PERFORM public._assert_authenticated();

  -- Find the caller's current home (at most one is allowed today)
  SELECT m.home_id
    INTO v_home_id
    FROM public.memberships m
   WHERE m.user_id = v_user
     AND m.is_current
   LIMIT 1;

  -- Leave the home first; bubbles OWNER_MUST_TRANSFER_FIRST if needed
  IF v_home_id IS NOT NULL THEN
    PERFORM public.homes_leave(v_home_id);
  END IF;

  -- Mark profile as deactivated (idempotent)
  UPDATE public.profiles p
     SET deactivated_at = COALESCE(p.deactivated_at, now()),
         updated_at     = now()
   WHERE p.id = v_user
  RETURNING deactivated_at INTO v_deactivated_at;

  IF v_deactivated_at IS NULL THEN
    PERFORM public.api_error(
      'PROFILE_NOT_FOUND',
      'Profile not found for current user.',
      'P0002',
      jsonb_build_object('user_id', v_user)
    );
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'code', 'DEACTIVATION_REQUESTED',
    'data', jsonb_build_object(
      'deactivated_at', v_deactivated_at
    )
  );
END;
$$;


ALTER FUNCTION "public"."profiles_request_deactivation"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."requeue_jobs_after_submit_failure"("p_job_ids" "uuid"[], "p_error" "text", "p_backoff_seconds" integer DEFAULT 600) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_backoff int := greatest(30, least(coalesce(p_backoff_seconds, 600), 6*3600));
begin
  update public.rewrite_jobs
     set status = 'queued',
         not_before_at = now() + make_interval(secs => v_backoff),
         last_error = left(coalesce(p_error,'submit_failed'), 512),
         last_error_at = now(),
         updated_at = now()
   where job_id = any(p_job_ids)
     and status = 'processing';
end;
$$;


ALTER FUNCTION "public"."requeue_jobs_after_submit_failure"("p_job_ids" "uuid"[], "p_error" "text", "p_backoff_seconds" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rewrite_batch_collector_dispatch_v1"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_pending_count int := 0;
  v_supabase_url text;
  v_worker_secret text;
  v_request_id bigint;
begin
  select count(*)::int
    into v_pending_count
  from public.rewrite_provider_batches b
  where b.status in ('submitted', 'running');

  if coalesce(v_pending_count, 0) = 0 then
    raise notice 'rewrite_batch_collector skipped: no pending items';
    return jsonb_build_object(
      'ok', true,
      'skipped_no_pending', true,
      'pending_count', 0
    );
  end if;

  begin
    select s.decrypted_secret
      into v_supabase_url
    from vault.decrypted_secrets s
    where s.name = 'SUPABASE_URL'
    limit 1;
  exception
    when undefined_table or insufficient_privilege then
      v_supabase_url := null;
  end;

  begin
    select s.decrypted_secret
      into v_worker_secret
    from vault.decrypted_secrets s
    where s.name = 'WORKER_SHARED_SECRET'
    limit 1;
  exception
    when undefined_table or insufficient_privilege then
      v_worker_secret := null;
  end;

  if v_supabase_url is null or btrim(v_supabase_url) = '' then
    v_supabase_url := nullif(current_setting('app.settings.supabase_url', true), '');
  end if;

  if v_worker_secret is null or btrim(v_worker_secret) = '' then
    v_worker_secret := nullif(current_setting('app.settings.worker_shared_secret', true), '');
  end if;

  if v_supabase_url is null or v_worker_secret is null then
    raise exception 'rewrite_batch_collector_dispatch_v1_missing_config';
  end if;

  select net.http_post(
    url := v_supabase_url || '/functions/v1/rewrite_batch_collector',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-internal-secret', v_worker_secret,
      'x-worker-id', 'cron_batch_collector'
    ),
    body := jsonb_build_object(
      'pending_count', v_pending_count,
      'source', 'pg_cron',
      'worker', 'rewrite_batch_collector'
    )
  )
  into v_request_id;

  return jsonb_build_object(
    'ok', true,
    'skipped_no_pending', false,
    'pending_count', v_pending_count,
    'request_id', v_request_id
  );
end;
$$;


ALTER FUNCTION "public"."rewrite_batch_collector_dispatch_v1"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rewrite_batch_list_pending_v1"("p_limit" integer DEFAULT 20) RETURNS TABLE("provider_batch_id" "text", "status" "text", "input_file_id" "text", "output_file_id" "text", "error_file_id" "text", "endpoint" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  select provider_batch_id, status, input_file_id, output_file_id, error_file_id, endpoint
  from public.rewrite_provider_batches
  where status in ('submitted','running')
  order by coalesce(last_checked_at, created_at) asc
  limit p_limit;
$$;


ALTER FUNCTION "public"."rewrite_batch_list_pending_v1"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rewrite_batch_register_v1"("p_provider_batch_id" "text", "p_input_file_id" "text", "p_job_count" integer, "p_endpoint" "text" DEFAULT '/v1/responses'::"text") RETURNS "void"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  insert into public.rewrite_provider_batches(
    provider_batch_id, provider, endpoint, status, input_file_id, job_count
  ) values (
    p_provider_batch_id, 'openai', p_endpoint, 'submitted', p_input_file_id, coalesce(p_job_count,0)
  )
  on conflict (provider_batch_id)
  do update set
    input_file_id = excluded.input_file_id,
    job_count = excluded.job_count,
    status = case
      when public.rewrite_provider_batches.status in ('completed','failed','canceled') then public.rewrite_provider_batches.status
      else excluded.status
    end,
    updated_at = now();
$$;


ALTER FUNCTION "public"."rewrite_batch_register_v1"("p_provider_batch_id" "text", "p_input_file_id" "text", "p_job_count" integer, "p_endpoint" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rewrite_batch_submitter_dispatch_v1"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
declare
  v_pending_count int := 0;
  v_supabase_url text;
  v_worker_secret text;
  v_request_id bigint;
begin
  select count(*)::int
    into v_pending_count
  from public.rewrite_jobs j
  where j.status = 'queued'
    and (j.not_before_at is null or j.not_before_at <= now())
    and j.provider_batch_id is null
    and j.submitted_at is null;

  if coalesce(v_pending_count, 0) = 0 then
    raise notice 'rewrite_batch_submitter skipped: no pending items';
    return jsonb_build_object(
      'ok', true,
      'skipped_no_pending', true,
      'pending_count', 0
    );
  end if;

  begin
    select s.decrypted_secret
      into v_supabase_url
    from vault.decrypted_secrets s
    where s.name = 'SUPABASE_URL'
    limit 1;
  exception
    when undefined_table or insufficient_privilege then
      v_supabase_url := null;
  end;

  begin
    select s.decrypted_secret
      into v_worker_secret
    from vault.decrypted_secrets s
    where s.name = 'WORKER_SHARED_SECRET'
    limit 1;
  exception
    when undefined_table or insufficient_privilege then
      v_worker_secret := null;
  end;

  if v_supabase_url is null or btrim(v_supabase_url) = '' then
    v_supabase_url := nullif(current_setting('app.settings.supabase_url', true), '');
  end if;

  if v_worker_secret is null or btrim(v_worker_secret) = '' then
    v_worker_secret := nullif(current_setting('app.settings.worker_shared_secret', true), '');
  end if;

  if v_supabase_url is null or v_worker_secret is null then
    raise exception 'rewrite_batch_submitter_dispatch_v1_missing_config';
  end if;

  select net.http_post(
    url := v_supabase_url || '/functions/v1/rewrite_batch_submitter',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-internal-secret', v_worker_secret,
      'x-worker-id', 'cron_batch_submitter'
    ),
    body := jsonb_build_object(
      'pending_count', v_pending_count,
      'source', 'pg_cron',
      'worker', 'rewrite_batch_submitter'
    )
  )
  into v_request_id;

  return jsonb_build_object(
    'ok', true,
    'skipped_no_pending', false,
    'pending_count', v_pending_count,
    'request_id', v_request_id
  );
end;
$$;


ALTER FUNCTION "public"."rewrite_batch_submitter_dispatch_v1"() OWNER TO "postgres";


