CREATE OR REPLACE FUNCTION "public"."shopping_list_add_item_v3"("p_home_id" "uuid", "p_name" "text", "p_quantity" "text" DEFAULT NULL::"text", "p_details" "text" DEFAULT NULL::"text", "p_reference_photo_path" "text" DEFAULT NULL::"text", "p_scope_type" "text" DEFAULT 'house'::"text", "p_unit_id" "uuid" DEFAULT NULL::"uuid", "p_confirm_recent_purchase" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_resolved_scope record;
  v_purchase_memory jsonb := NULL;
  v_item public.shopping_list_items;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_member(p_home_id);

  SELECT *
  INTO v_resolved_scope
  FROM public._shopping_list__assert_scope_target(
    p_home_id,
    p_scope_type,
    p_unit_id
  );

  BEGIN
    v_purchase_memory := public._shopping_list__purchase_memory_payload(
      p_home_id,
      v_resolved_scope.scope_type,
      v_resolved_scope.unit_id,
      p_name
    );
  EXCEPTION
    WHEN OTHERS THEN
      v_purchase_memory := NULL;
  END;

  IF v_purchase_memory IS NOT NULL
     AND COALESCE(p_confirm_recent_purchase, FALSE) = FALSE THEN
    RETURN public._shopping_list__build_add_item_payload_v3(
      NULL::public.shopping_list_items,
      v_purchase_memory,
      TRUE
    );
  END IF;

  v_item := public._shopping_list__add_item_core(
    p_home_id,
    p_name,
    p_quantity,
    p_details,
    p_reference_photo_path,
    p_scope_type,
    p_unit_id
  );

  RETURN public._shopping_list__build_add_item_payload_v3(
    v_item,
    v_purchase_memory,
    FALSE
  );
END;
$$;


ALTER FUNCTION "public"."shopping_list_add_item_v3"("p_home_id" "uuid", "p_name" "text", "p_quantity" "text", "p_details" "text", "p_reference_photo_path" "text", "p_scope_type" "text", "p_unit_id" "uuid", "p_confirm_recent_purchase" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."shopping_list_archive_item"("p_item_id" "uuid") RETURNS "public"."shopping_list_items"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_existing public.shopping_list_items;
  v_updated public.shopping_list_items;
BEGIN
  PERFORM public._assert_authenticated();

  SELECT i.*
  INTO v_existing
  FROM public.shopping_list_items i
  JOIN public.memberships m
    ON m.home_id = i.home_id
   AND m.user_id = v_user
   AND m.valid_to IS NULL
  WHERE i.id = p_item_id
    AND i.archived_at IS NULL
  FOR UPDATE;

  IF v_existing.id IS NULL THEN
    PERFORM public.api_error(
      'item_not_found',
      'Shopping list item not found.',
      'P0002',
      jsonb_build_object('item_id', p_item_id)
    );
  END IF;

  UPDATE public.shopping_list_items
  SET
    archived_at = now(),
    archived_by_user_id = v_user
  WHERE id = p_item_id
  RETURNING * INTO v_updated;

  IF v_updated.is_completed = TRUE THEN
    PERFORM public._shopping_list__write_purchase_memory(ARRAY[v_updated.id]);
  END IF;

  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."shopping_list_archive_item"("p_item_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."shopping_list_archive_items_for_user"("p_home_id" "uuid", "p_item_ids" "uuid"[]) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_updated integer := 0;
  v_updated_item_ids uuid[];
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_member(p_home_id);

  IF p_item_ids IS NULL OR cardinality(p_item_ids) = 0 THEN
    RETURN 0;
  END IF;

  WITH ids AS (
    SELECT DISTINCT unnest(p_item_ids) AS id
  ),
  updated AS (
    UPDATE public.shopping_list_items i
    SET
      archived_at = now(),
      archived_by_user_id = v_user
    FROM ids
    WHERE i.id = ids.id
      AND i.home_id = p_home_id
      AND i.archived_at IS NULL
      AND i.completed_by_user_id = v_user
    RETURNING i.id
  )
  SELECT count(*)::int, array_agg(id)
  INTO v_updated, v_updated_item_ids
  FROM updated;

  IF v_updated > 0 THEN
    PERFORM public._shopping_list__write_purchase_memory(v_updated_item_ids);
  END IF;

  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."shopping_list_archive_items_for_user"("p_home_id" "uuid", "p_item_ids" "uuid"[]) OWNER TO "postgres";


