ALTER FUNCTION "public"."update_member_directory_note_v2"("p_note_id" "uuid", "p_label" "text", "p_custom_title" "text", "p_contact_name" "text", "p_phone_number" "text", "p_details" "text", "p_reference_url" "text", "p_photo_path" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."update_member_directory_note_v2"("p_note_id" "uuid", "p_label" "text", "p_custom_title" "text", "p_contact_name" "text", "p_phone_number" "text", "p_details" "text", "p_reference_url" "text", "p_photo_path" "text") IS 'Updates an existing active member-directory note owned by the authenticated user. v2 adds optional reference_url support while preserving v1 validation and immutable note_type semantics.';



CREATE OR REPLACE FUNCTION "public"."upsert_home_directory_note"("p_home_id" "uuid", "p_note_id" "uuid" DEFAULT NULL::"uuid", "p_title" "text" DEFAULT NULL::"text", "p_details" "text" DEFAULT NULL::"text", "p_note_type" "text" DEFAULT 'general'::"text", "p_reference_url" "text" DEFAULT NULL::"text", "p_photo_path" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_note public.home_directory_notes%ROWTYPE;
  v_existing public.home_directory_notes%ROWTYPE;
  v_title text := nullif(btrim(p_title), '');
  v_details text := nullif(btrim(p_details), '');
  v_note_type text := lower(COALESCE(nullif(btrim(p_note_type), ''), 'general'));
  v_reference_url text := nullif(btrim(p_reference_url), '');
  v_photo_path text := nullif(btrim(p_photo_path), '');
  v_photo_delta integer := 0;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_active(p_home_id);
  PERFORM public._house_directory_assert_owner(p_home_id);

  PERFORM public.api_assert(
    v_title IS NOT NULL,
    'HOUSE_DIRECTORY_NOTE_REQUIRED_FIELDS',
    'title is required.',
    '22023'
  );

  PERFORM public.api_assert(
    char_length(v_title) BETWEEN 1 AND 120,
    'HOUSE_DIRECTORY_NOTE_REQUIRED_FIELDS',
    'title must be between 1 and 120 characters.',
    '22023'
  );

  PERFORM public.api_assert(
    v_details IS NULL OR char_length(v_details) <= 4000,
    'HOUSE_DIRECTORY_NOTE_REQUIRED_FIELDS',
    'details must be 4000 characters or fewer.',
    '22023'
  );

  PERFORM public.api_assert(
    v_note_type IN ('general', 'tutorial'),
    'HOUSE_DIRECTORY_NOTE_INVALID_TYPE',
    'note_type must be one of general or tutorial.',
    '22023'
  );

  PERFORM public.api_assert(
    v_reference_url IS NULL OR (char_length(v_reference_url) <= 2048 AND v_reference_url ~* '^https?://'),
    'HOUSE_DIRECTORY_NOTE_INVALID_URL',
    'reference_url must be null or an http/https URL.',
    '22023'
  );

  PERFORM public.api_assert(
    v_photo_path IS NULL
    OR (
      char_length(v_photo_path) <= 512
      AND v_photo_path LIKE 'households/%'
    ),
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'photo_path must be a storage object path under households/.',
    '22023'
  );

  IF p_note_id IS NULL THEN
    v_photo_delta := CASE WHEN v_photo_path IS NOT NULL THEN 1 ELSE 0 END;

    IF v_photo_delta > 0 THEN
      PERFORM public._home_assert_quota(
        p_home_id,
        jsonb_build_object('house_directory_note_photos', v_photo_delta)
      );
    END IF;

    INSERT INTO public.home_directory_notes (
      home_id,
      title,
      details,
      note_type,
      reference_url,
      photo_path,
      archived_at,
      created_by_user_id,
      updated_by_user_id
    )
    VALUES (
      p_home_id,
      v_title,
      v_details,
      v_note_type,
      v_reference_url,
      v_photo_path,
      NULL,
      v_user,
      v_user
    )
    RETURNING * INTO v_note;

    IF v_photo_delta > 0 THEN
      PERFORM public._home_usage_apply_delta(
        p_home_id,
        jsonb_build_object('house_directory_note_photos', v_photo_delta)
      );
    END IF;
  ELSE
    SELECT *
      INTO v_existing
    FROM public.home_directory_notes n
    WHERE n.id = p_note_id
      AND n.home_id = p_home_id
      AND n.archived_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      PERFORM public.api_error(
        'HOUSE_DIRECTORY_NOTE_NOT_FOUND',
        'The note was not found for this home, or it has been archived.',
        'P0002',
        jsonb_build_object('home_id', p_home_id, 'note_id', p_note_id)
      );
    END IF;

    v_photo_delta := CASE
      WHEN v_existing.photo_path IS NULL AND v_photo_path IS NOT NULL THEN 1
      ELSE 0
    END;

    IF v_photo_delta > 0 THEN
      PERFORM public._home_assert_quota(
        p_home_id,
        jsonb_build_object('house_directory_note_photos', v_photo_delta)
      );
    END IF;

    UPDATE public.home_directory_notes n
       SET title = v_title,
           details = v_details,
           note_type = v_note_type,
           reference_url = v_reference_url,
           photo_path = v_photo_path,
           updated_by_user_id = v_user
     WHERE n.id = p_note_id
       AND n.home_id = p_home_id
       AND n.archived_at IS NULL
    RETURNING * INTO v_note;

    IF v_photo_delta > 0 THEN
      PERFORM public._home_usage_apply_delta(
        p_home_id,
        jsonb_build_object('house_directory_note_photos', v_photo_delta)
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'note', jsonb_build_object(
      'id', v_note.id,
      'home_id', v_note.home_id,
      'title', v_note.title,
      'details', v_note.details,
      'note_type', v_note.note_type,
      'reference_url', v_note.reference_url,
      'photo_path', v_note.photo_path,
      'archived_at', v_note.archived_at,
      'created_at', v_note.created_at,
      'updated_at', v_note.updated_at
    )
  );
END;
$$;


ALTER FUNCTION "public"."upsert_home_directory_note"("p_home_id" "uuid", "p_note_id" "uuid", "p_title" "text", "p_details" "text", "p_note_type" "text", "p_reference_url" "text", "p_photo_path" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_home_directory_service"("p_home_id" "uuid", "p_service_id" "uuid" DEFAULT NULL::"uuid", "p_service_type" "text" DEFAULT NULL::"text", "p_custom_label" "text" DEFAULT NULL::"text", "p_provider_name" "text" DEFAULT NULL::"text", "p_account_reference" "text" DEFAULT NULL::"text", "p_link_url" "text" DEFAULT NULL::"text", "p_term_start_date" "date" DEFAULT NULL::"date", "p_term_end_date" "date" DEFAULT NULL::"date", "p_renewal_reminder_offset_value" integer DEFAULT NULL::integer, "p_renewal_reminder_offset_unit" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_service public.home_directory_services%ROWTYPE;
  v_service_type text := lower(nullif(btrim(p_service_type), ''));
  v_custom_label text := nullif(btrim(p_custom_label), '');
  v_provider_name text := nullif(btrim(p_provider_name), '');
  v_account_reference text := nullif(btrim(p_account_reference), '');
  v_link_url text := nullif(btrim(p_link_url), '');
  v_offset_unit text := lower(nullif(btrim(p_renewal_reminder_offset_unit), ''));
  v_notes text := nullif(btrim(p_notes), '');
  v_reminder jsonb := NULL;
  v_constraint_name text;
BEGIN
  -- Replace semantics: callers should send the full intended current state.
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_active(p_home_id);
  PERFORM public._house_directory_assert_owner(p_home_id);

  PERFORM public.api_assert(
    v_service_type IS NOT NULL,
    'HOUSE_DIRECTORY_INVALID_ENUM',
    'service_type is required.',
    '22023'
  );

  PERFORM public.api_assert(
    v_service_type IN ('rent', 'internet', 'electricity', 'gas', 'water', 'other'),
    'HOUSE_DIRECTORY_INVALID_ENUM',
    'service_type must be one of rent, internet, electricity, gas, water, other.',
    '22023'
  );

  IF v_service_type = 'other' THEN
    PERFORM public.api_assert(
      v_custom_label IS NOT NULL,
      'HOUSE_DIRECTORY_OTHER_LABEL_REQUIRED',
      'custom_label is required when service_type is other.',
      '22023'
    );
    PERFORM public.api_assert(
      char_length(v_custom_label) BETWEEN 1 AND 40,
      'HOUSE_DIRECTORY_OTHER_LABEL_REQUIRED',
      'custom_label must be between 1 and 40 characters.',
      '22023'
    );
  ELSE
    PERFORM public.api_assert(
      v_custom_label IS NULL,
      'HOUSE_DIRECTORY_OTHER_LABEL_FORBIDDEN',
      'custom_label must be null unless service_type is other.',
      '22023'
    );
  END IF;

  PERFORM public.api_assert(
    v_provider_name IS NOT NULL,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'provider_name is required.',
    '22023'
  );

  PERFORM public.api_assert(
    char_length(v_provider_name) BETWEEN 1 AND 120,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'provider_name must be between 1 and 120 characters.',
    '22023'
  );

  PERFORM public.api_assert(
    v_account_reference IS NULL OR char_length(v_account_reference) <= 120,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'account_reference must be 120 characters or fewer.',
    '22023'
  );

  PERFORM public.api_assert(
    v_link_url IS NULL OR (char_length(v_link_url) <= 2048 AND v_link_url ~* '^https?://'),
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'link_url must be null or an http/https URL.',
    '22023'
  );

  IF p_term_end_date IS NOT NULL AND p_term_start_date IS NULL THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_INVALID_TERM_RANGE',
      'term_start_date is required when term_end_date is provided.',
      '22023'
    );
  END IF;

  IF p_term_start_date IS NOT NULL AND p_term_end_date IS NOT NULL AND p_term_start_date > p_term_end_date THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_INVALID_TERM_RANGE',
      'term_start_date must be on or before term_end_date.',
      '22023'
    );
  END IF;

  IF v_service_type = 'rent' THEN
    PERFORM public.api_assert(
      p_term_start_date IS NOT NULL AND p_term_end_date IS NOT NULL,
      'HOUSE_DIRECTORY_RENT_TERM_REQUIRED',
      'Rent services require both term_start_date and term_end_date.',
      '22023'
    );
  END IF;

  IF (p_renewal_reminder_offset_value IS NULL) <> (v_offset_unit IS NULL) THEN
    PERFORM public.api_error(
      'HOUSE_DIRECTORY_INVALID_REMINDER_OFFSET',
      'renewal_reminder_offset_value and renewal_reminder_offset_unit must both be provided or both be null.',
      '22023'
    );
  END IF;

  IF p_renewal_reminder_offset_value IS NOT NULL THEN
    PERFORM public.api_assert(
      p_renewal_reminder_offset_value >= 1,
      'HOUSE_DIRECTORY_INVALID_REMINDER_OFFSET',
      'renewal_reminder_offset_value must be at least 1.',
      '22023'
    );

    PERFORM public.api_assert(
      v_offset_unit IN ('day', 'week', 'month'),
      'HOUSE_DIRECTORY_INVALID_REMINDER_OFFSET',
      'renewal_reminder_offset_unit must be day, week, or month.',
      '22023'
    );

    PERFORM public.api_assert(
      p_term_start_date IS NOT NULL AND p_term_end_date IS NOT NULL,
      'HOUSE_DIRECTORY_INVALID_REMINDER_OFFSET',
      'A reminder offset requires both term_start_date and term_end_date.',
      '22023'
    );

    PERFORM public._house_directory_assert_valid_reminder_offset(
      p_term_start_date,
      p_term_end_date,
      p_renewal_reminder_offset_value,
      v_offset_unit
    );
  END IF;

  PERFORM public.api_assert(
    v_notes IS NULL OR char_length(v_notes) <= 2000,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'notes must be 2000 characters or fewer.',
    '22023'
  );

  IF p_service_id IS NULL THEN
    INSERT INTO public.home_directory_services (
      home_id,
      service_type,
      custom_label,
      provider_name,
      account_reference,
      link_url,
      term_start_date,
      term_end_date,
      renewal_reminder_offset_value,
      renewal_reminder_offset_unit,
      notes,
      archived_at,
      created_by_user_id,
      updated_by_user_id
    )
    VALUES (
      p_home_id,
      v_service_type,
      v_custom_label,
      v_provider_name,
      v_account_reference,
      v_link_url,
      p_term_start_date,
      p_term_end_date,
      p_renewal_reminder_offset_value,
      v_offset_unit,
      v_notes,
      NULL,
      v_user,
      v_user
    )
    RETURNING * INTO v_service;
  ELSE
    UPDATE public.home_directory_services s
       SET service_type = v_service_type,
           custom_label = v_custom_label,
           provider_name = v_provider_name,
           account_reference = v_account_reference,
           link_url = v_link_url,
           term_start_date = p_term_start_date,
           term_end_date = p_term_end_date,
           renewal_reminder_offset_value = p_renewal_reminder_offset_value,
           renewal_reminder_offset_unit = v_offset_unit,
           notes = v_notes,
           updated_by_user_id = v_user
     WHERE s.id = p_service_id
       AND s.home_id = p_home_id
       AND s.archived_at IS NULL
    RETURNING * INTO v_service;

    IF NOT FOUND THEN
      PERFORM public.api_error(
        'HOUSE_DIRECTORY_SERVICE_NOT_FOUND',
        'The service was not found for this home, or it has been archived.',
        'P0002',
        jsonb_build_object('home_id', p_home_id, 'service_id', p_service_id)
      );
    END IF;
  END IF;

  PERFORM public._house_directory_reconcile_service_reminder(v_service.id);

  SELECT jsonb_build_object(
           'id', r.id,
           'service_id', r.service_id,
           'reminder_kind', r.reminder_kind,
           'status', r.status,
           'term_start_date', r.term_start_date,
           'term_end_date', r.term_end_date,
           'due_at', r.due_at,
           'dismissed_at', r.dismissed_at,
           'created_at', r.created_at,
           'updated_at', r.updated_at
         )
    INTO v_reminder
  FROM public.home_directory_service_reminders r
  WHERE r.service_id = v_service.id
    AND r.reminder_kind = 'renewal'
    AND r.term_start_date = v_service.term_start_date
    AND r.term_end_date = v_service.term_end_date
    AND r.status <> 'retired';

  RETURN jsonb_build_object(
    'ok', true,
    'service', jsonb_build_object(
      'id', v_service.id,
      'home_id', v_service.home_id,
      'service_type', v_service.service_type,
      'custom_label', v_service.custom_label,
      'provider_name', v_service.provider_name,
      'account_reference', v_service.account_reference,
      'link_url', v_service.link_url,
      'term_start_date', v_service.term_start_date,
      'term_end_date', v_service.term_end_date,
      'renewal_reminder_offset_value', v_service.renewal_reminder_offset_value,
      'renewal_reminder_offset_unit', v_service.renewal_reminder_offset_unit,
      'notes', v_service.notes,
      'archived_at', v_service.archived_at,
      'created_at', v_service.created_at,
      'updated_at', v_service.updated_at
    ),
    'reminder', v_reminder
  );

EXCEPTION
  WHEN unique_violation THEN
    GET STACKED DIAGNOSTICS v_constraint_name = CONSTRAINT_NAME;

    IF v_constraint_name = 'uq_home_directory_services_one_active_rent_per_home' THEN
      PERFORM public.api_error(
        'HOUSE_DIRECTORY_ACTIVE_SERVICE_CONFLICT',
        'Only one active rent service is allowed per home.',
        '23505',
        jsonb_build_object('home_id', p_home_id, 'service_type', 'rent')
      );
    ELSIF v_constraint_name = 'uq_home_directory_services_one_active_internet_per_home' THEN
      PERFORM public.api_error(
        'HOUSE_DIRECTORY_ACTIVE_SERVICE_CONFLICT',
        'Only one active internet service is allowed per home.',
        '23505',
        jsonb_build_object('home_id', p_home_id, 'service_type', 'internet')
      );
    ELSIF v_constraint_name = 'uq_home_directory_services_one_active_electricity_per_home' THEN
      PERFORM public.api_error(
        'HOUSE_DIRECTORY_ACTIVE_SERVICE_CONFLICT',
        'Only one active electricity service is allowed per home.',
        '23505',
        jsonb_build_object('home_id', p_home_id, 'service_type', 'electricity')
      );
    ELSE
      RAISE;
    END IF;
END;
$$;


ALTER FUNCTION "public"."upsert_home_directory_service"("p_home_id" "uuid", "p_service_id" "uuid", "p_service_type" "text", "p_custom_label" "text", "p_provider_name" "text", "p_account_reference" "text", "p_link_url" "text", "p_term_start_date" "date", "p_term_end_date" "date", "p_renewal_reminder_offset_value" integer, "p_renewal_reminder_offset_unit" "text", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_home_directory_wifi"("p_home_id" "uuid", "p_ssid" "text", "p_password" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_ssid text := nullif(btrim(p_ssid), '');
  v_password text := p_password;
  v_row public.home_directory_wifi%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();
  PERFORM public._assert_home_active(p_home_id);
  PERFORM public._house_directory_assert_owner(p_home_id);

  PERFORM public.api_assert(
    v_ssid IS NOT NULL,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'SSID is required.',
    '22023'
  );

  PERFORM public.api_assert(
    char_length(v_ssid) BETWEEN 1 AND 64,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'SSID must be between 1 and 64 characters.',
    '22023'
  );

  PERFORM public.api_assert(
    v_password IS NULL OR btrim(v_password) <> '',
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'Wi-Fi password cannot be whitespace-only.',
    '22023'
  );

  PERFORM public.api_assert(
    v_password IS NULL OR char_length(v_password) <= 128,
    'HOUSE_DIRECTORY_INVALID_INPUT',
    'Wi-Fi password must be 128 characters or fewer.',
    '22023'
  );

  INSERT INTO public.home_directory_wifi (
    home_id,
    ssid,
    password,
    created_by_user_id,
    updated_by_user_id
  )
  VALUES (
    p_home_id,
    v_ssid,
    v_password,
    v_user,
    v_user
  )
  ON CONFLICT (home_id)
  DO UPDATE
     SET ssid = EXCLUDED.ssid,
         password = EXCLUDED.password,
         updated_by_user_id = EXCLUDED.updated_by_user_id
  RETURNING * INTO v_row;

  RETURN jsonb_build_object(
    'ok', true,
    'wifi', jsonb_build_object(
      'id', v_row.id,
      'home_id', v_row.home_id,
      'ssid', v_row.ssid,
      'qr_payload', public._house_directory_build_wifi_qr(v_row.ssid, v_row.password),
      'created_at', v_row.created_at,
      'updated_at', v_row.updated_at
    )
  );
END;
$$;


ALTER FUNCTION "public"."upsert_home_directory_wifi"("p_home_id" "uuid", "p_ssid" "text", "p_password" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_member_directory_bank_account"("p_account_holder_name" "text", "p_account_number" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid := auth.uid();
  v_account_holder_name text := nullif(btrim(p_account_holder_name), '');
  v_account_number text := nullif(btrim(p_account_number), '');
  v_row public.member_directory_bank_accounts%ROWTYPE;
BEGIN
  PERFORM public._assert_authenticated();

  PERFORM public.api_assert(
    v_account_holder_name IS NOT NULL,
    'MEMBER_DIRECTORY_BANK_ACCOUNT_REQUIRED_FIELDS',
    'account_holder_name is required.',
    '22023'
  );

  PERFORM public.api_assert(
    v_account_number IS NOT NULL,
    'MEMBER_DIRECTORY_BANK_ACCOUNT_REQUIRED_FIELDS',
    'account_number is required.',
    '22023'
  );

  PERFORM public.api_assert(
    char_length(v_account_holder_name) <= 120,
    'MEMBER_DIRECTORY_INVALID_INPUT',
    'account_holder_name must be between 1 and 120 characters.',
    '22023'
  );

  PERFORM public.api_assert(
    char_length(v_account_number) <= 50,
    'MEMBER_DIRECTORY_INVALID_INPUT',
    'account_number must be between 1 and 50 characters.',
    '22023'
  );

  INSERT INTO public.member_directory_bank_accounts (
    user_id,
    account_holder_name,
    account_number
  )
  VALUES (
    v_user,
    v_account_holder_name,
    v_account_number
  )
  ON CONFLICT (user_id)
  DO UPDATE SET
    account_holder_name = EXCLUDED.account_holder_name,
    account_number = EXCLUDED.account_number
  RETURNING * INTO v_row;

  RETURN jsonb_build_object(
    'ok', true,
    'has_bank_account', true,
    'bank_account', jsonb_build_object(
      'id', v_row.id,
      'account_holder_name', v_row.account_holder_name,
      'account_number', v_row.account_number,
      'created_at', v_row.created_at,
      'updated_at', v_row.updated_at
    )
  );
END;
$$;


ALTER FUNCTION "public"."upsert_member_directory_bank_account"("p_account_holder_name" "text", "p_account_number" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_member_directory_bank_account"("p_account_holder_name" "text", "p_account_number" "text") IS 'Creates or updates the authenticated user single active member-directory bank account. Bank account is optional overall, but required when this RPC is called.';



CREATE OR REPLACE FUNCTION "public"."user_context_v1"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user uuid;
  v_show_avatar boolean;
  v_has_preference_report boolean;
  v_has_personal_mentions boolean;
  v_has_personal_directory_content boolean;
  v_avatar_storage_path text;
  v_display_name text;
BEGIN
  PERFORM public._assert_authenticated();
  v_user := auth.uid();

  v_has_preference_report := EXISTS (
    SELECT 1
    FROM public.preference_reports pr
    WHERE pr.subject_user_id = v_user
      AND pr.status = 'published'
  );

  v_has_personal_mentions := EXISTS (
    SELECT 1
    FROM public.gratitude_wall_personal_items i
    WHERE i.recipient_user_id = v_user
      AND i.author_user_id <> v_user
  );

  v_has_personal_directory_content := (
    EXISTS (
      SELECT 1
      FROM public.member_directory_bank_accounts b
      WHERE b.user_id = v_user
    )
    OR EXISTS (
      SELECT 1
      FROM public.member_directory_notes n
      WHERE n.user_id = v_user
        AND n.archived_at IS NULL
    )
  );

  v_show_avatar := (
    v_has_preference_report
    OR v_has_personal_mentions
    OR v_has_personal_directory_content
  );

  SELECT
    p.username,
    a.storage_path
  INTO v_display_name, v_avatar_storage_path
  FROM public.profiles p
  LEFT JOIN public.avatars a
    ON a.id = p.avatar_id
  WHERE p.id = v_user;

  IF NOT v_show_avatar THEN
    v_avatar_storage_path := NULL;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'user_id', v_user,
    'has_preference_report', v_has_preference_report,
    'has_personal_mentions', v_has_personal_mentions,
    'has_personal_directory_content', v_has_personal_directory_content,
    'show_avatar', v_show_avatar,
    'avatar_storage_path', v_avatar_storage_path,
    'display_name', v_display_name
  );
END;
$$;


