COMMENT ON COLUMN "public"."member_directory_bank_accounts"."user_id" IS 'Owner of the bank account record. Product intentionally supports one active bank account per user.';



COMMENT ON COLUMN "public"."member_directory_bank_accounts"."account_holder_name" IS 'Display name used by other home members when making payments.';



COMMENT ON COLUMN "public"."member_directory_bank_accounts"."account_number" IS 'Bank account number shared with active members of the same active home for payment purposes.';



CREATE TABLE IF NOT EXISTS "public"."member_directory_notes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "note_type" "text" NOT NULL,
    "label" "text",
    "custom_title" "text",
    "contact_name" "text",
    "phone_number" "text",
    "details" "text",
    "photo_path" "text",
    "archived_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reference_url" "text",
    CONSTRAINT "member_directory_notes_details_check" CHECK (((("note_type" = 'emergency_contact'::"text") AND (("details" IS NULL) OR ("char_length"("btrim"("details")) <= 2000))) OR (("note_type" = 'allergy'::"text") AND ("details" IS NULL)) OR (("note_type" = 'other'::"text") AND (("details" IS NULL) OR (("char_length"("btrim"("details")) >= 1) AND ("char_length"("btrim"("details")) <= 2000)))))),
    CONSTRAINT "member_directory_notes_emergency_fields_check" CHECK (((("note_type" = 'emergency_contact'::"text") AND (("char_length"("btrim"(COALESCE("contact_name", ''::"text"))) >= 1) AND ("char_length"("btrim"(COALESCE("contact_name", ''::"text"))) <= 120)) AND (("char_length"("btrim"(COALESCE("phone_number", ''::"text"))) >= 1) AND ("char_length"("btrim"(COALESCE("phone_number", ''::"text"))) <= 30))) OR (("note_type" <> 'emergency_contact'::"text") AND ("contact_name" IS NULL) AND ("phone_number" IS NULL)))),
    CONSTRAINT "member_directory_notes_label_check" CHECK (((("note_type" = 'allergy'::"text") AND (("char_length"("btrim"(COALESCE("label", ''::"text"))) >= 1) AND ("char_length"("btrim"(COALESCE("label", ''::"text"))) <= 120))) OR (("note_type" <> 'allergy'::"text") AND ("label" IS NULL)))),
    CONSTRAINT "member_directory_notes_note_type_check" CHECK (("note_type" = ANY (ARRAY['emergency_contact'::"text", 'allergy'::"text", 'other'::"text"]))),
    CONSTRAINT "member_directory_notes_other_title_check" CHECK (((("note_type" = 'other'::"text") AND (("char_length"("btrim"(COALESCE("custom_title", ''::"text"))) >= 1) AND ("char_length"("btrim"(COALESCE("custom_title", ''::"text"))) <= 80))) OR (("note_type" <> 'other'::"text") AND ("custom_title" IS NULL)))),
    CONSTRAINT "member_directory_notes_phone_number_format_check" CHECK ((("phone_number" IS NULL) OR (("phone_number" ~ '^[0-9+()\- ]{1,30}$'::"text") AND ("phone_number" ~ '[0-9]'::"text")))),
    CONSTRAINT "member_directory_notes_photo_path_check" CHECK ((("photo_path" IS NULL) OR ("char_length"("photo_path") <= 512))),
    CONSTRAINT "member_directory_notes_reference_url_check" CHECK ((("reference_url" IS NULL) OR (("char_length"("reference_url") <= 2048) AND ("reference_url" ~* '^https?://'::"text"))))
);


ALTER TABLE "public"."member_directory_notes" OWNER TO "postgres";


COMMENT ON TABLE "public"."member_directory_notes" IS 'RPC-only table for user-owned member-directory notes visible to active members of the same active home. Supports optional singleton emergency contact and repeatable allergy/other notes. Allergy uses label for chip display and search/filtering. Other notes are best-effort soft limited. No direct client table access.';



COMMENT ON COLUMN "public"."member_directory_notes"."note_type" IS 'Client-localized category key. Valid values: emergency_contact, allergy, other.';



COMMENT ON COLUMN "public"."member_directory_notes"."label" IS 'Dedicated allergy label. Required only for allergy rows. Intended for chip-style display and search/filtering.';



COMMENT ON COLUMN "public"."member_directory_notes"."custom_title" IS 'Required only for other notes. Client should display this directly.';



COMMENT ON COLUMN "public"."member_directory_notes"."contact_name" IS 'Required only for emergency_contact notes.';



COMMENT ON COLUMN "public"."member_directory_notes"."phone_number" IS 'Required only for emergency_contact notes. Accepts international-style free-text phone formats using digits, spaces, plus, parentheses, and hyphen.';



COMMENT ON COLUMN "public"."member_directory_notes"."details" IS 'Optional supporting details for emergency_contact notes. Forbidden for allergy rows in v1.0. Optional supporting details for other notes.';



COMMENT ON COLUMN "public"."member_directory_notes"."photo_path" IS 'Optional anonymous households-bucket object key. RPC validates only expected key structure under the user current active home path; knowledge of the key may allow retrieval depending on bucket policy.';



COMMENT ON COLUMN "public"."member_directory_notes"."archived_at" IS 'Soft-delete timestamp. Active reads exclude archived rows. Hard delete is forbidden by trigger.';



COMMENT ON COLUMN "public"."member_directory_notes"."reference_url" IS 'Optional http/https URL attached to a member-directory note for supporting context or follow-up.';



